### 🧠 Real-World Examples - When This Matters! ✨

#### 🎨 Configuration Management (Read-Heavy)

```rust
use std::sync::{Arc, RwLock};
use std::collections::HashMap;
use std::thread;

// Perfect use case for RwLock - mostly reading, occasional writing
#[derive(Debug, Clone)]
struct AppConfig {
    settings: HashMap<String, String>,
    version: u32,
}

impl AppConfig {
    fn new() -> Self {
        let mut settings = HashMap::new();
        settings.insert("database_url".to_string(), "localhost:5432".to_string());
        settings.insert("cache_size".to_string(), "1000".to_string());

        Self {
            settings,
            version: 1,
        }
    }

    fn get_setting(&self, key: &str) -> Option<&String> {
        self.settings.get(key)
    }
}

fn config_manager() {
    let config = Arc::new(RwLock::new(AppConfig::new()));
    let mut handles = vec![];

    // Many reader threads - can access simultaneously
    for i in 0..5 {
        let config_clone = config.clone();
        let handle = thread::spawn(move || {
            // Multiple readers can access at the same time!
            let guard = config_clone.read().unwrap();
            let db_url = guard.get_setting("database_url");
            println!("Worker {} sees DB URL: {:?}", i, db_url);
        });
        handles.push(handle);
    }

    // One writer thread - updates configuration
    let config_clone = config.clone();
    let writer_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(10));
        // Writer must wait for all readers to finish
        let mut guard = config_clone.write().unwrap();
        guard.settings.insert("new_setting".to_string(), "new_value".to_string());
        guard.version += 1;
        println!("Configuration updated to version {}", guard.version);
    });
    handles.push(writer_handle);

    // Wait for all threads
    for handle in handles {
        handle.join().unwrap();
    }
}
```

#### 🎨 Counter with High Read Frequency

```rust
use std::sync::{Arc, Mutex, RwLock};
use std::thread;

// Compare performance characteristics
struct CounterWithMutex {
    value: Mutex<u64>,
}

struct CounterWithRwLock {
    value: RwLock<u64>,
}

impl CounterWithMutex {
    fn new(initial: u64) -> Arc<Self> {
        Arc::new(Self {
            value: Mutex::new(initial),
        })
    }

    fn increment(&self) {
        let mut guard = self.value.lock().unwrap();
        *guard += 1;
    }

    fn get_value(&self) -> u64 {
        *self.value.lock().unwrap()  // Blocks other access even for reading!
    }
}

impl CounterWithRwLock {
    fn new(initial: u64) -> Arc<Self> {
        Arc::new(Self {
            value: RwLock::new(initial),
        })
    }

    fn increment(&self) {
        let mut guard = self.value.write().unwrap();
        *guard += 1;
    }

    fn get_value(&self) -> u64 {
        *self.value.read().unwrap()  // Allows concurrent reads!
    }
}

fn performance_comparison() {
    let mutex_counter = CounterWithMutex::new(0);
    let rwlock_counter = CounterWithRwLock::new(0);

    let mut handles = vec![];

    // High read frequency scenario
    for _ in 0..10 {
        let mutex_clone = mutex_counter.clone();
        let rwlock_clone = rwlock_counter.clone();

        let handle = thread::spawn(move || {
            // Mix of reads and writes
            for i in 0..100 {
                if i % 10 == 0 {
                    mutex_clone.increment();
                    rwlock_clone.increment();
                } else {
                    let _ = mutex_clone.get_value();  // Blocks other access
                    let _ = rwlock_clone.get_value(); // Allows concurrent reads
                }
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Mutex counter: {}", mutex_counter.get_value());
    println!("RwLock counter: {}", rwlock_counter.get_value());
}
```

