### 🧠 Why This Pattern is GORGEOUS 💝✨

1. **Performance**: `RwLock` allows concurrent reads for read-heavy workloads
2. **Concurrency**: Better throughput when multiple threads read simultaneously
3. **Safety**: Both prevent data races with compile-time guarantees
4. **Flexibility**: Choose the right tool for your access patterns
5. **Ergonomics**: Similar APIs make both easy to use

#### 🧠 Performance Characteristics

```rust
use std::sync::{Arc, Mutex, RwLock};
use std::time::Instant;

fn benchmark_locks() {
    const ITERATIONS: usize = 1000;

    // Mutex benchmark - exclusive access
    let mutex_data = Arc::new(Mutex::new(0u64));
    let start = Instant::now();

    let handles: Vec<_> = (0..4).map(|_| {
        let data = mutex_data.clone();
        std::thread::spawn(move || {
            for _ in 0..ITERATIONS {
                let mut guard = data.lock().unwrap();
                *guard += 1;
            }
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    let mutex_time = start.elapsed();

    // RwLock benchmark - same exclusive writes
    let rwlock_data = Arc::new(RwLock::new(0u64));
    let start = Instant::now();

    let handles: Vec<_> = (0..4).map(|_| {
        let data = rwlock_data.clone();
        std::thread::spawn(move || {
            for _ in 0..ITERATIONS {
                let mut guard = data.write().unwrap();
                *guard += 1;
            }
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    let rwlock_write_time = start.elapsed();

    println!("Mutex time: {:?}", mutex_time);
    println!("RwLock write time: {:?}", rwlock_write_time);

    // But RwLock shines with concurrent reads!
    let start = Instant::now();
    let handles: Vec<_> = (0..10).map(|_| {
        let data = rwlock_data.clone();
        std::thread::spawn(move || {
            for _ in 0..1000 {
                let guard = data.read().unwrap();
                let _value = *guard;  // Just reading
            }
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    let rwlock_read_time = start.elapsed();
    println!("RwLock concurrent reads time: {:?}", rwlock_read_time);
}
```

