### 🧠 Real-World Examples - When This Shines! ✨

#### 🎨 JSON API Server

```rust
use axum::{
    extract::Path,
    http::StatusCode,
    response::Json,
    routing::{get, post},
    Router,
};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::{Arc, RwLock};

#[derive(Serialize, Deserialize, Debug, Clone)]
struct User {
    id: u32,
    name: String,
    email: String,
}

type AppState = Arc<RwLock<HashMap<u32, User>>>;

async fn get_users(State(state): State<AppState>) -> Json<Vec<User>> {
    let users = state.read().unwrap().values().cloned().collect();
    Json(users)
}

async fn get_user(
    Path(id): Path<u32>,
    State(state): State<AppState>,
) -> Result<Json<User>, StatusCode> {
    state
        .read()
        .unwrap()
        .get(&id)
        .cloned()
        .map(Json)
        .ok_or(StatusCode::NOT_FOUND)
}

async fn create_user(
    State(state): State<AppState>,
    Json(user): Json<User>,
) -> (StatusCode, Json<User>) {
    let mut store = state.write().unwrap();
    store.insert(user.id, user.clone());
    (StatusCode::CREATED, Json(user))
}

async fn hello() -> &'static str {
    "hello"
}

#[tokio::main]
async fn main() {
    let state = Arc::new(RwLock::new(HashMap::new()));

    let app = Router::new()
        .route("/", get(hello))
        .route("/users", get(get_users).post(create_user))
        .route("/users/:id", get(get_user))
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    println!("🚀 EVA's JSON API server running on http://localhost:3000");
    axum::serve(listener, app).await.unwrap();
}
```

