// Functional programming patterns
impl<T> LinkedList<T> {
    // Fold/reduce operation
    pub fn fold<U, F>(self, init: U, f: F) -> U
    where
        F: Fn(U, T) -> U,
    {
        let mut result = init;
        let mut current = self.head;

        while let Some(node) = current {
            result = f(result, node.value);
            current = node.next;
        }

        result
    }

    // Filter and collect into new list
    pub fn filter<F>(self, predicate: F) -> LinkedList<T>
    where
        F: Fn(&T) -> bool,
        T: Clone,
    {
        let mut result = LinkedList::new();
        let mut values = Vec::new();

        let mut current = self.head;
        while let Some(node) = current {
            if predicate(&node.value) {
                values.push(node.value.clone());
            }
            current = node.next;
        }

        // Push in reverse to maintain order
        for value in values.into_iter().rev() {
            result.push_front(value);
        }

        result
    }

    // Take first n elements
    pub fn take(self, n: usize) -> LinkedList<T> {
        let mut result = LinkedList::new();
        let mut count = 0;
        let mut current = self.head;
        let mut values = Vec::new();

        while count < n {
            if let Some(node) = current {
                values.push(node.value);
                current = node.next;
                count += 1;
            } else {
                break;
            }
        }

        // Push in reverse to maintain order
        for value in values.into_iter().rev() {
            result.push_front(value);
        }

        result
    }
}

