    println!("Sum using fold: {}", sum);

    // Filter even numbers
    let evens = numbers.clone().filter(|&x| x % 2 == 0);
    println!("Even numbers: {:?}", evens.to_vec());

    // Take first 5 elements
    let first_five = numbers.take(5);
    println!("First five: {:?}", first_five.to_vec());
}
