// Beautiful pipeline with automatic error propagation
fn process_log_file<P: AsRef<Path>>(path: P) -> Result<LogStats, Box<dyn std::error::Error>> {
    // Each ? automatically propagates any error
    let file = fs::File::open(path)?;                    // io::Error
    let reader = BufReader::new(file);
    let lines = reader.lines();

