struct LogStats {
    total_entries: u32,
    error_count: u32,
    warning_count: u32,
}

impl LogStats {
    fn new() -> Self {
        Self {
            total_entries: 0,
            error_count: 0,
            warning_count: 0,
        }
    }

    fn update(&mut self, entry: &LogEntry) {
        self.total_entries += 1;
        match entry.level {
            LogLevel::Error => self.error_count += 1,
            LogLevel::Warning => self.warning_count += 1,
            _ => {}
        }
    }
}

#[derive(Debug)]
