#### 🎨 Plugin System with Dynamic Dispatch

```rust
// Perfect use case for Box<dyn Trait> - plugin system
trait Plugin {
    fn name(&self) -> &str;
    fn process(&self, data: &str) -> String;
    fn priority(&self) -> u32;
}

struct EncryptionPlugin;
struct CompressionPlugin;
struct ValidationPlugin;

impl Plugin for EncryptionPlugin {
    fn name(&self) -> &str { "Encryption" }
    fn process(&self, data: &str) -> String { format!("encrypted({})", data) }
    fn priority(&self) -> u32 { 10 }
}

impl Plugin for CompressionPlugin {
    fn name(&self) -> &str { "Compression" }
    fn process(&self, data: &str) -> String { format!("compressed({})", data) }
    fn priority(&self) -> u32 { 5 }
}

impl Plugin for ValidationPlugin {
    fn name(&self) -> &str { "Validation" }
    fn process(&self, data: &str) -> String { format!("validated({})", data) }
    fn priority(&self) -> u32 { 1 }
}

// Dynamic dispatch - perfect for plugin systems!
struct PluginManager {
    plugins: Vec<Box<dyn Plugin>>,
}

impl PluginManager {
    fn new() -> Self {
        Self {
            plugins: vec![
                Box::new(EncryptionPlugin),
                Box::new(CompressionPlugin),
                Box::new(ValidationPlugin),
            ]
        }
    }

    fn process_data(&self, mut data: String) -> String {
        // Sort by priority and process
        let mut plugins: Vec<&Box<dyn Plugin>> = self.plugins.iter().collect();
        plugins.sort_by_key(|p| std::cmp::Reverse(p.priority()));

        for plugin in plugins {
            data = plugin.process(&data);
        }
        data
    }
}
