use proptest::prelude::*;
use std::collections::HashMap;

// Example function that processes Vec<u8>
fn parse_length_prefixed_data(data: &[u8]) -> Result<Vec<Vec<u8>>, String> {
    let mut result = Vec::new();
    let mut pos = 0;

    while pos < data.len() {
        if pos + 4 > data.len() {
            return Err("Incomplete length prefix".to_string());
        }

        let len = u32::from_le_bytes([
            data[pos], data[pos + 1], data[pos + 2], data[pos + 3]
        ]) as usize;
        pos += 4;

        if pos + len > data.len() {
            return Err("Incomplete data".to_string());
        }

        result.push(data[pos..pos + len].to_vec());
        pos += len;
    }

    Ok(result)
}

fn serialize_length_prefixed_data(chunks: &[Vec<u8>]) -> Vec<u8> {
    let mut result = Vec::new();

    for chunk in chunks {
        let len = chunk.len() as u32;
        result.extend_from_slice(&len.to_le_bytes());
        result.extend_from_slice(chunk);
    }

    result
}

// Beautiful proptest for round-trip serialization
proptest! {
    #[test]
    fn test_round_trip_serialization(
        chunks in prop::collection::vec(
            prop::collection::vec(any::<u8>(), 0..100),  // Each chunk: 0-100 bytes
            0..10  // 0-10 chunks
        )
    ) {
        // Serialize the chunks
        let serialized = serialize_length_prefixed_data(&chunks);

        // Deserialize back
        let deserialized = parse_length_prefixed_data(&serialized);

        // Should always succeed and match original
        prop_assert!(deserialized.is_ok());
        prop_assert_eq!(deserialized.unwrap(), chunks);
    }

    #[test]
    fn test_parse_never_panics(
        data in prop::collection::vec(any::<u8>(), 0..1000)
    ) {
        // Just ensure parsing never crashes
        let _ = parse_length_prefixed_data(&data);
    }

    #[test]
    fn test_parse_properties(
        data in prop::collection::vec(any::<u8>(), 0..1000)
    ) {
        match parse_length_prefixed_data(&data) {
            Ok(chunks) => {
                // If parsing succeeds, total length should match
                let total_chunk_len: usize = chunks.iter().map(|c| c.len() + 4).sum();
                prop_assert_eq!(total_chunk_len, data.len());
            }
            Err(_) => {
                // If parsing fails, it should be due to incomplete data
                // This is a valid error condition
            }
        }
    }
}
