#### 🎨 Protocol Parser Testing

```rust
use proptest::prelude::*;

#[derive(Debug, PartialEq)]
enum PacketType {
    Data,
    Ack,
    Error,
}

#[derive(Debug, PartialEq)]
struct Packet {
    packet_type: PacketType,
    sequence: u32,
    payload: Vec<u8>,
}

fn parse_packet(data: &[u8]) -> Result<Packet, String> {
    if data.len() < 6 {
        return Err("Packet too short".to_string());
    }

    let packet_type = match data[0] {
        0 => PacketType::Data,
        1 => PacketType::Ack,
        2 => PacketType::Error,
        _ => return Err("Invalid packet type".to_string()),
    };

    let sequence = u32::from_be_bytes([data[1], data[2], data[3], data[4]]);
    let payload_len = data[5] as usize;

    if 6 + payload_len > data.len() {
        return Err("Payload length mismatch".to_string());
    }

    let payload = data[6..6 + payload_len].to_vec();

    Ok(Packet {
        packet_type,
        sequence,
        payload,
    })
}

fn serialize_packet(packet: &Packet) -> Vec<u8> {
    let mut result = Vec::new();

    let type_byte = match packet.packet_type {
        PacketType::Data => 0,
        PacketType::Ack => 1,
        PacketType::Error => 2,
    };
    result.push(type_byte);

    result.extend_from_slice(&packet.sequence.to_be_bytes());

    if packet.payload.len() > 255 {
        panic!("Payload too long");
    }
    result.push(packet.payload.len() as u8);
    result.extend_from_slice(&packet.payload);

    result
}

proptest! {
    #[test]
    fn test_packet_round_trip(
        packet_type in prop_oneof![Just(PacketType::Data), Just(PacketType::Ack), Just(PacketType::Error)],
        sequence in any::<u32>(),
        payload in prop::collection::vec(any::<u8>(), 0..255)
    ) {
        let packet = Packet {
            packet_type,
            sequence,
            payload,
        };

        let serialized = serialize_packet(&packet);
        let parsed = parse_packet(&serialized);

        prop_assert!(parsed.is_ok());
        prop_assert_eq!(parsed.unwrap(), packet);
    }

    #[test]
    fn test_parse_never_crashes_random_data(
        data in prop::collection::vec(any::<u8>(), 0..1000)
    ) {
        // Parse random data - should never panic, just return Err
        let _ = parse_packet(&data);
    }

    #[test]
    fn test_parse_valid_packets(
        packet_type in prop_oneof![Just(PacketType::Data), Just(PacketType::Ack), Just(PacketType::Error)],
        sequence in any::<u32>(),
        payload_len in 0u8..=200,
        extra_bytes in 0usize..100
    ) {
        // Construct a valid packet manually
        let mut data = Vec::new();
        let type_byte = match packet_type {
            PacketType::Data => 0,
            PacketType::Ack => 1,
            PacketType::Error => 2,
        };
        data.push(type_byte);
