### 🎯 TL;DR - The Key Difference

```rust
// String - owned, growable, heap-allocated string
let owned_string: String = String::from("Hello, world!");  // ✨ I own this data
let owned_string2: String = "Hello, world!".to_string();   // ✨ Also owned

// &str - borrowed, fixed-size string slice
let string_slice: &str = "Hello, world!";                 // ✨ I'm borrowing this
let slice_from_string: &str = &owned_string;              // ✨ Borrowing from owned string
```

**Key insight**: `String` = **I own the data**, `&str` = **I'm borrowing a view of string data**! ✨

---

### 🔍 Deep Dive — With EVA Energy! 💫

#### 🧱 `String` - Owned String Type

```rust
fn string_examples() {
    // Creating Strings in different ways
    let s1 = String::new();                    // Empty string
    let s2 = String::from("Hello");            // From string literal
    let s3 = "Hello".to_string();              // Convert &str to String
    let s4 = "Hello".to_owned();               // Same as to_string()
    let s5 = format!("Hello, {}!", "world");   // Format macro

    // Strings are growable
    let mut greeting = String::from("Hello");
    greeting.push(',');                        // Add single char
    greeting.push_str(" world!");              // Add string slice
    println!("{}", greeting);                  // "Hello, world!"

    // Strings own their data - stored on heap
    let owned_data = greeting.clone();         // Deep copy
    println!("Original: {}, Copy: {}", greeting, owned_data);
}
```

#### 🧱 `&str` - String Slice (Borrowed)

```rust
fn str_examples() {
    // String literals are &str
    let literal: &str = "I'm a string literal stored in the binary";

    // Slicing Strings gives &str
    let owned = String::from("Hello, world!");
    let slice1: &str = &owned[0..5];           // "Hello"
    let slice2: &str = &owned[..];             // Whole string as slice

    // &str is just a view - no ownership
    println!("Literal: {}", literal);
    println!("Slice: {}", slice1);
    println!("Full slice: {}", slice2);

    // No allocation needed - just references to existing data
}
