    let result2 = process_text(&owned);

    // Works with string slices
    let slice = &owned[0..3];
    let result3 = process_text(slice);

    println!("{} {} {}", result1, result2, result3);
}

// Sometimes you need owned String
fn require_owned(owned_text: String) -> String {
    // We take ownership and can modify/move it
    let mut result = owned_text;
    result.push_str(" - processed");
    result
}

fn ownership_examples() {
    let owned = String::from("Hello");

    // This moves ownership - owned is no longer valid
    let processed = require_owned(owned);
    // println!("{}", owned);  // ❌ Won't compile!

    println!("{}", processed);
}
