#### 🎨 String Building and Performance

```rust
use std::time::Instant;

fn string_building_performance() {
    // Inefficient: Creating many temporary Strings
    let start = Instant::now();
    let mut result = String::new();
    for i in 0..1000 {
        result = format!("{}{}", result, i);  // Creates new String each time!
    }
    let inefficient_time = start.elapsed();

    // Efficient: Using String's push methods
    let start = Instant::now();
    let mut result = String::new();
    for i in 0..1000 {
        result.push_str(&i.to_string());  // Appends to existing String
    }
    let efficient_time = start.elapsed();

    // Most efficient: Using a buffer
    let start = Instant::now();
    let mut parts = Vec::new();
    for i in 0..1000 {
        parts.push(i.to_string());
    }
    let result = parts.join("");  // Single allocation at the end
    let buffer_time = start.elapsed();

    println!("Inefficient: {:?}", inefficient_time);
    println!("Efficient: {:?}", efficient_time);
    println!("Buffer: {:?}", buffer_time);
}
```

