    input.to_uppercase()
}

// 2. Return types - choose based on needs
fn return_owned() -> String {
    "I need to own this".to_string()  // Return owned data
}

fn return_borrowed(data: &String) -> &str {
    &data[..]  // Return borrowed view
}

// 3. String building patterns
fn efficient_string_building(parts: &[&str]) -> String {
    // Good: Pre-allocate when you know the size
    let total_len: usize = parts.iter().map(|s| s.len()).sum();
    let mut result = String::with_capacity(total_len);

    for part in parts {
        result.push_str(part);
    }

    result
}

// 4. Avoid common pitfalls
fn avoid_pitfalls() {
    // ❌ Don't do this - unnecessary allocation
    // let s = "hello".to_string().to_string();

    // ✅ Do this instead
    let s = "hello".to_string();

    // ❌ Don't do this - mixing ownership incorrectly
    // fn bad_example(s: String) -> &str { &s }  // ❌ Won't compile - dangling reference

    // ✅ Do this instead
    fn good_example(s: &str) -> &str { s }  // ✅ Borrowing works fine
}

// 5. Use string slices for pattern matching
fn pattern_matching(text: &str) -> bool {
    match text {
        "hello" => true,
        "world" => true,
        _ => false,
    }
}
