use axum::{
    extract::State,
    response::sse::{Event, Sse},
    routing::get,
    Router,
};
use futures::stream::{self, Stream, StreamExt};
use serde::Serialize;
use std::convert::Infallible;
use std::sync::Arc;
use tokio::sync::broadcast;
use tokio_stream::wrappers::BroadcastStream;

// Shared state for broadcasting messages
#[derive(Clone)]
struct AppState {
    tx: broadcast::Sender<String>,
}

#[derive(Serialize)]
struct ServerEvent {
    timestamp: u64,
    message: String,
    event_type: String,
}

async fn sse_events(
    State(state): State<AppState>,
) -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    // Subscribe to the broadcast channel
    let rx = state.tx.subscribe();
    let stream = BroadcastStream::new(rx)
        .filter_map(|result| async move {
            match result {
                Ok(message) => {
                    let event = ServerEvent {
                        timestamp: std::time::SystemTime::now()
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap()
                            .as_secs(),
                        message,
                        event_type: "update".to_string(),
                    };

                    let json_data = serde_json::to_string(&event).unwrap();
                    Some(Ok(Event::default()
                        .event("message")
                        .data(json_data)
                        .id(uuid::Uuid::new_v4().to_string())))
                }
                Err(_) => None, // Handle recv error
            }
        });

    Sse::new(stream).keep_alive(
        axio::response::sse::KeepAlive::new()
            .interval(Duration::from_secs(30))
            .text("ping"),
    )
}

// Function to send messages to all connected clients
async fn broadcast_message(state: AppState, message: String) {
    let _ = state.tx.send(message);
}
