use serde::Serialize;
use std::convert::Infallible;
use std::sync::Arc;
use tokio::sync::broadcast;
use tokio_stream::wrappers::BroadcastStream;

#[derive(Clone)]
struct DashboardState {
    metrics_tx: broadcast::Sender<SystemMetrics>,
    alerts_tx: broadcast::Sender<Alert>,
}

#[derive(Serialize, Clone, Debug)]
struct SystemMetrics {
    timestamp: u64,
    cpu_usage: f64,
    memory_usage: f64,
    active_users: u32,
    requests_per_second: f64,
}

#[derive(Serialize, Clone, Debug)]
struct Alert {
    id: String,
    level: AlertLevel,
    message: String,
    timestamp: u64,
}

#[derive(Serialize, Clone, Debug)]
enum AlertLevel {
    Info,
    Warning,
    Critical,
}

async fn dashboard_metrics_sse(
    State(state): State<DashboardState>,
) -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    let metrics_rx = state.metrics_tx.subscribe();
    let alerts_rx = state.alerts_tx.subscribe();

    // Combine both streams
    let metrics_stream = BroadcastStream::new(metrics_rx)
        .filter_map(|result| async move {
            result.ok().map(|metrics| {
                let json_data = serde_json::to_string(&metrics).unwrap();
                Ok(Event::default()
                    .event("metrics")
                    .data(json_data))
            })
        });

    let alerts_stream = BroadcastStream::new(alerts_rx)
        .filter_map(|result| async move {
            result.ok().map(|alert| {
                let json_data = serde_json::to_string(&alert).unwrap();
                Ok(Event::default()
                    .event("alert")
                    .data(json_data)
                    .id(alert.id))
            })
        });

    // Merge the streams
    let combined_stream = stream::select(metrics_stream, alerts_stream);

    Sse::new(combined_stream).keep_alive(
        axum::response::sse::KeepAlive::new()
            .interval(Duration::from_secs(30))
            .text("dashboard-ping"),
    )
