use axum::{
    extract::{State, Query},
    response::sse::{Event, Sse},
    routing::get,
    Router,
};
use futures::stream::{self, Stream};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::convert::Infallible;
use tokio::sync::broadcast;

#[derive(Clone)]
struct NotificationState {
    // Channel per user
    user_channels: Arc<std::sync::Mutex<HashMap<String, broadcast::Sender<UserNotification>>>>,
}

#[derive(Serialize, Deserialize, Clone, Debug)]
struct UserNotification {
    id: String,
    title: String,
    message: String,
    notification_type: NotificationType,
    timestamp: u64,
    read: bool,
}

#[derive(Serialize, Deserialize, Clone, Debug)]
enum NotificationType {
    Message,
    Alert,
    Update,
    System,
}

#[derive(Deserialize)]
struct UserQuery {
    user_id: String,
}

async fn user_notifications_sse(
    State(state): State<NotificationState>,
    Query(query): Query<UserQuery>,
) -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    // Get or create channel for user
    let tx = {
        let mut channels = state.user_channels.lock().unwrap();
        channels.entry(query.user_id.clone())
            .or_insert_with(|| {
                let (tx, _) = broadcast::channel(100);
                tx
            })
            .clone()
    };

    let rx = tx.subscribe();

    let stream = BroadcastStream::new(rx)
        .filter_map(|result| async move {
            match result {
                Ok(notification) => {
                    let json_data = serde_json::to_string(&notification).unwrap();
                    Some(Ok(Event::default()
                        .event("notification")
                        .data(json_data)
                        .id(notification.id)))
                }
                Err(e) => {
                    eprintln!("Notification stream error: {:?}", e);
                    None
                }
            }
        });

    Sse::new(stream).keep_alive(
        axum::response::sse::KeepAlive::new()
            .interval(Duration::from_secs(45))
            .text("notification-ping"),
    )
}

// Function to send notification to specific user
async fn send_user_notification(
    state: NotificationState,
    user_id: String,
    notification: UserNotification,
) {
    let channels = state.user_channels.lock().unwrap();
    if let Some(tx) = channels.get(&user_id) {
        let _ = tx.send(notification);
    }
}
