```rust
// 1. Handle client disconnections gracefully
use tokio_stream::wrappers::BroadcastStream;

async fn robust_sse_handler() -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    let (tx, rx) = tokio::sync::broadcast::channel::<String>(100);

    // Spawn a task to send periodic updates
    tokio::spawn(async move {
        let mut interval = tokio::time::interval(Duration::from_secs(10));
        let mut counter = 0;

        loop {
            interval.tick().await;
            counter += 1;

            let message = format!("Update #{}", counter);
            if tx.send(message).is_err() {
                // No more subscribers, stop sending
                break;
            }
        }
    });

    let stream = BroadcastStream::new(rx)
        .filter_map(|result| async move {
            match result {
                Ok(message) => Some(Ok(Event::default().data(message))),
                Err(broadcast::error::RecvError::Closed) => None,
                Err(broadcast::error::RecvError::Lagged(_)) => {
                    Some(Ok(Event::default().data("warning: messages dropped")))
                }
            }
        });

    Sse::new(stream)
}

// 2. Add CORS headers for cross-origin requests
use axum::http::HeaderMap;

async fn sse_with_cors() -> (HeaderMap, Sse<impl Stream<Item = Result<Event, Infallible>>>) {
    let mut headers = HeaderMap::new();
    headers.insert("Access-Control-Allow-Origin", "*".parse().unwrap());
    headers.insert("Cache-Control", "no-cache".parse().unwrap());
    headers.insert("Connection", "keep-alive".parse().unwrap());

    let stream = stream::repeat_with(|| {
        tokio::time::sleep(Duration::from_secs(5)).await;
        Ok(Event::default().data("ping"))
    });

    (headers, Sse::new(stream))
}

// 3. Handle different event types
#[derive(Serialize)]
struct TypedEvent {
    event_type: String,
    payload: serde_json::Value,
    timestamp: u64,
}

async fn typed_events_sse() -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    let stream = IntervalStream::new(tokio::time::interval(Duration::from_secs(3)))
        .enumerate()
        .map(|(i, _)| {
            let event_data = TypedEvent {
                event_type: if i % 2 == 0 { "info".to_string() } else { "warning".to_string() },
                payload: serde_json::json!({ "counter": i }),
                timestamp: std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap()
                    .as_secs(),
            };

            let json_data = serde_json::to_string(&event_data).unwrap();
            let event_name = event_data.event_type.clone();

            Ok(Event::default()
                .event(event_name)
                .data(json_data))
        });

    Sse::new(stream)
}
