    pub fn new(kind: ErrorKind, message: impl Into<String>) -> Self {
        Self {
            kind,
            message: message.into(),
            source: None,
        }
    }

    pub fn with_source(
        kind: ErrorKind, 
        message: impl Into<String>, 
        source: Box<dyn std::error::Error + Send + Sync>
