}

impl fmt::Display for RichError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "[{}] {}", self.code, self.message)?;
        if !self.context.is_empty() {
            write!(f, " (context: ")?;
            for (key, value) in &self.context {
                write!(f, "{}={}, ", key, value)?;
            }
            write!(f, ")")?;
        }
        Ok(())
    }
}
```

