```rust
use std::time::{Duration, Instant};
use std::thread;

fn cpu_intensive_work(n: u64) -> u64 {
    // Simulate CPU-intensive work that blocks the thread
    let mut result = 0;
    for i in 0..n {
        result += i * i;
        // This would block if run on async runtime thread!
        if i % 1000000 == 0 {
            thread::sleep(Duration::from_micros(1));  // Simulate work
        }
    }
    result
}

fn blocking_file_operation() -> String {
