    let start = Instant::now();

    // Spawn multiple blocking tasks - they run on separate thread pool
    let handles: Vec<_> = (1..=3)
        .map(|n| tokio::task::spawn_blocking(move || cpu_intensive_work(n * 10000000)))
        .collect();

    // Also spawn a blocking I/O task
    let file_handle = tokio::task::spawn_blocking(blocking_file_operation);

    // Wait for all blocking tasks to complete
    let results = futures::future::join_all(handles).await;
    let file_result = file_handle.await.unwrap();

    let duration = start.elapsed();
    println!("Blocking processing took: {:?}", duration);

    for result in results {
        println!("CPU result: {}", result.unwrap());
    }
