    sleep(Duration::from_secs(3)).await;

    // Clean shutdown
    drop(tx);  // Close the sender

    // Wait for all tasks to complete
    for handle in handles {
        handle.await.unwrap();
    }
}

async fn worker_task(
    tx: Arc<broadcast::Sender<BroadcastMessage>>,
    mut rx: broadcast::Receiver<BroadcastMessage>,
    id: usize,
) {
    // Task that both sends and receives messages
    let mut counter = 0;

    loop {
        tokio::select! {
            // Send a message every 2 seconds
            _ = sleep(Duration::from_secs(2)) => {
                counter += 1;
                let message = BroadcastMessage {
                    id: counter,
                    content: format!("Message from worker {}", id),
                    timestamp: std::time::SystemTime::now()
                        .duration_since(std::time::UNIX_EPOCH)
                        .unwrap()
                        .as_secs(),
                };

                match tx.send(message) {
                    Ok(receivers) => {
                        println!("Worker {} sent message to {} receivers", id, receivers);
                    }
                    Err(_) => {
                        println!("Worker {} - channel closed, shutting down", id);
                        break;
                    }
                }
            }

            // Receive messages
            result = rx.recv() => {
                match result {
                    Ok(message) => {
                        if message.content.contains(&format!("worker {}", id)) {
                            // Don't print our own messages to reduce noise
                            continue;
                        }
                        println!("Worker {} received: [{}] {}", 
                                id, message.id, message.content);
                    }
                    Err(broadcast::error::RecvError::Closed) => {
                        println!("Worker {} - channel closed", id);
                        break;
                    }
                    Err(broadcast::error::RecvError::Lagged(skipped)) => {
                        println!("Worker {} - lagged behind, skipped {} messages", id, skipped);
                    }
                }
            }
        }
    }

    println!("Worker {} finished", id);
}
