use tokio::sync::broadcast;
use tokio::time::{sleep, Duration};
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

#[derive(Debug, Clone)]
struct ChatMessage {
    user_id: u32,
    username: String,
    content: String,
    timestamp: u64,
    message_type: MessageType,
}

#[derive(Debug, Clone)]
enum MessageType {
    Text,
    Join,
    Leave,
    System,
}

struct ChatRoom {
    tx: broadcast::Sender<ChatMessage>,
    users: Arc<Mutex<HashMap<u32, String>>>,  // user_id -> username
}

impl ChatRoom {
    fn new() -> Self {
        let (tx, _rx) = broadcast::channel(1000);
        Self {
            tx,
            users: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn subscribe(&self) -> broadcast::Receiver<ChatMessage> {
        self.tx.subscribe()
    }

    fn add_user(&self, user_id: u32, username: String) {
        self.users.lock().unwrap().insert(user_id, username.clone());

        let join_message = ChatMessage {
            user_id,
            username,
            content: "joined the chat".to_string(),
            timestamp: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_secs(),
            message_type: MessageType::Join,
        };

        let _ = self.tx.send(join_message);
    }

    fn remove_user(&self, user_id: u32) -> Option<String> {
        let username = self.users.lock().unwrap().remove(&user_id);
        if let Some(ref name) = username {
            let leave_message = ChatMessage {
                user_id,
                username: name.clone(),
                content: "left the chat".to_string(),
                timestamp: std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap()
                    .as_secs(),
                message_type: MessageType::Leave,
            };

            let _ = self.tx.send(leave_message);
        }
        username
    }

    fn send_message(&self, user_id: u32, content: String) -> Result<usize, broadcast::error::SendError<ChatMessage>> {
        let username = {
            self.users.lock().unwrap()
                .get(&user_id)
                .cloned()
                .unwrap_or_else(|| "Unknown".to_string())
        };

        let message = ChatMessage {
            user_id,
            username,
            content,
            timestamp: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_secs(),
            message_type: MessageType::Text,
        };

        self.tx.send(message)
    }
}

