// 1. Handle receiver lag gracefully
async fn handle_lag_gracefully() {
    let (tx, _rx) = broadcast::channel::<String>(3);

    let rx = tx.subscribe();
    tokio::spawn(async move {
        let mut receiver = rx;
        loop {
            match receiver.recv().await {
                Ok(message) => println!("Received: {}", message),
                Err(broadcast::error::RecvError::Lagged(skipped)) => {
                    println!("Warning: Skipped {} messages due to lag", skipped);
                }
                Err(broadcast::error::RecvError::Closed) => {
                    println!("Channel closed");
                    break;
                }
            }
        }
    });

    // Send messages faster than receiver can handle
    for i in 1..=10 {
        let _ = tx.send(format!("Message {}", i));
        sleep(Duration::from_millis(50)).await;
    }

    sleep(Duration::from_secs(2)).await;
}

// 2. Use broadcast for pub/sub patterns
struct EventBus<T: Clone> {
    tx: broadcast::Sender<T>,
