async fn broadcast_with_shutdown() {
    let (tx, _rx) = broadcast::channel::<String>(10);
    let shutdown_tx = Arc::new(tx);

    // Worker tasks
    for i in 1..=3 {
        let rx = shutdown_tx.subscribe();
        tokio::spawn(async move {
            worker_with_shutdown(rx, i).await;
        });
