use std::time::Instant;

fn performance_comparison() {
    // Inefficient: Using push in a loop
    let start = Instant::now();
    let mut vec1 = Vec::new();
    for i in 0..10000 {
        vec1.push(i);
    }
    let push_time = start.elapsed();

    // Efficient: Using extend
    let start = Instant::now();
    let mut vec2 = Vec::new();
    vec2.extend(0..10000);
    let extend_time = start.elapsed();

    println!("Push time: {:?}", push_time);
    println!("Extend time: {:?}", extend_time);

    // extend is typically faster because it can pre-allocate
    assert_eq!(vec1.len(), vec2.len());
}
