        return Err(StatusCode::NOT_FOUND);
    }

    Ok(Json(json!({
        "id": id,
        "name": format!("User {}", id)
    })))
}

async fn list_users(Query(pagination): Query<Pagination>) -> Json<serde_json::Value> {
    let page = pagination.page.unwrap_or(1);
    let limit = pagination.limit.unwrap_or(10);

    Json(json!({
        "page": page,
        "limit": limit,
        "users": (0..limit).map(|i| format!("User {}", (page - 1) * limit + i + 1)).collect::<Vec<_>>()
    }))
}

#[tokio::test]
async fn test_path_and_query_params() {
    let app = Router::new()
        .route("/users/:id", get(get_user))
        .route("/users", get(list_users));

    // Test path parameter
    let response = app
        .oneshot(Request::builder().uri("/users/42").body(Body::empty()).unwrap())
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::OK);
    let body = hyper::body::to_bytes(response.into_body()).await.unwrap();
    let user: serde_json::Value = serde_json::from_slice(&body).unwrap();
    assert_eq!(user["id"], 42);
    assert_eq!(user["name"], "User 42");

    // Test not found
    let response = app
        .oneshot(Request::builder().uri("/users/0").body(Body::empty()).unwrap())
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::NOT_FOUND);

    // Test query parameters
    let response = app
        .oneshot(Request::builder().uri("/users?page=2&limit=5").body(Body::empty()).unwrap())
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::OK);
    let body = hyper::body::to_bytes(response.into_body()).await.unwrap();
    let result: serde_json::Value = serde_json::from_slice(&body).unwrap();
    assert_eq!(result["page"], 2);
    assert_eq!(result["limit"], 5);
    assert_eq!(result["users"].as_array().unwrap().len(), 5);
}
