#### 🎨 Testing Authentication Middleware

```rust
use axum::{
    async_trait,
    extract::FromRequestParts,
    http::{header, request::Parts, HeaderMap, Request, StatusCode},
    middleware::{from_fn, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use serde_json::json;
use std::collections::HashMap;
use tower::ServiceExt;

#[derive(Clone)]
struct AppState {
    api_keys: HashMap<String, String>, // key -> user_id
}

async fn auth_middleware(
    headers: HeaderMap,
    State(state): State<AppState>,
    next: Next,
) -> Result<Response, StatusCode> {
    let auth_header = headers
        .get(header::AUTHORIZATION)
        .and_then(|header| header.to_str().ok())
        .and_then(|header| header.strip_prefix("Bearer "))
        .ok_or(StatusCode::UNAUTHORIZED)?;

    if state.api_keys.contains_key(auth_header) {
        Ok(next.run(Request::new(Body::empty())).await)
    } else {
        Err(StatusCode::UNAUTHORIZED)
    }
}

async fn protected_route() -> Json<serde_json::Value> {
    Json(json!({"message": "Access granted"}))
}

#[tokio::test]
async fn test_auth_middleware() {
    let mut api_keys = HashMap::new();
    api_keys.insert("valid-key".to_string(), "user-123".to_string());

    let state = AppState { api_keys };
    let app = Router::new()
        .route("/protected", get(protected_route))
        .layer(from_fn(auth_middleware))
        .with_state(state);

    // Test without auth header
    let response = app
        .oneshot(Request::builder().uri("/protected").body(Body::empty()).unwrap())
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::UNAUTHORIZED);

    // Test with invalid auth header
    let response = app
        .oneshot(
            Request::builder()
                .uri("/protected")
                .header(header::AUTHORIZATION, "Bearer invalid-key")
                .body(Body::empty())
                .unwrap(),
        )
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::UNAUTHORIZED);

    // Test with valid auth header
    let response = app
        .oneshot(
            Request::builder()
                .uri("/protected")
                .header(header::AUTHORIZATION, "Bearer valid-key")
                .body(Body::empty())
                .unwrap(),
        )
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::OK);
    let body = hyper::body::to_bytes(response.into_body()).await.unwrap();
    let result: serde_json::Value = serde_json::from_slice(&body).unwrap();
    assert_eq!(result["message"], "Access granted");
}
```

