```rust
// Conceptual implementation of Arc drop behavior
impl<T> Drop for Arc<T> {
    fn drop(&mut self) {
        // Decrement the reference count
        if self.dec_ref_count() == 0 {
            // This was the LAST reference!
            // ✨ Now we can safely drop the data ✨
            unsafe {
                // Drop the actual data T
                std::ptr::drop_in_place(self.data_ptr);
                // Deallocate the Arc control block
                deallocate(self.control_block_ptr);
            }
        }
        // If ref count > 0, do nothing - other Arcs still exist
    }
}

// The control block looks something like this:
struct ArcControlBlock {
    ref_count: AtomicUsize,
    data: T,  // Your actual data
}
