        .fetch_all(db)
        .await?;

    let mut posts_with_authors = Vec::new();

    // N queries: For each post, get the author
    for post in posts {
        let author: User = sqlx::query_as("SELECT * FROM users WHERE id = $1")
            .bind(post.author_id)
            .fetch_one(db)
            .await?;

        posts_with_authors.push(PostWithAuthor { post, author });
    }

    Ok(posts_with_authors)
}

