    let posts_with_authors: Vec<PostWithAuthor> = sqlx::query_as(
        r#"
        SELECT 
            posts.id as post_id,
            posts.title,
            posts.content,
            posts.author_id,
            users.id as user_id,
            users.name,
            users.email
        FROM posts 
        JOIN users ON posts.author_id = users.id
        ORDER BY posts.id
        "#
    )
    .fetch_all(db)
    .await?;

