// Using DataLoader pattern (GraphQL style)
use std::collections::HashMap;

struct DataLoader<K, V> {
    load_fn: Box<dyn Fn(Vec<K>) -> HashMap<K, V>>,
    cache: HashMap<K, V>,
}

impl<K, V> DataLoader<K, V> 
where 
    K: Eq + std::hash::Hash + Clone,
    V: Clone,
{
    fn new<F>(load_fn: F) -> Self 
    where 
        F: Fn(Vec<K>) -> HashMap<K, V> + 'static
    {
        Self {
            load_fn: Box::new(load_fn),
            cache: HashMap::new(),
        }
    }

    async fn load(&mut self, keys: Vec<K>) -> HashMap<K, V> {
        // Filter out cached keys
        let missing_keys: Vec<K> = keys
            .into_iter()
            .filter(|k| !self.cache.contains_key(k))
            .collect();

        // Load missing data in batch
        if !missing_keys.is_empty() {
            let new_data = (self.load_fn)(missing_keys);
            self.cache.extend(new_data);
        }

        // Return requested data
        keys.into_iter()
            .filter_map(|k| self.cache.get(&k).cloned().map(|v| (k, v)))
            .collect()
    }
}

