fn arc_lifecycle() {
    // Create the first Arc - reference count = 1
    let data = Arc::new(vec![1, 2, 3]);
    println!("Count after creation: {}", Arc::strong_count(&data)); // 1

    // Clone the Arc - reference count = 2
