```rust
use tokio::sync::broadcast;
use std::sync::Arc;
use std::collections::HashMap;

struct HITLManager {
    checkpoints: Arc<std::sync::RwLock<HashMap<String, HITLCheckpoint>>>,
    tx: broadcast::Sender<HITLNotification>,
}

#[derive(Debug, Clone)]
pub enum HITLNotification {
    Created { checkpoint_id: String },
    Approved { checkpoint_id: String },
    Rejected { checkpoint_id: String, reason: String },
    Expired { checkpoint_id: String },
}

impl HITLManager {
    fn new() -> Self {
        let (tx, _rx) = broadcast::channel(100);
        Self {
            checkpoints: Arc::new(std::sync::RwLock::new(HashMap::new())),
            tx,
        }
    }

    async fn create_checkpoint(&self, reason: String, metadata: Value) -> Result<String, Error> {
        let checkpoint_id = uuid::Uuid::new_v4().to_string();
        let checkpoint = HITLCheckpoint {
            id: checkpoint_id.clone(),
            reason,
            metadata,
            created_at: std::time::SystemTime::now(),
            status: HITLStatus::Pending,
        };

        // Store the checkpoint
        {
            let mut checkpoints = self.checkpoints.write().unwrap();
            checkpoints.insert(checkpoint_id.clone(), checkpoint);
        }

        // Notify listeners (UI, monitoring, etc.)
        let _ = self.tx.send(HITLNotification::Created {
            checkpoint_id: checkpoint_id.clone(),
        });

        // ✨ This is where the magic happens - notify human operators!
        notify_human_operators(&checkpoint_id).await?;

        Ok(checkpoint_id)
    }

    async fn approve_checkpoint(&self, checkpoint_id: &str) -> Result<(), Error> {
        {
            let mut checkpoints = self.checkpoints.write().unwrap();
            if let Some(checkpoint) = checkpoints.get_mut(checkpoint_id) {
                checkpoint.status = HITLStatus::Approved;
            }
        }

        let _ = self.tx.send(HITLNotification::Approved {
            checkpoint_id: checkpoint_id.to_string(),
        });

        Ok(())
    }

    async fn reject_checkpoint(&self, checkpoint_id: &str, reason: String) -> Result<(), Error> {
        {
            let mut checkpoints = self.checkpoints.write().unwrap();
            if let Some(checkpoint) = checkpoints.get_mut(checkpoint_id) {
                checkpoint.status = HITLStatus::Rejected;
            }
        }

        let _ = self.tx.send(HITLNotification::Rejected {
            checkpoint_id: checkpoint_id.to_string(),
            reason,
        });

        Ok(())
    }
}

// Notification system for human operators
async fn notify_human_operators(checkpoint_id: &str) -> Result<(), Error> {
    // Send notification via multiple channels
    tokio::join!(
        send_webhook_notification(checkpoint_id),
        send_email_notification(checkpoint_id),
        update_dashboard_ui(checkpoint_id),
        log_audit_event(checkpoint_id)
    );

    Ok(())
}
