// Batch processing of checkpoints
async fn batch_process_checkpoints(checkpoint_ids: Vec<String>) -> Result<(), Error> {
    // Process multiple checkpoints in parallel
    let results: Vec<_> = checkpoint_ids
        .into_iter()
        .map(|id| async move {
            match process_single_checkpoint(&id).await {
                Ok(_) => Ok(id),
                Err(e) => Err((id, e)),
            }
        })
        .collect();

    let (successes, failures): (Vec<_>, Vec<_>) = results.into_iter().partition(Result::is_ok);

    log_batch_results(successes, failures).await?;
    Ok(())
}
