async fn tiered_security_strategy(input: SecurityInput) -> Result<Outcome, Error> {
    let risk_score = calculate_risk_score(&input);

    if risk_score > 90.0 {
        // Executive approval required for very high risk
        return Ok(Outcome::Pause {
            reason: "Critical risk operation".to_string(),
            context: serde_json::json!({
                "risk_score": risk_score,
                "operation": input.operation,
                "user_id": input.user_id,
                "details": input.details,
            }),
        });
    } else if risk_score > 70.0 {
        // Senior approval required for high risk
        return Ok(Outcome::Pause {
            reason: "High risk operation requires senior review".to_string(),
            context: serde_json::json!({
                "risk_score": risk_score,
                "operation": input.operation,
                "user_id": input.user_id,
            }),
        });
    } else if risk_score > 50.0 {
        // Standard approval for moderate risk
        return Ok(Outcome::Pause {
            reason: "Moderate risk operation requires review".to_string(),
            context: serde_json::json!({
                "risk_score": risk_score,
                "operation": input.operation,
                "user_id": input.user_id,
            }),
        });
    }

    // Low risk - proceed automatically
    Ok(Outcome::Continue(serde_json::json!({
        "status": "low_risk_approved",
        "risk_score": risk_score
    })))
