    required_approvers: Vec<String>
) -> Result<String, Error> {
    let workflow_id = generate_workflow_id();

    // Create individual approval requests for each approver
    for approver in required_approvers {
        let approval_id = create_individual_approval(
            workflow_id.clone(),
            approver,
            reason.clone(),
            context.clone()
        ).await?;

        notify_approver(approval_id).await?;
    }

    Ok(workflow_id)
}

// Approval with consensus
async fn await_consensus_approval(workflow_id: String) -> Result<Approval, Error> {
    let required_approvals = get_required_approvals(&workflow_id).await?;
    let mut approvals = 0;
    let mut rejections = 0;

    loop {
        let current_status = get_workflow_status(&workflow_id).await?;

        match current_status {
            WorkflowStatus::Approved => approvals += 1,
            WorkflowStatus::Rejected => rejections += 1,
            WorkflowStatus::Pending => continue,
        }

        // Check consensus rules
        if approvals >= required_approvals {
            return Ok(Approval::Approved);
        }

        if rejections > 0 {
            return Ok(Approval::Rejected);
        }

        tokio::time::sleep(Duration::from_secs(1)).await;
    }
}
