```rust
use tokio::time::{sleep, Duration, Instant};
use futures::stream::Stream;
use std::pin::Pin;

pub struct LoopRunner {
    max_retries: usize,
    backoff_strategy: BackoffStrategy,
    timeout: Option<Duration>,
}

pub enum LoopAction<T> {
    Continue(T),
    Retry { delay: Duration, error: Error },
    Terminate { reason: String },
    Skip,
    Backoff { duration: Duration },
}

pub enum TerminationReason {
    Completed,           // Stream ended naturally
    Error(String),       // Fatal error occurred
    Timeout,             // Operation timed out
    Cancelled,           // External cancellation
    Manual,              // Manual shutdown requested
}

impl LoopRunner {
    pub fn new() -> Self {
        Self {
            max_retries: 3,
            backoff_strategy: BackoffStrategy::Exponential,
            timeout: None,
        }
    }

    pub async fn run<S, F, Fut, T>(
        &mut self,
        mut stream: S,
        mut processor: F,
    ) -> Result<TerminationReason, Error>
    where
        S: Stream + Unpin,
        F: FnMut(S::Item) -> Fut,
        Fut: std::future::Future<Output = LoopAction<T>>,
    {
        let start_time = Instant::now();
        let mut retry_count = 0;
        let mut backoff_delay = Duration::from_millis(100);

        loop {
            // Check timeout
            if let Some(timeout) = self.timeout {
                if start_time.elapsed() > timeout {
                    return Ok(TerminationReason::Timeout);
                }
            }

            // Poll the stream
            match stream.next().await {
                Some(item) => {
                    match processor(item).await {
                        LoopAction::Continue(result) => {
                            // ✨ Process result and continue
                            self.handle_success(result).await?;
                            retry_count = 0; // Reset retry counter
                            backoff_delay = Duration::from_millis(100); // Reset backoff
                        }
                        LoopAction::Retry { delay, error } => {
                            // ✨ Handle retry with backoff
                            if retry_count >= self.max_retries {
                                return Ok(TerminationReason::Error(
                                    format!("Max retries exceeded: {}", error)
                                ));
                            }
                            retry_count += 1;
                            sleep(delay).await;
                        }
                        LoopAction::Terminate { reason } => {
                            // ✨ Graceful termination requested
                            self.cleanup().await?;
                            return Ok(TerminationReason::Manual);
                        }
                        LoopAction::Skip => {
                            // Skip this item and continue
                            continue;
                        }
                        LoopAction::Backoff { duration } => {
                            // Apply backoff strategy
                            sleep(duration).await;
                            backoff_delay = self.apply_backoff(backoff_delay);
                        }
                    }
                }
                None => {
                    // ✨ Stream completed naturally
                    self.cleanup().await?;
                    return Ok(TerminationReason::Completed);
                }
            }
        }
    }

    async fn handle_success<T>(&self, result: T) -> Result<(), Error> {
        // Handle successful processing
        println!("✅ Successfully processed item");
        // Log metrics, update state, etc.
        Ok(())
    }

    async fn cleanup(&self) -> Result<(), Error> {
        // ✨ Graceful cleanup on termination
        println!("🧹 Cleaning up resources...");
        // Close connections, flush buffers, save state, etc.
        Ok(())
    }

    fn apply_backoff(&self, current_delay: Duration) -> Duration {
        match self.backoff_strategy {
            BackoffStrategy::Exponential => current_delay * 2,
            BackoffStrategy::Linear => current_delay + Duration::from_millis(100),
            BackoffStrategy::Fixed => current_delay,
        }
    }
}
```

