struct Message {
    id: String,
    payload: String,
    priority: u8,
    retry_count: usize,
}

impl MessageProcessor {
    async fn process_message(&mut self, message: Message) -> LoopAction<()> {
        match self.handle_message(&message).await {
            Ok(_) => {
                self.processed_count += 1;
                println!("✅ Processed message {}", message.id);
                LoopAction::Continue(())
            }
            Err(e) if message.retry_count < 3 => {
                // Retry with exponential backoff
                let delay = Duration::from_millis(100 * 2_u64.pow(message.retry_count as u32));
                println!("⚠️  Retrying message {} (attempt {})", message.id, message.retry_count + 1);
                LoopAction::Retry {
                    delay,
                    error: e,
                }
            }
            Err(e) => {
                self.error_count += 1;
                println!("❌ Failed to process message {}: {}", message.id, e);

                // Dead letter queue handling
                self.send_to_dead_letter_queue(&message).await?;

                if self.error_count > 100 {
                    // Too many errors - terminate for investigation
                    LoopAction::Terminate {
                        reason: "Too many processing errors".to_string(),
                    }
                } else {
                    LoopAction::Skip
                }
            }
        }
    }

    async fn run(&mut self) -> Result<TerminationReason, Error> {
        let stream = futures::stream::unfold(&mut self.queue_receiver, |rx| async {
            rx.recv().await.map(|msg| (msg, rx))
        });

        self.runner.run(stream, |message| {
            self.process_message(message)
        }).await
    }

