use tokio::sync::broadcast;
use std::time::SystemTime;

struct DataPipeline {
    input_stream: broadcast::Receiver<DataPoint>,
    runner: LoopRunner,
    metrics: PipelineMetrics,
}

#[derive(Debug, Clone)]
struct DataPoint {
    timestamp: SystemTime,
    value: f64,
    source: String,
    metadata: serde_json::Value,
}

#[derive(Debug)]
struct PipelineMetrics {
    processed_count: usize,
    error_count: usize,
    last_processed: Option<SystemTime>,
    throughput: f64, // items/second
}

impl DataPipeline {
    async fn process_data_point(&mut self, data_point: DataPoint) -> LoopAction<ProcessedData> {
        let start_time = SystemTime::now();

        match self.transform_data(data_point).await {
            Ok(processed) => {
                self.metrics.processed_count += 1;
                self.metrics.last_processed = Some(start_time);

                // Calculate throughput
                if let Some(last) = self.metrics.last_processed {
                    let elapsed = start_time.duration_since(last).unwrap_or_default();
                    self.metrics.throughput = 1.0 / elapsed.as_secs_f64();
                }

                LoopAction::Continue(processed)
            }
            Err(Error::Transient(e)) => {
                self.metrics.error_count += 1;
                println!("⚠️  Transient error processing data: {}", e);

                // Backoff for transient errors
                LoopAction::Backoff {
                    duration: Duration::from_millis(500),
                }
            }
            Err(Error::Fatal(e)) => {
                self.metrics.error_count += 1;
                println!("❌ Fatal error in pipeline: {}", e);

                // Terminate pipeline for fatal errors
                LoopAction::Terminate {
                    reason: format!("Fatal pipeline error: {}", e),
                }
            }
        }
    }

    async fn transform_data(&self, data_point: DataPoint) -> Result<ProcessedData, Error> {
        // Simulate data transformation
        sleep(Duration::from_millis(10)).await;

        // Simulate occasional errors
        if data_point.value.is_nan() {
            return Err(Error::Fatal("Invalid data value (NaN)".into()));
        }

        if data_point.value < 0.0 {
            return Err(Error::Transient("Negative value requires validation".into()));
        }

        Ok(ProcessedData {
            original: data_point,
            transformed_value: data_point.value * 2.0,
            processed_at: SystemTime::now(),
        })
    }

    async fn run(&mut self) -> Result<TerminationReason, Error> {
        let stream = futures::stream::unfold(&mut self.input_stream, |rx| async {
            match rx.recv().await {
                Ok(data) => Some((data, rx)),
                Err(broadcast::error::RecvError::Closed) => None,
                Err(broadcast::error::RecvError::Lagged(_)) => {
                    println!("⚠️  Pipeline lagging behind data stream");
                    // Continue processing - this is handled by the broadcast channel
                    None
                }
            }
        });

        self.runner.run(stream, |data_point| {
            self.process_data_point(data_point)
        }).await
    }
}

#[derive(Debug)]
struct ProcessedData {
    original: DataPoint,
    transformed_value: f64,
    processed_at: SystemTime,
