// Cancellation support
use tokio::signal;
use tokio::sync::oneshot;

impl LoopRunner {
    pub async fn run_with_cancellation<S, F, Fut, T>(
        &mut self,
        stream: S,
        processor: F,
    ) -> Result<TerminationReason, Error>
    where
        S: Stream + Unpin,
        F: FnMut(S::Item) -> Fut,
        Fut: std::future::Future<Output = LoopAction<T>>,
    {
        // Set up cancellation signal
        let (cancel_tx, mut cancel_rx) = oneshot::channel();

        // Spawn signal handler
        tokio::spawn(async move {
            signal::ctrl_c().await.expect("Failed to listen for ctrl-c");
            let _ = cancel_tx.send(());
        });

        // Run with cancellation support
        tokio::select! {
            result = self.run(stream, processor) => {
                result
            }
            _ = &mut cancel_rx => {
                println!("🛑 Received cancellation signal");
                self.cleanup().await?;
                Ok(TerminationReason::Cancelled)
            }
        }
    }
}

// Health checking
impl LoopRunner {
    pub async fn run_with_health_check<S, F, Fut, T>(
        &mut self,
        stream: S,
        processor: F,
        health_check_interval: Duration,
    ) -> Result<TerminationReason, Error>
    where
        S: Stream + Unpin,
        F: FnMut(S::Item) -> Fut,
        Fut: std::future::Future<Output = LoopAction<T>>,
    {
        let (health_tx, mut health_rx) = mpsc::channel(1);

        // Spawn health checker
        let health_handle = tokio::spawn(async move {
            loop {
                sleep(health_check_interval).await;
                if health_tx.send(()).await.is_err() {
                    break; // Channel closed
                }
            }
        });

        // Run main loop
        let result = self.run(stream, processor).await;

        // Clean up health checker
        health_handle.abort();

        result
    }
}

