impl CircuitBreaker {
    async fn run_with_circuit_breaker<F, Fut, T>(
        &self,
        runner: &mut LoopRunner,
        stream: impl Stream + Unpin,
        processor: F,
    ) -> Result<TerminationReason, Error>
    where
        F: FnMut(<impl Stream as Stream>::Item) -> Fut,
        Fut: std::future::Future<Output = LoopAction<T>>,
    {
