            return Err(Error::CircuitBreakerOpen);
        }

        let result = runner.run(stream, processor).await;

        match &result {
            Ok(TerminationReason::Error(_)) => {
                self.record_failure().await;
            }
            Ok(_) => {
                self.reset().await;
            }
            Err(_) => {
                self.record_failure().await;
            }
        }

        result
    }
}

