impl StrategyRegistry {
    // ✨ This is the core lookup mechanism
    pub fn lookup(&self, strategy_name: &str) -> Option<Arc<dyn Strategy>> {
        // 1. Acquire read lock (allows concurrent reads)
        let strategies = self.strategies.read().unwrap();

        // 2. Look up by name in the HashMap
        //    This is O(1) average case!
        let strategy_ref = strategies.get(strategy_name);

        // 3. Clone the Arc (cheap - just increments reference count)
        strategy_ref.cloned()

        // 4. Return the cloned Arc<dyn Strategy> or None
    }
}

