        strategies.values()
            .filter(|strategy| {
                // Check if strategy has all required capabilities
                let metadata = self.get_metadata(strategy.name()).unwrap_or_default();
                required_capabilities.iter().all(|cap| metadata.capabilities.contains(&cap.to_string()))
            })
            .cloned()
            .collect()
    }

    // ✨ Version-aware lookup
    pub fn lookup_version(&self, name: &str, version: Option<&str>) -> Option<Arc<dyn Strategy>> {
        let strategies = self.strategies.read().unwrap();

        if let Some(version) = version {
            // Look for specific version
            strategies.get(&format!("{}@{}", name, version)).cloned()
        } else {
            // Look for latest version
            strategies.get(name).cloned()
        }
    }

    // ✨ Fallback strategy lookup
    pub fn lookup_with_fallback(&self, primary: &str, fallback: &str) -> Option<Arc<dyn Strategy>> {
        self.lookup(primary).or_else(|| self.lookup(fallback))
    }
}

