// 2. Strategy caching for performance
use std::time::{Duration, Instant};

pub struct CachedStrategyLookup {
    registry: StrategyRegistry,
    cache: Arc<RwLock<lru::LruCache<String, (Arc<dyn Strategy>, Instant)>>>,
    ttl: Duration,
}

impl CachedStrategyLookup {
    pub fn lookup_cached(&self, name: &str) -> Option<Arc<dyn Strategy>> {
        // Check cache first
        {
            let cache = self.cache.read().unwrap();
            if let Some((strategy, timestamp)) = cache.peek(name) {
                if timestamp.elapsed() < self.ttl {
                    return Some(strategy.clone());
                }
            }
        }

        // Cache miss - look up in registry
        if let Some(strategy) = self.registry.lookup(name) {
            // Update cache
            let mut cache = self.cache.write().unwrap();
            cache.put(name.to_string(), (strategy.clone(), Instant::now()));
            Some(strategy)
        } else {
            None
        }
    }
}

