#### 🧱 The Complete Bridge Architecture

```rust
use tokio::sync::{mpsc, broadcast};
use std::time::Instant;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum ApprovalResult {
    Approved {
        approved_by: String,
        timestamp: Instant,
        metadata: serde_json::Value,
    },
    Rejected {
        rejected_by: String,
        reason: String,
        timestamp: Instant,
    },
    Timeout {
        duration: std::time::Duration,
    },
    Cancelled,
}

pub struct HITLSender {
    tx: mpsc::Sender<ApprovalResult>,
}

pub struct HITLReceiver {
    rx: broadcast::Receiver<ApprovalResult>,
}

impl HITLSender {
    pub fn new(tx: mpsc::Sender<ApprovalResult>) -> Self {
        Self { tx }
    }

    pub async fn send(&self, result: ApprovalResult) -> Result<(), mpsc::error::SendError<ApprovalResult>> {
        self.tx.send(result).await
    }
}

impl HITLReceiver {
    pub fn new(rx: broadcast::Receiver<ApprovalResult>) -> Self {
        Self { rx }
    }

    pub async fn recv(&mut self) -> Result<ApprovalResult, broadcast::error::RecvError> {
        self.rx.recv().await
    }

    // ✨ Allow cloning for multiple subscribers
    pub fn clone(&self) -> Self {
        Self {
            rx: self.rx.resubscribe(),
        }
    }
}

// ✨ The magic bridge function!
pub fn spawn_hitl_continuation(
    buffer_size: usize,
) -> (HITLSender, HITLReceiver) {
    // 1. Create broadcast channel for multiple listeners
    let (broadcast_tx, broadcast_rx) = broadcast::channel::<ApprovalResult>(buffer_size);

    // 2. Create mpsc channel for single HITL responder
    let (mpsc_tx, mut mpsc_rx) = mpsc::channel::<ApprovalResult>(1);

    // 3. ✨ Spawn the bridge task that connects mpsc to broadcast
    let broadcast_tx_clone = broadcast_tx.clone();
    tokio::spawn(async move {
        println!("🌉 HITL bridge started - bridging mpsc to broadcast");

        // 4. Bridge loop: receive from mpsc, send to broadcast
        while let Some(result) = mpsc_rx.recv().await {
            println!("🌉 Bridging HITL result to {} subscribers", broadcast_tx_clone.receiver_count());

            // 5. ✨ Send to ALL broadcast subscribers
            match broadcast_tx_clone.send(result) {
                Ok(receivers) => {
                    println!("🌉 HITL result delivered to {} receivers", receivers);
                }
                Err(broadcast::error::SendError(result)) => {
                    println!("🌉 No subscribers for HITL result: {:?}", result);
                    // Result dropped - no one was listening
                }
            }
        }

        println!("🌉 HITL bridge closing - mpsc channel closed");
        // 6. When mpsc closes, broadcast channel also closes
        drop(broadcast_tx_clone);
    });

    // 7. Return sender (mpsc) and receiver (broadcast) handles
    (HITLSender::new(mpsc_tx), HITLReceiver::new(broadcast_rx))
}
