// Bridge with timeout and fallback handling
pub fn spawn_hitl_continuation_with_timeout(
    buffer_size: usize,
    timeout: Duration,
) -> (HITLSender, HITLReceiver) {
    let (broadcast_tx, broadcast_rx) = broadcast::channel::<ApprovalResult>(buffer_size);
    let (mpsc_tx, mut mpsc_rx) = mpsc::channel::<ApprovalResult>(1);

    let broadcast_tx_clone = broadcast_tx.clone();
    tokio::spawn(async move {
        tokio::select! {
            // Normal operation - bridge mpsc to broadcast
            _ = async {
                while let Some(result) = mpsc_rx.recv().await {
                    let _ = broadcast_tx_clone.send(result);
                }
            } => {
                println!("🌉 Bridge completed normally");
            }
            // Timeout handling
            _ = sleep(timeout) => {
                println!("⏰ Bridge timeout - sending timeout result");
                let timeout_result = ApprovalResult::Timeout { duration: timeout };
                let _ = broadcast_tx_clone.send(timeout_result);
            }
        }

        drop(broadcast_tx_clone);
    });

    (HITLSender::new(mpsc_tx), HITLReceiver::new(broadcast_rx))
}

// Bridge with retry logic
pub fn spawn_hitl_continuation_with_retry(
    buffer_size: usize,
    max_retries: usize,
) -> (HITLSender, HITLReceiver) {
    let (broadcast_tx, broadcast_rx) = broadcast::channel::<ApprovalResult>(buffer_size);
    let (mpsc_tx, mut mpsc_rx) = mpsc::channel::<ApprovalResult>(1);

    let broadcast_tx_clone = broadcast_tx.clone();
    tokio::spawn(async move {
        let mut retries = 0;

        while retries <= max_retries {
            match mpsc_rx.recv().await {
                Some(result) => {
                    // ✨ Successful bridge
                    let _ = broadcast_tx_clone.send(result);
                    break; // Success - exit loop
                }
                None => {
                    // Channel closed - retry logic
                    if retries < max_retries {
                        retries += 1;
                        println!("⚠️  Bridge channel closed, retry {}/{}", retries, max_retries);
                        sleep(Duration::from_millis(100 * retries as u64)).await;

                        // Recreate channel for retry
                        let (new_tx, new_rx) = mpsc::channel::<ApprovalResult>(1);
                        mpsc_rx = new_rx;
                        // In real implementation, you'd need to reconnect sender too
                    } else {
                        println!("❌ Bridge failed after {} retries", max_retries);
                        break;
                    }
                }
            }
        }

        drop(broadcast_tx_clone);
    });

    (HITLSender::new(mpsc_tx), HITLReceiver::new(broadcast_rx))
}

