            _ = cancel_token.cancelled() => {
                println!("🛑 Bridge cancelled");
            }
        }

        drop(broadcast_tx_clone);
    });

    (HITLSender::new(mpsc_tx), HITLReceiver::new(broadcast_rx), cancellation_token)
