pub fn spawn_transforming_hitl_continuation<F, T, U>(
    buffer_size: usize,
    transformer: F,
) -> (HITLSender<T>, HITLReceiver<U>)
where
    F: Fn(T) -> U + Send + Sync + 'static,
    T: Send + 'static,
    U: Clone + Send + Sync + 'static,
{
    let (broadcast_tx, broadcast_rx) = broadcast::channel::<U>(buffer_size);
    let (mpsc_tx, mut mpsc_rx) = mpsc::channel::<T>(1);

    let broadcast_tx_clone = broadcast_tx.clone();
