use tokio::sync::{mpsc, broadcast};
use std::collections::HashMap;
use std::sync::Arc;

pub struct HITLContinuationBridge {
    bridges: Arc<std::sync::RwLock<HashMap<String, broadcast::Sender<ApprovalDecision>>>>,
}

impl HITLContinuationBridge {
    pub fn new() -> Self {
        Self {
            bridges: Arc::new(std::sync::RwLock::new(HashMap::new())),
        }
    }

    // ✨ The core bridging function
    pub async fn spawn_hitl_continuation(
        &self,
        approval_id: String,
        mpsc_rx: mpsc::Receiver<ApprovalDecision>
    ) -> Result<broadcast::Sender<ApprovalDecision>, Error> {
        // Create broadcast channel for fan-out
        let (broadcast_tx, _) = broadcast::channel::<ApprovalDecision>(100);
        let broadcast_tx_clone = broadcast_tx.clone();

        // Store the bridge for future lookups
        {
            let mut bridges = self.bridges.write().unwrap();
            bridges.insert(approval_id.clone(), broadcast_tx.clone());
        }

        // ✨ Spawn the bridging task
        tokio::spawn(async move {
            println!("🌉 HITL bridge activated for approval {}", approval_id);

            // Wait for decision on MPSC channel (point-to-point)
            match mpsc_rx.recv().await {
                Some(decision) => {
                    println!("📬 Received decision via MPSC: {:?}", decision);

                    // ✨ Broadcast to all listeners (fan-out)
                    if let Err(e) = broadcast_tx_clone.send(decision.clone()) {
                        println!("⚠️  Broadcast send error: {}", e);
                    } else {
                        println!("📢 Decision broadcast to all listeners");
                    }

                    // Log the broadcast
                    audit_log_broadcast(&approval_id, &decision).await;
                }
                None => {
                    println!("📭 MPSC channel closed for approval {}", approval_id);
                }
            }

            // Cleanup the bridge
            // (In a real implementation, you'd want more sophisticated cleanup)
        });

        Ok(broadcast_tx)
    }

    // ✨ Get existing broadcast sender for an approval
    pub fn get_broadcast_sender(&self, approval_id: &str) -> Option<broadcast::Sender<ApprovalDecision>> {
        let bridges = self.bridges.read().unwrap();
        bridges.get(approval_id).cloned()
    }

    // ✨ Subscribe to an existing approval's broadcast
    pub fn subscribe(&self, approval_id: &str) -> Option<broadcast::Receiver<ApprovalDecision>> {
        self.get_broadcast_sender(approval_id)
            .map(|tx| tx.subscribe())
    }
}

