```rust
// Bridge with timeout handling
impl HITLContinuationBridge {
    pub async fn spawn_hitl_continuation_with_timeout(
        &self,
        approval_id: String,
        mpsc_rx: mpsc::Receiver<ApprovalDecision>,
        timeout: Duration,
    ) -> Result<broadcast::Sender<ApprovalDecision>, Error> {
        let (broadcast_tx, _) = broadcast::channel::<ApprovalDecision>(100);
        let broadcast_tx_clone = broadcast_tx.clone();

        // ✨ Store with timeout info
        {
            let mut bridges = self.bridges.write().unwrap();
            bridges.insert(approval_id.clone(), broadcast_tx.clone());
        }

        tokio::spawn(async move {
            // ✨ Race between decision and timeout
            tokio::select! {
                decision = mpsc_rx.recv() => {
                    if let Some(decision) = decision {
                        let _ = broadcast_tx_clone.send(decision);
                    }
                }
                _ = tokio::time::sleep(timeout) => {
                    // ✨ Timeout occurred - broadcast timeout decision
                    let timeout_decision = ApprovalDecision::Timeout;
                    let _ = broadcast_tx_clone.send(timeout_decision);
                    println!("⏰ Timeout for approval {}", approval_id);
                }
            }
        });

        Ok(broadcast_tx)
    }
}

// Bridge with retry capability
async fn spawn_hitl_continuation_with_retry(
    bridge: &HITLContinuationBridge,
    approval_id: String,
    mut decision_source: impl FnMut() -> mpsc::Receiver<ApprovalDecision>,
    max_retries: usize,
) -> Result<broadcast::Sender<ApprovalDecision>, Error> {
    let (broadcast_tx, _) = broadcast::channel::<ApprovalDecision>(100);
    let broadcast_tx_clone = broadcast_tx.clone();

    tokio::spawn(async move {
        let mut attempts = 0;

        loop {
            attempts += 1;
            let mpsc_rx = decision_source();

            // ✨ Try to get decision
            tokio::select! {
                decision = mpsc_rx.recv() => {
                    if let Some(decision) = decision {
                        let _ = broadcast_tx_clone.send(decision);
                        break; // Success!
                    }
                }
                _ = tokio::time::sleep(Duration::from_secs(30)) => {
                    // Timeout - retry if attempts remain
                }
            }

            if attempts >= max_retries {
                let _ = broadcast_tx_clone.send(ApprovalDecision::Timeout);
                break;
            }

            println!("🔄 Retrying approval {} (attempt {}/{})", approval_id, attempts, max_retries);
            tokio::time::sleep(Duration::from_secs(5)).await;
        }
    });

    Ok(broadcast_tx)
}

// Bridge with circuit breaker
use std::sync::atomic::{AtomicU32, Ordering};

struct CircuitBreaker {
    failure_count: AtomicU32,
    failure_threshold: u32,
    timeout: Duration,
}

impl HITLContinuationBridge {
    pub async fn spawn_with_circuit_breaker(
        &self,
        approval_id: String,
        mpsc_rx: mpsc::Receiver<ApprovalDecision>,
        circuit_breaker: &CircuitBreaker,
    ) -> Result<broadcast::Sender<ApprovalDecision>, Error> {
        if circuit_breaker.is_open() {
            return Err(Error::CircuitBreakerOpen);
        }

        let (broadcast_tx, _) = broadcast::channel::<ApprovalDecision>(100);
        let broadcast_tx_clone = broadcast_tx.clone();
        let breaker_clone = circuit_breaker.clone();

        tokio::spawn(async move {
            match mpsc_rx.recv().await {
                Some(decision) => {
                    let _ = broadcast_tx_clone.send(decision);
                    breaker_clone.reset();
                }
                None => {
                    breaker_clone.record_failure();
                }
            }
        });

        Ok(broadcast_tx)
    }
}
