#### 🧱 Checkpoint Management System

```rust
// The checkpoint storage system
struct CheckpointRegistry {
    checkpoints: Arc<Mutex<HashMap<String, HITLCheckpoint>>>,
    completion_notifiers: Arc<Mutex<HashMap<String, broadcast::Sender<ApprovalResult>>>>,
}

#[derive(Debug, Clone)]
pub struct HITLCheckpoint {
    pub id: String,
    pub reason: String,
    pub context: Value,
    pub strategy_state: StrategyState,
    pub user_id: String,
    pub created_at: std::time::Instant,
    pub expires_at: std::time::Instant,
}

impl CheckpointRegistry {
    // 1. ✨ Store checkpoint when strategy pauses
    async fn store_checkpoint(&self, checkpoint: HITLCheckpoint) -> Result<(), Error> {
        let mut checkpoints = self.checkpoints.lock().await;
        checkpoints.insert(checkpoint.id.clone(), checkpoint);

        // Create completion notifier for this checkpoint
        let (tx, _rx) = broadcast::channel(10);
        let mut notifiers = self.completion_notifiers.lock().await;
        notifiers.insert(checkpoint.id.clone(), tx);

        println!("💾 Stored checkpoint: {}", checkpoint.id);
        Ok(())
    }

    // 2. ✨ Retrieve checkpoint for resumption
    async fn retrieve_checkpoint(&self, id: &str) -> Result<HITLCheckpoint, Error> {
        let checkpoints = self.checkpoints.lock().await;
        checkpoints.get(id)
            .cloned()
            .ok_or_else(|| Error::CheckpointNotFound(id.to_string()))
    }

    // 3. ✨ Get completion notifier
    async fn get_completion_notifier(&self, id: &str) -> Result<broadcast::Sender<ApprovalResult>, Error> {
        let notifiers = self.completion_notifiers.lock().await;
        notifiers.get(id)
            .cloned()
            .ok_or_else(|| Error::NotifierNotFound(id.to_string()))
    }

    // 4. ✨ Clean up checkpoint after completion
    async fn cleanup_checkpoint(&self, id: &str) -> Result<(), Error> {
        let mut checkpoints = self.checkpoints.lock().await;
        checkpoints.remove(id);

        let mut notifiers = self.completion_notifiers.lock().await;
        notifiers.remove(id);

        println!("🧹 Cleaned up checkpoint: {}", id);
        Ok(())
    }
}

// Global checkpoint registry
static CHECKPOINT_REGISTRY: Lazy<CheckpointRegistry> = Lazy::new(|| CheckpointRegistry::new());
```

