async fn process_batch_approvals(
    approvals: Vec<ApprovalRequest>,
) -> Result<Vec<BatchApprovalResult>, Error> {
    let mut results = Vec::new();

    // Process approvals in parallel
    let approval_futures: Vec<_> = approvals
        .into_iter()
        .map(|approval| async move {
            let result = resume_strategy_from_approval(approval).await;
            (approval.checkpoint_id.clone(), result)
        })
