    pub session_id: String,         // ✨ Binds to user session
    pub checkpoint_id: String,      // ✨ Binds to specific checkpoint
    pub user_id: String,            // ✨ Binds to specific user
    pub created_at: SystemTime,     // ✨ Token creation time
    pub expires_at: SystemTime,     // ✨ Expiration timestamp
    pub permissions: Vec<String>,   // ✨ Required permissions
    pub operation_context: serde_json::Value, // ✨ Operation context
    pub single_use: AtomicBool,     // ✨ Single-use flag (atomic for thread safety)
}

pub struct SecureHITLResumeManager {
    token_store: TokenStore,        // ✨ Secure token storage
    crypto_provider: CryptoProvider, // ✨ Cryptographic operations
    session_manager: SessionManager, // ✨ Session validation
    audit_logger: AuditLogger,      // ✨ Security audit trail
}

impl SecureHITLResumeManager {
    // ✨ Generate secure resume token
    pub async fn generate_resume_token(
        &self,
        checkpoint: &HITLCheckpoint,
        session: &UserSession,
    ) -> Result<String, Error> {
        // 1. Generate cryptographically secure token
        let token = self.crypto_provider.generate_secure_token(32)?;

        // 2. Create resume context with security bindings
        let resume_token = HITLResumeToken {
            token: token.clone(),
            session_id: session.id.clone(),
            checkpoint_id: checkpoint.id.clone(),
            user_id: session.user_id.clone(),
            created_at: SystemTime::now(),
            expires_at: SystemTime::now() + Duration::from_secs(3600), // 1 hour TTL
            permissions: checkpoint.required_permissions.clone(),
            operation_context: checkpoint.context.clone(),
            single_use: AtomicBool::new(false), // Not used yet
        };

        // 3. ✨ Store token securely with encryption
        self.token_store.store_token(&resume_token).await?;

        // 4. ✨ Log token generation for audit
        self.audit_logger.log_token_generation(&resume_token, session).await?;

        Ok(token)
    }

    // ✨ Validate and consume resume token
    pub async fn validate_and_consume_token(
        &self,
        token: &str,
        session: &UserSession,
    ) -> Result<ResumeContext, Error> {
        // 1. ✨ Retrieve token from secure store
        let resume_token = self.token_store.retrieve_token(token).await?;

        // 2. ✨ Verify single-use (atomic operation)
        if resume_token.single_use.compare_exchange(
            false, true, 
            Ordering::SeqCst, 
            Ordering::SeqCst
        ).is_err() {
            // Token already used!
            self.audit_logger.log_token_reuse_attempt(token, session).await?;
            return Err(Error::TokenAlreadyUsed);
        }

        // 3. ✨ Verify session binding
        if resume_token.session_id != session.id {
            self.audit_logger.log_session_mismatch(token, session).await?;
            return Err(Error::SessionMismatch);
        }

        // 4. ✨ Verify user binding
        if resume_token.user_id != session.user_id {
            self.audit_logger.log_user_mismatch(token, session).await?;
            return Err(Error::UserMismatch);
        }

        // 5. ✨ Verify TTL
        if SystemTime::now() > resume_token.expires_at {
            self.audit_logger.log_token_expired(token, session).await?;
            return Err(Error::TokenExpired);
        }

        // 6. ✨ Verify permissions
        self.verify_permissions(&resume_token, session).await?;

        // 7. ✨ Clean up used token
        self.token_store.delete_token(token).await?;

        // 8. ✨ Log successful validation
        self.audit_logger.log_token_consumed(token, session).await?;

        Ok(ResumeContext {
            checkpoint_id: resume_token.checkpoint_id,
            operation_context: resume_token.operation_context,
            user_id: resume_token.user_id,
        })
    }
}
