// ✨ Session binding ensures tokens can only be used in the same session
impl SecureHITLResumeManager {
    async fn verify_session_binding(
        &self,
        resume_token: &HITLResumeToken,
        session: &UserSession,
    ) -> Result<(), Error> {
        // ✨ Verify session ID matches
        if resume_token.session_id != session.id {
            return Err(Error::InvalidSessionBinding);
        }

        // ✨ Verify session is still valid
        if !self.session_manager.is_session_valid(&session.id).await? {
            return Err(Error::SessionExpired);
        }

        // ✨ Verify session hasn't been revoked
        if self.session_manager.is_session_revoked(&session.id).await? {
            return Err(Error::SessionRevoked);
        }

        // ✨ Verify IP address binding (if enabled)
        if self.is_ip_binding_enabled() {
            let current_ip = session.client_ip.as_ref().ok_or(Error::MissingClientIP)?;
            let token_ip = self.token_store.get_token_client_ip(&resume_token.token).await?;

            if current_ip != &token_ip {
                self.audit_logger.log_ip_mismatch(
                    &resume_token.token, 
                    current_ip, 
                    &token_ip
                ).await?;
                return Err(Error::IPMismatch);
            }
        }

        // ✨ Verify user agent binding (if enabled)
        if self.is_user_agent_binding_enabled() {
            let current_ua = session.user_agent.as_ref().ok_or(Error::MissingUserAgent)?;
            let token_ua = self.token_store.get_token_user_agent(&resume_token.token).await?;

            if current_ua != &token_ua {
                self.audit_logger.log_user_agent_mismatch(
                    &resume_token.token,
                    current_ua,
                    &token_ua
                ).await?;
                return Err(Error::UserAgentMismatch);
            }
        }

        Ok(())
    }
}

