use std::collections::HashMap;
use std::sync::Mutex;

pub struct RateLimiter {
    attempts: Mutex<HashMap<String, (usize, SystemTime)>>,
    max_attempts: usize,
    window: Duration,
}

impl RateLimiter {
    pub async fn check_rate_limit(&self, user_id: &str) -> Result<(), Error> {
        let now = SystemTime::now();
        let mut attempts = self.attempts.lock().unwrap();

        let (count, last_attempt) = attempts.entry(user_id.to_string())
            .or_insert((0, now));

        // Reset count if outside window
        if now.duration_since(*last_attempt)? > self.window {
            *count = 0;
            *last_attempt = now;
        }

        // ✨ Check rate limit
        if *count >= self.max_attempts {
            return Err(Error::RateLimitExceeded);
        }

        *count += 1;
        Ok(())
    }
}

