        let token_hash = self.calculate_token_hash(token)?;
        let encrypted_data = self.storage.get(&token_hash).await?;

        let decrypted_data = self.cipher.decrypt(
            Nonce::from_slice(&[0; 12]),
            encrypted_data.as_ref()
        )?;

        let token: HITLResumeToken = serde_json::from_slice(&decrypted_data)?;
        Ok(token)
    }
