                timestamp: Instant::now(),
                action: AuditAction::TokenCreated,
                actor: session.user_id.clone(),
                details: json!({ "approval_id": approval_id }),
            }],
        };

        // ✨ Store with cryptographic protection
        let encrypted_token = self.crypto_provider.encrypt_token(&token)?;
        let token_id = self.generate_secure_token_id(&approval_id);

        {
            let mut tokens = self.tokens.write().await;
            tokens.insert(token_id.clone(), token);
        }

        // ✨ Log creation audit
        self.audit_logger.log_token_creation(&token_id, session).await?;

        Ok(token_id)
    }

    // ✨ Validate and consume token with full security checks
    pub async fn validate_and_consume(
        &self,
        token_id: &str,
        session: &UserSession,
    ) -> Result<ResumeContext, SecurityError> {
        let mut tokens = self.tokens.write().await;
        let token = tokens.get(token_id).ok_or(SecurityError::TokenNotFound)?;

        // ✨ 1. Session binding verification
        self.verify_session_binding(token, session)?;

        // ✨ 2. TTL enforcement
        if token.is_expired() {
            self.audit_logger.log_token_expired(token_id, session).await?;
            return Err(SecurityError::TokenExpired);
        }

        // ✨ 3. Single-use guarantee with atomic operation
        if token.used.compare_exchange(false, true, Ordering::AcqRel, Ordering::Acquire).is_err() {
            self.audit_logger.log_token_reuse_attempt(token_id, session).await?;
            return Err(SecurityError::TokenAlreadyUsed);
        }

        // ✨ 4. Permission check
        if !token.has_permission(Permission::ResumeProcessing) {
            self.audit_logger.log_permission_denied(token_id, session).await?;
            return Err(SecurityError::InsufficientPermissions);
        }

        // ✨ 5. Log successful validation
        self.audit_logger.log_token_consumed(token_id, session).await?;

        // ✨ Return context for resuming processing
        Ok(ResumeContext {
            approval_id: token.approval_id.clone(),
            context: token.context.clone(),
        })
    }

    fn create_session_binding(&self, session: &UserSession) -> Result<SessionBinding, SecurityError> {
        let binding_data = format!("{}:{}:{}:{}", 
            session.session_id, 
            session.user_id, 
            session.ip_address.as_deref().unwrap_or(""),
            session.user_agent.as_deref().unwrap_or("")
        );

        let signature = self.crypto_provider.sign_binding(&binding_data)?;

        Ok(SessionBinding {
            session_id: session.session_id.clone(),
            user_id: session.user_id.clone(),
            ip_address: session.ip_address.clone(),
            user_agent: session.user_agent.clone(),
            binding_signature: signature,
        })
    }

    fn verify_session_binding(
        &self,
        token: &HITLResumeToken,
        session: &UserSession,
    ) -> Result<(), SecurityError> {
        // ✨ Verify the cryptographic binding
        let current_binding_data = format!("{}:{}:{}:{}", 
            session.session_id, 
            session.user_id, 
            session.ip_address.as_deref().unwrap_or(""),
            session.user_agent.as_deref().unwrap_or("")
        );

        if !self.crypto_provider.verify_binding(&current_binding_data, &token.session_binding.binding_signature)? {
            return Err(SecurityError::SessionBindingMismatch);
        }

        // ✨ Additional binding checks
        if token.session_binding.session_id != session.session_id {
            return Err(SecurityError::SessionIdMismatch);
        }

        if token.session_binding.user_id != session.user_id {
            return Err(SecurityError::UserIdMismatch);
        }

        // Optional: IP address binding
        if let (Some(token_ip), Some(session_ip)) = (&token.session_binding.ip_address, &session.ip_address) {
            if token_ip != session_ip {
                return Err(SecurityError::IpAddressMismatch);
            }
        }

        Ok(())
    }
}
