// ResumeRegistry ensures each nonce can only be used once!
struct ResumeRegistry {
    nonces: Arc<RwLock<HashMap<String, NonceEntry>>>,
}

struct NonceEntry {
    strategy_id: String,
    created_at: Instant,
    expires_at: Instant,
    used: bool,  // ✨ This prevents reuse!
}

impl ResumeRegistry {
    // ✨ Store a nonce (first use)
    fn store_nonce(&self, nonce: String, strategy_id: String) -> Result<(), Error> {
        let mut nonces = self.nonces.write().unwrap();

        if nonces.contains_key(&nonce) {
            // ✨ Nonce already exists - reject!
            return Err(Error::NonceAlreadyExists);
        }

        nonces.insert(nonce, NonceEntry {
            strategy_id,
            created_at: Instant::now(),
            expires_at: Instant::now() + Duration::from_secs(3600), // 1 hour TTL
            used: false,
        });

        Ok(())
    }

    // ✨ Retrieve and mark as used (single-use enforcement!)
    fn consume_nonce(&self, nonce: &str) -> Result<String, Error> {
        let mut nonces = self.nonces.write().unwrap();

        match nonces.get_mut(nonce) {
            Some(entry) => {
                // ✨ Check if already used
                if entry.used {
                    return Err(Error::NonceAlreadyUsed);  // ✨ Single-use enforced!
                }

                // ✨ Check expiration
                if Instant::now() > entry.expires_at {
                    return Err(Error::NonceExpired);
                }

                // ✨ Mark as used and return strategy_id
                entry.used = true;
                Ok(entry.strategy_id.clone())
            }
            None => Err(Error::NonceNotFound),
        }
    }
}
