pub struct NonceEntry {
    pub strategy_id: String,
    pub created_at: Instant,
    pub expires_at: Instant,
    pub used: bool,
    pub session_id: String,  // ✨ Session binding!
    pub user_id: String,     // ✨ User binding!
    pub permissions: Vec<String>, // ✨ Permission scope!
}

pub struct ResumeRegistry {
    nonces: Arc<RwLock<HashMap<String, NonceEntry>>>,
    default_ttl: Duration,
}

impl ResumeRegistry {
    pub fn new(default_ttl: Duration) -> Self {
        Self {
            nonces: Arc::new(RwLock::new(HashMap::new())),
            default_ttl,
        }
    }

    // ✨ Store nonce with full security context
    pub fn store_nonce_with_context(
        &self,
        nonce: String,
        strategy_id: String,
        session_id: String,
        user_id: String,
        permissions: Vec<String>,
    ) -> Result<(), Error> {
        let mut nonces = self.nonces.write().unwrap();

        // ✨ Prevent nonce reuse
        if nonces.contains_key(&nonce) {
            return Err(Error::NonceAlreadyExists);
        }

        let entry = NonceEntry {
            strategy_id,
            created_at: Instant::now(),
            expires_at: Instant::now() + self.default_ttl,
            used: false,
            session_id,
            user_id,
            permissions,
        };

        nonces.insert(nonce, entry);
        Ok(())
    }

    // ✨ Consume nonce with full security validation
    pub fn consume_nonce_with_validation(
        &self,
        nonce: &str,
        expected_session_id: &str,
        required_permissions: &[&str],
    ) -> Result<NonceEntry, Error> {
        let mut nonces = self.nonces.write().unwrap();

        match nonces.get_mut(nonce) {
            Some(entry) => {
                // ✨ 1. Check if already used (single-use enforcement)
                if entry.used {
                    return Err(Error::NonceAlreadyUsed);
                }

                // ✨ 2. Check expiration (TTL enforcement)
                if Instant::now() > entry.expires_at {
                    return Err(Error::NonceExpired);
                }

                // ✨ 3. Check session binding
                if entry.session_id != expected_session_id {
                    return Err(Error::SessionMismatch);
                }

                // ✨ 4. Check permission requirements
                if !self.has_required_permissions(&entry.permissions, required_permissions) {
                    return Err(Error::InsufficientPermissions);
                }

                // ✨ 5. Mark as used and return
                entry.used = true;
                Ok(entry.clone())
            }
            None => Err(Error::NonceNotFound),
        }
    }

    fn has_required_permissions(&self, user_permissions: &[String], required: &[&str]) -> bool {
        required.iter().all(|perm| user_permissions.contains(&perm.to_string()))
    }

    // ✨ Cleanup expired nonces (garbage collection)
    pub fn cleanup_expired_nonces(&self) -> usize {
        let mut nonces = self.nonces.write().unwrap();
        let now = Instant::now();
        let initial_count = nonces.len();

        nonces.retain(|_, entry| now <= entry.expires_at);

        let final_count = nonces.len();
        initial_count - final_count
    }
}
