    pub fn consume_time_bounded_nonce(
        &self,
        nonce: &str,
        current_time: Instant,
        user_timezone: &str,
    ) -> Result<NonceEntry, Error> {
        let mut nonces = self.nonces.write().unwrap();

        match nonces.get_mut(nonce) {
            Some(EntryType::TimeBounded(time_entry)) => {
                // ✨ Check time bounds
                if current_time < time_entry.valid_after {
                    return Err(Error::NonceNotYetValid);
                }

                if current_time > time_entry.valid_before {
                    return Err(Error::NonceExpired);
                }

                // ✨ Check timezone restriction
                if let Some(restricted_tz) = &time_entry.timezone_restriction {
                    if restricted_tz != user_timezone {
                        return Err(Error::TimezoneMismatch);
                    }
                }

                // ✨ Standard consumption
                self.validate_and_consume_nonce(&mut time_entry.base_entry, nonce)
            }
            _ => Err(Error::InvalidNonceType),
        }
    }
}
