// 1. Comprehensive nonce validation
impl ResumeRegistry {
    fn validate_nonce_comprehensive(&self, entry: &NonceEntry, context: &ValidationContext) -> Result<(), Error> {
        let now = Instant::now();

        // ✨ 1. Single-use check
        if entry.used {
            return Err(Error::NonceAlreadyUsed);
        }

        // ✨ 2. TTL check
        if now > entry.expires_at {
            return Err(Error::NonceExpired);
        }

        // ✨ 3. Session binding
        if entry.session_id != context.session_id {
            return Err(Error::SessionMismatch);
        }

        // ✨ 4. User binding
        if entry.user_id != context.user_id {
            return Err(Error::UserMismatch);
        }

        // ✨ 5. Permission check
        if !self.has_permissions(&entry.permissions, &context.required_permissions) {
            return Err(Error::InsufficientPermissions);
        }

        // ✨ 6. Device binding (if enabled)
        if context.enforce_device_binding {
            if !self.is_same_device(&entry, context)? {
                return Err(Error::DeviceMismatch);
            }
        }

        // ✨ 7. IP binding (if enabled)
        if context.enforce_ip_binding {
            if !self.is_same_network(&entry, context)? {
                return Err(Error::NetworkMismatch);
            }
        }

        // ✨ 8. Rate limiting
        if let Some(rate_limit) = &context.rate_limit {
            if !self.check_rate_limit(entry, rate_limit)? {
                return Err(Error::RateLimitExceeded);
            }
        }

        Ok(())
    }
}

