impl ResumeRegistry {
    pub fn cleanup_with_metrics(&self) -> CleanupMetrics {
        let start_time = Instant::now();
        let initial_count = {
            let nonces = self.nonces.read().unwrap();
            nonces.len()
        };

        let expired_count = self.cleanup_expired_nonces();
        let final_count = {
            let nonces = self.nonces.read().unwrap();
            nonces.len()
        };

        let cleanup_metrics = CleanupMetrics {
            initial_count,
            expired_count,
            final_count,
            cleanup_duration: start_time.elapsed(),
            memory_reclaimed: (expired_count * std::mem::size_of::<NonceEntry>()) as u64,
        };

        // ✨ Log cleanup metrics
        if cleanup_metrics.expired_count > 0 {
            info!("🧹 Nonce cleanup: removed {} expired nonces in {:?}",
                  cleanup_metrics.expired_count,
                  cleanup_metrics.cleanup_duration);
        }

        cleanup_metrics
    }
}

