use serde::{Deserialize, Serialize};
use std::collections::HashMap;

#[derive(Debug, Deserialize)]
pub struct HITLResolveRequest {
    pub checkpoint_id: String,
    pub choice_index: usize,        // ✨ This is what gets bounds-checked!
    pub rationale: Option<String>,
    pub confidence: Option<f32>,
}

#[derive(Debug, Clone)]
pub struct HITLCheckpoint {
    pub id: String,
    pub options_count: usize,       // ✨ Total number of valid options
    pub options_descriptions: Vec<String>, // Human-readable option descriptions
    pub context: serde_json::Value,
    pub created_at: std::time::SystemTime,
    pub expires_at: std::time::SystemTime,
    pub user_id: String,
    pub session_id: String,
}

// ✨ The core bounds checking logic
async fn validate_choice_bounds(
    request: &HITLResolveRequest,
    checkpoint: &HITLCheckpoint,
) -> Result<(), Error> {
    // ✨ Calculate maximum valid choice index
    let max_valid_index = checkpoint.options_count.saturating_sub(1);

    println!("🛡️  Bounds check: requested={}, max_valid={}, total_options={}", 
             request.choice_index, max_valid_index, checkpoint.options_count);

    // ✨ Security check: choice must be within valid range
    if request.choice_index > max_valid_index {
        let error = Error::ChoiceIndexOutOfBounds {
            requested: request.choice_index,
            max_valid: max_valid_index,
            total_options: checkpoint.options_count,
            checkpoint_id: checkpoint.id.clone(),
        };

        // ✨ Log security violation
        audit_log_choice_violation(request, checkpoint, &error).await?;

        return Err(error);
    }

    println!("✅ Choice index {} is within bounds (0-{})", 
             request.choice_index, max_valid_index);

    Ok(())
}

// The main resolve handler with bounds checking
async fn copilot_hitl_resolve_handler(
    request: HITLResolveRequest,
    session: &UserSession,
) -> Result<ResolveResponse, Error> {
    println!("📥 Processing HITL resolve request for checkpoint: {}", request.checkpoint_id);

    // 1. ✨ Retrieve the checkpoint
    let checkpoint = retrieve_checkpoint(&request.checkpoint_id).await
        .map_err(|e| {
            audit_log_checkpoint_retrieval_failure(&request, session, &e).await;
            e
        })?;

    // 2. ✨ Validate session binding
    validate_session_binding(&checkpoint, session).await?;

    // 3. ✨ ✨ THE CRITICAL SECURITY CHECK ✨ ✨
    validate_choice_bounds(&request, &checkpoint).await?;

    // 4. ✨ Validate TTL
    validate_checkpoint_ttl(&checkpoint).await?;

    // 5. ✨ Process the legitimate choice
    let result = process_valid_choice(request, checkpoint, session).await?;

    Ok(result)
}
