// Example of how bounds checking prevents attacks:

// ✨ LEGITIMATE scenario:
// Checkpoint has 3 options: [Accept, Review, Reject]
// options_count = 3
// Valid choices: 0, 1, 2
// User selects choice_index = 1 (Review) ✅ VALID

// ❌ MALICIOUS scenario (without bounds check):
// Attacker sends choice_index = 999
// Without bounds check, this might access invalid memory or trigger
// undefined behavior in the choice resolution logic!

// ✨ WITH bounds check:
// options_count = 3, so max_valid_index = 2
// Attacker sends choice_index = 999
// Bounds check fails: 999 > 2 ❌ REJECTED
// Security violation logged! 🛡️

async fn demonstrate_security_violation() -> Result<(), Error> {
    // Simulate a legitimate checkpoint
    let checkpoint = HITLCheckpoint {
        id: "test-checkpoint-123".to_string(),
        options_count: 3,  // Only 3 valid options!
        options_descriptions: vec![
            "Accept recommendation".to_string(),
            "Request human review".to_string(),
            "Reject recommendation".to_string(),
        ],
        context: serde_json::json!({}),
        created_at: std::time::SystemTime::now(),
        expires_at: std::time::SystemTime::now() + std::time::Duration::from_secs(3600),
        user_id: "user-456".to_string(),
        session_id: "session-789".to_string(),
    };

    // ✨ Legitimate request
    let good_request = HITLResolveRequest {
        checkpoint_id: "test-checkpoint-123".to_string(),
        choice_index: 1,  // Valid choice
        rationale: Some("Needs human review".to_string()),
        confidence: Some(0.8),
    };

    assert!(validate_choice_bounds(&good_request, &checkpoint).await.is_ok());
    println!("✅ Good request passed bounds check");

    // ❌ Malicious request
    let bad_request = HITLResolveRequest {
        checkpoint_id: "test-checkpoint-123".to_string(),
        choice_index: 999,  // INVALID choice!
        rationale: None,
        confidence: None,
    };

    let result = validate_choice_bounds(&bad_request, &checkpoint).await;
    assert!(result.is_err());
    println!("🛡️  Bad request blocked by bounds check");

    match result.unwrap_err() {
        Error::ChoiceIndexOutOfBounds { requested, max_valid, .. } => {
            assert_eq!(requested, 999);
            assert_eq!(max_valid, 2);  // 3 options = indices 0,1,2
            println!("✨ Bounds check correctly identified violation!");
        }
        _ => panic!("Expected ChoiceIndexOutOfBounds error"),
    }

    Ok(())
}
