// Memory management with TTL enforcement
struct HITLResourceManager {
    parked_states: Arc<RwLock<HashMap<String, ParkedHITLState>>>,
    metrics_collector: MetricsCollector,
    cleanup_scheduler: CleanupScheduler,
}

impl HITLResourceManager {
    // ✨ Prevent memory leaks with TTL cleanup
    async fn enforce_ttl_cleanup(&self) -> Result<CleanupStats, Error> {
        let start_time = Instant::now();
        let mut expired_states = Vec::new();

        // ✨ Collect expired states
        {
            let states = self.parked_states.read().await;
            for (id, state) in states.iter() {
                if state.is_expired() {
                    expired_states.push(id.clone());
                }
            }
        }

        // ✨ Remove expired states
        let mut cleanup_count = 0;
        {
            let mut states = self.parked_states.write().await;
            for state_id in expired_states {
                if states.remove(&state_id).is_some() {
                    cleanup_count += 1;
                    self.log_expired_state(&state_id).await?;
                }
            }
        }

        // ✨ Update metrics
        let stats = CleanupStats {
            cleaned_up: cleanup_count,
            duration: start_time.elapsed(),
            memory_reclaimed: cleanup_count * std::mem::size_of::<ParkedHITLState>(),
        };

        self.metrics_collector.record_ttl_cleanup(&stats).await?;

        if cleanup_count > 0 {
            println!("🧹 HITL TTL cleanup: removed {} expired states in {:?}", 
                     cleanup_count, stats.duration);
        }

        Ok(stats)
    }

    // ✨ Proactive memory pressure management
    async fn handle_memory_pressure(&self) -> Result<(), Error> {
        let current_count = {
            let states = self.parked_states.read().await;
            states.len()
        };

        if current_count > 5000 {
            println!("⚠️  High memory pressure: {} parked states", current_count);

            // ✨ Aggressive cleanup of oldest states
            self.cleanup_oldest_states(100).await?;

            // ✨ Alert monitoring system
            self.alert_high_memory_pressure(current_count).await?;
        }

        Ok(())
    }

    async fn cleanup_oldest_states(&self, count: usize) -> Result<usize, Error> {
        let mut states_to_remove = Vec::new();

        // ✨ Get oldest states
        {
            let states = self.parked_states.read().await;
            let mut sorted_states: Vec<_> = states.iter().collect();
            sorted_states.sort_by_key(|(_, state)| state.parked_at);

            states_to_remove = sorted_states
                .into_iter()
                .take(count)
                .map(|(id, _)| id.clone())
                .collect();
        }

        // ✨ Remove oldest states
        let mut removed_count = 0;
        {
            let mut states = self.parked_states.write().await;
            for state_id in states_to_remove {
                if states.remove(&state_id).is_some() {
                    removed_count += 1;
                }
            }
        }

        Ok(removed_count)
    }
}

