// Dynamic TTL adjustment based on system load
struct AdaptiveTTLManager {
    base_ttl: Duration,
    load_monitor: LoadMonitor,
    performance_metrics: PerformanceMetrics,
}

impl AdaptiveTTLManager {
    async fn calculate_dynamic_ttl(&self, context: &StrategyContext) -> Duration {
        let current_load = self.load_monitor.get_current_load().await;
        let avg_processing_time = self.performance_metrics.get_avg_processing_time().await;

        // ✨ Adjust TTL based on system conditions
        let load_factor = if current_load > 0.8 {
            0.5 // Reduce TTL under high load
        } else if current_load < 0.3 {
            1.5 // Increase TTL under low load
        } else {
            1.0 // Normal TTL
        };

        let time_factor = if avg_processing_time > Duration::from_secs(30) {
            0.7 // Reduce TTL for slow processing
        } else {
            1.0 // Normal TTL
        };

        let base_seconds = self.base_ttl.as_secs();
        let adjusted_seconds = (base_seconds as f64 * load_factor * time_factor) as u64;

        Duration::from_secs(adjusted_seconds.max(300).min(7200)) // 5 min to 2 hours
    }
}

