) -> Result<Vec<BatchDismissalResult>, Error> {
    let mut results = Vec::new();

    // ✨ Process dismissals in parallel
    let dismissal_futures: Vec<_> = dismissal_requests
        .into_iter()
        .map(|request| async move {
            let result = handle_dismissal_flow(request).await;
            (request.checkpoint_id.clone(), result)
