```rust
use std::time::{Duration, Instant};
use std::collections::HashMap;
use std::sync::{Arc, RwLock};

#[derive(Debug, Clone)]
pub struct ParkedHITLState {
    pub checkpoint_id: String,
    pub strategy_context: StrategyContext,
    pub parked_at: Instant,
    pub expires_at: Instant,        // ✨ TTL enforcement point
    pub user_id: String,
    pub session_id: String,
    pub security_context: SecurityContext,
    pub audit_trail: Vec<AuditEvent>,
}

pub struct HITLParkingLot {
    parked_states: Arc<RwLock<HashMap<String, ParkedHITLState>>>,
    default_ttl: Duration,          // ✨ Configurable TTL (30 minutes default)
    cleanup_interval: Duration,
}

impl HITLParkingLot {
    pub fn new(default_ttl: Duration) -> Self {
        let lot = Self {
            parked_states: Arc::new(RwLock::new(HashMap::new())),
            default_ttl,
            cleanup_interval: Duration::from_secs(300), // 5 minutes cleanup
        };

        // ✨ Spawn background cleanup task
        lot.spawn_cleanup_task();
        lot
    }

    // ✨ Park a strategy state with TTL
    pub fn park_state(
        &self,
        strategy_context: StrategyContext,
        user_id: String,
        session_id: String,
    ) -> Result<String, Error> {
        let checkpoint_id = generate_secure_checkpoint_id();
        let now = Instant::now();

        let parked_state = ParkedHITLState {
            checkpoint_id: checkpoint_id.clone(),
            strategy_context,
            parked_at: now,
            expires_at: now + self.default_ttl,  // ✨ 30-minute TTL!
            user_id,
            session_id,
            security_context: SecurityContext::new(),
            audit_trail: vec![AuditEvent {
                timestamp: now,
                action: AuditAction::StateParked,
                actor: user_id.clone(),
                details: serde_json::json!({ "reason": "HITL pause required" }),
            }],
        };

        {
            let mut states = self.parked_states.write().unwrap();
            states.insert(checkpoint_id.clone(), parked_state);
        }

        println!("🅿️  Parked HITL state {} with 30-minute TTL", checkpoint_id);
        Ok(checkpoint_id)
    }

    // ✨ Retrieve parked state with TTL validation
    pub fn retrieve_state(&self, checkpoint_id: &str) -> Result<ParkedHITLState, Error> {
        let mut states = self.parked_states.write().unwrap();

        match states.get(checkpoint_id) {
            Some(state) => {
                // ✨ CRITICAL: Check TTL before returning state
                if state.is_expired() {
                    // ✨ Expired state - remove and return error
                    states.remove(checkpoint_id);
                    return Err(Error::ParkedStateExpired {
                        checkpoint_id: checkpoint_id.to_string(),
                        parked_duration: state.parked_at.elapsed(),
                    });
                }

                println!("🚗 Retrieved parked state {} ({} seconds remaining)", 
                         checkpoint_id, 
                         state.expires_at.duration_since(Instant::now()).as_secs());

                Ok(state.clone())
            }
            None => Err(Error::ParkedStateNotFound {
                checkpoint_id: checkpoint_id.to_string(),
            }),
        }
    }

    // ✨ Background cleanup task
    fn spawn_cleanup_task(&self) {
        let states = Arc::clone(&self.parked_states);
        let interval = self.cleanup_interval;

        tokio::spawn(async move {
            loop {
                tokio::time::sleep(interval).await;
                Self::cleanup_expired_states(&states).await;
            }
        });
    }

    async fn cleanup_expired_states(states: &Arc<RwLock<HashMap<String, ParkedHITLState>>>) {
        let mut expired_count = 0;
        let mut cleanup_list = Vec::new();

        {
            let states_read = states.read().unwrap();
            for (id, state) in states_read.iter() {
                if state.is_expired() {
                    cleanup_list.push(id.clone());
                    expired_count += 1;
                }
            }
        }

        if expired_count > 0 {
            let mut states_write = states.write().unwrap();
            for id in cleanup_list {
                if let Some(state) = states_write.remove(&id) {
                    println!("🗑️  Cleaned up expired parked state {} (parked for {} seconds)",
                             id, state.parked_at.elapsed().as_secs());

                    // ✨ Log cleanup for audit trail
                    audit_log_expired_state(&state).await;
                }
            }

            println!("🧹 Cleanup completed: {} expired states removed", expired_count);
        }
    }
}

impl ParkedHITLState {
    pub fn is_expired(&self) -> bool {
        Instant::now() > self.expires_at
    }

    pub fn remaining_time(&self) -> Option<Duration> {
        let now = Instant::now();
        if now < self.expires_at {
            Some(self.expires_at - now)
        } else {
            None
        }
    }

    pub fn add_audit_event(&mut self, event: AuditEvent) {
        self.audit_trail.push(event);
    }
}
