impl HITLParkingLot {
    pub fn retrieve_state_with_grace_period(
        &self,
        checkpoint_id: &str,
        grace_period: Duration,
    ) -> Result<ParkedHITLState, Error> {
        let mut states = self.parked_states.write().unwrap();

        match states.get(checkpoint_id) {
            Some(state) => {
                let now = Instant::now();

                // ✨ Check if within grace period
                if now > state.expires_at {
                    let grace_deadline = state.expires_at + grace_period;
                    if now > grace_deadline {
                        // Truly expired
                        states.remove(checkpoint_id);
                        return Err(Error::ParkedStateExpired {
                            checkpoint_id: checkpoint_id.to_string(),
                            parked_duration: state.parked_at.elapsed(),
