async fn collect_ttl_metrics() -> Result<ParkingLotMetrics, Error> {
    let parking_lot = get_parking_lot();
    let states = parking_lot.parked_states.read().unwrap();
    let now = Instant::now();

    let total_states = states.len();
    let mut expired_count = 0;
    let mut total_duration = Duration::from_secs(0);
    let mut expiring_soon = 0;
    let mut longest_parked: Option<Duration> = None;

    for state in states.values() {
        let parked_duration = state.parked_at.elapsed();

        if state.is_expired() {
            expired_count += 1;
        } else {
            total_duration += parked_duration;
            if (state.expires_at - now).as_secs() < 300 { // 5 minutes
                expiring_soon += 1;
            }
            longest_parked = Some(match longest_parked {
                Some(current_longest) => current_longest.max(parked_duration),
                None => parked_duration,
            });
        }
    }

    let average_duration = if total_states > expired_count {
        total_duration / (total_states - expired_count) as u32
    } else {
        Duration::from_secs(0)
    };

    Ok(ParkingLotMetrics {
        total_states,
        expired_states: expired_count,
        average_parking_duration: average_duration,
        expiring_soon,
        longest_parked,
    })
}

