const HITL_TTL_REASONS: &[(&str, &str)] = &[
    ("User Attention Span", "People lose context after ~30 minutes"),
    ("Security Freshness", "Approvals should be recent decisions"),
    ("Resource Management", "Prevents memory leaks from abandoned approvals"),
    ("Operational Efficiency", "Keeps approval queues manageable"),
    ("Compliance Requirements", "Many regulations require time limits"),
];

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HITLCheckpoint {
    pub id: String,
    pub reason: String,
    pub context: serde_json::Value,
    pub created_at: Instant,
    pub expires_at: Instant,
    pub user_id: String,
    pub priority: PriorityLevel,
    pub category: ApprovalCategory,
    pub audit_trail: Vec<AuditEvent>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum PriorityLevel {
    Low,      // Can wait longer
    Normal,   // Standard 30-minute TTL
    High,     // Shorter TTL for urgency
    Critical, // Very short TTL
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum ApprovalCategory {
    Financial,
    Security,
    Content,
    System,
    Compliance,
}

// ✨ Dynamic TTL based on priority and category
impl HITLCheckpoint {
    pub fn calculate_ttl(&self) -> Duration {
        let base_ttl = Duration::from_secs(30 * 60); // 30 minutes

        let ttl = match (&self.priority, &self.category) {
            (PriorityLevel::Critical, _) => Duration::from_secs(5 * 60),    // 5 minutes
            (PriorityLevel::High, ApprovalCategory::Financial) => Duration::from_secs(15 * 60), // 15 minutes
            (PriorityLevel::High, _) => Duration::from_secs(20 * 60),       // 20 minutes
            (PriorityLevel::Normal, _) => base_ttl,                         // 30 minutes
            (PriorityLevel::Low, _) => Duration::from_secs(60 * 60),        // 1 hour
        };

        // Apply category-specific adjustments
        let adjusted_ttl = match &self.category {
            ApprovalCategory::Financial => ttl.mul_f32(0.8),    // Financial approvals expire faster
            ApprovalCategory::Security => ttl.mul_f32(0.9),     // Security approvals expire faster
            ApprovalCategory::Compliance => ttl.mul_f32(1.2),   // Compliance approvals can wait longer
            _ => ttl,
        };

        adjusted_ttl.max(Duration::from_secs(60)) // Minimum 1 minute
    }

    pub fn is_expired(&self) -> bool {
        Instant::now() > self.expires_at
    }

    pub fn time_until_expiration(&self) -> Option<Duration> {
        let now = Instant::now();
        if now < self.expires_at {
            Some(self.expires_at - now)
        } else {
            None
        }
    }
}
