            // ✨ Remove from storage
            remove_checkpoint(&checkpoint.id).await?;

            cleanup_count += 1;
        }

        Ok(cleanup_count)
    }

    async fn warn_expiring_soon(&self) -> Result<usize, Error> {
        let warning_time = Instant::now() + self.warning_threshold;
        let expiring_soon = find_checkpoints_expiring_before(warning_time).await?;

        let mut warning_count = 0;
        for checkpoint in expiring_soon {
            // Only warn if we haven't already
            if !checkpoint.has_expiration_warning() {
                // ✨ Send warning notification
                send_expiration_warning(&checkpoint).await?;

                // ✨ Update checkpoint to prevent duplicate warnings
                mark_expiration_warning_sent(&checkpoint.id).await?;

                warning_count += 1;
            }
        }

        Ok(warning_count)
    }
}
