async fn request_ttl_extension(
    checkpoint_id: &str,
    requester: &str,
    reason: &str,
    extension_duration: Duration,
) -> Result<(), Error> {
    let mut checkpoint = retrieve_checkpoint(checkpoint_id).await?;

    // ✨ Validate extension request
    if !is_authorized_for_extension(requester, &checkpoint).await? {
        return Err(Error::UnauthorizedExtensionRequest);
    }

    // ✨ Check if extension is reasonable
    let max_extension = Duration::from_secs(60 * 60); // Max 1 hour extension
    if extension_duration > max_extension {
        return Err(Error::ExtensionTooLong);
    }

    // ✨ Apply extension
    checkpoint.expires_at += extension_duration;

    // ✨ Log extension
    checkpoint.audit_trail.push(AuditEvent {
        timestamp: Instant::now(),
        action: "TTL_EXTENSION".to_string(),
        actor: requester.to_string(),
        details: serde_json::json!({
            "reason": reason,
            "extension_duration": extension_duration.as_secs(),
            "new_expiration": checkpoint.expires_at
        }),
    });

    update_checkpoint(&checkpoint).await?;

    // ✨ Notify affected parties
    notify_ttl_extension(&checkpoint, extension_duration).await?;

    Ok(())
}
