#### 🧱 The Complete Turn Span Architecture

```rust
use std::collections::HashMap;
use std::time::{Duration, Instant};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TurnSpan {
    pub span_id: String,              // ✨ Unique within trace
    pub trace_id: String,             // ✨ Global trace identifier
    pub parent_span_id: Option<String>, // ✨ Hierarchical linking
    pub operation_name: String,       // ✨ Human-readable operation name
    pub service_name: String,         // ✨ Which service is handling
    pub start_time: Instant,          // ✨ When operation started
    pub end_time: Option<Instant>,    // ✨ When operation completed
    pub duration: Option<Duration>,   // ✨ How long it took
    pub status: SpanStatus,           // ✨ Success, error, or in-progress
    pub metadata: HashMap<String, String>, // ✨ Rich context data
    pub tags: Vec<String>,            // ✨ Categorization tags
    pub logs: Vec<SpanLog>,           // ✨ Detailed operation logs
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum SpanStatus {
    InProgress,
    Success,
    Error { message: String },
    Cancelled,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SpanLog {
    pub timestamp: Instant,
    pub level: LogLevel,
    pub message: String,
    pub attributes: HashMap<String, String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum LogLevel {
    Debug,
    Info,
    Warn,
    Error,
}

impl TurnSpan {
    // ✨ Create new span with automatic ID generation
    pub fn new(operation_name: &str, parent_span_id: Option<&str>) -> Self {
        let trace_id = Self::generate_trace_id();
        let span_id = Self::generate_span_id();

        Self {
            span_id,
            trace_id,
            parent_span_id: parent_span_id.map(|s| s.to_string()),
            operation_name: operation_name.to_string(),
            service_name: std::env::var("SERVICE_NAME").unwrap_or("unknown".to_string()),
            start_time: Instant::now(),
            end_time: None,
            duration: None,
            status: SpanStatus::InProgress,
            metadata: HashMap::new(),
            tags: Vec::new(),
            logs: Vec::new(),
        }
    }

    // ✨ Generate globally unique trace ID
    fn generate_trace_id() -> String {
        Uuid::new_v4().to_string()
    }

    // ✨ Generate unique span ID within trace
    fn generate_span_id() -> String {
        Uuid::new_v4().to_string()[..8].to_string() // Shorter for readability
    }

    // ✨ Add metadata for rich context
    pub fn add_metadata(&mut self, key: &str, value: &str) {
        self.metadata.insert(key.to_string(), value.to_string());
    }

    // ✨ Add tags for categorization
    pub fn add_tag(&mut self, tag: &str) {
        if !self.tags.contains(&tag.to_string()) {
            self.tags.push(tag.to_string());
        }
    }

    // ✨ Add structured logs
    pub fn log(&mut self, level: LogLevel, message: &str, attributes: HashMap<String, String>) {
        self.logs.push(SpanLog {
            timestamp: Instant::now(),
            level,
            message: message.to_string(),
            attributes,
        });
    }

    // ✨ Mark span as complete
    pub fn complete(&mut self) {
        let end_time = Instant::now();
        self.end_time = Some(end_time);
        self.duration = Some(end_time.duration_since(self.start_time));
        if matches!(self.status, SpanStatus::InProgress) {
            self.status = SpanStatus::Success;
        }
    }

    // ✨ Mark span as failed
    pub fn fail(&mut self, error_message: &str) {
        self.end_time = Some(Instant::now());
        self.duration = Some(Instant::now().duration_since(self.start_time));
        self.status = SpanStatus::Error {
            message: error_message.to_string(),
        };
    }
}
