// Example of a complex distributed operation
async fn complex_user_operation(user_id: &str) -> Result<OperationResult, Error> {
    // ✨ Root span for the entire operation
    let mut root_span = TurnSpan::new("complex_user_operation", None);
    root_span.add_metadata("user_id", user_id);
    root_span.add_tag("user_operation");
    root_span.add_tag("high_priority");

    println!("🚀 Starting complex operation trace: {}", root_span.trace_id);

    // ✨ Step 1: Validate user (creates child span)
    let mut validate_span = TurnSpan::new("validate_user", Some(&root_span.span_id));
    validate_span.add_metadata("user_id", user_id);
    validate_span.add_tag("validation");

    match validate_user(user_id).await {
        Ok(_) => {
            validate_span.complete();
            root_span.log(LogLevel::Info, "User validation successful", HashMap::new());
        }
        Err(e) => {
            validate_span.fail(&e.to_string());
            root_span.log(LogLevel::Error, "User validation failed", 
                         [("error".to_string(), e.to_string())].iter().cloned().collect());
            root_span.fail("Operation failed during user validation");
            return Err(e);
        }
    }

    // ✨ Step 2: Fetch user data from external service (child span)
    let mut fetch_span = TurnSpan::new("fetch_user_data", Some(&root_span.span_id));
    fetch_span.add_metadata("user_id", user_id);
    fetch_span.add_metadata("service", "user-service");
    fetch_span.add_tag("external_call");

    let user_data = match fetch_user_data_from_service(user_id).await {
        Ok(data) => {
            fetch_span.complete();
            data
        }
        Err(e) => {
            fetch_span.fail(&e.to_string());
            root_span.fail(&format!("Failed to fetch user data: {}", e));
            return Err(e);
        }
    };

    // ✨ Step 3: Process user data (child span)
    let mut process_span = TurnSpan::new("process_user_data", Some(&root_span.span_id));
    process_span.add_metadata("user_id", user_id);
    process_span.add_metadata("data_size", &user_data.len().to_string());
    process_span.add_tag("processing");

    let result = match process_user_data(user_data).await {
        Ok(processed) => {
            process_span.complete();
            processed
        }
        Err(e) => {
            process_span.fail(&e.to_string());
            root_span.fail(&format!("Failed to process user data: {}", e));
            return Err(e);
        }
    };

    // ✨ Complete root span
    root_span.complete();

    // ✨ All spans now connected via trace_id and parent_span_id!
    // This creates a beautiful trace that can be visualized in tools like Jaeger or Zipkin

    println!("✅ Complex operation completed successfully");
    println!("📊 Trace ID: {} | Duration: {:?} | Spans: 4", 
             root_span.trace_id, root_span.duration.unwrap());

    Ok(result)
}

