#[derive(Debug)]
pub enum SamplerType {
    Probabilistic,
    RateLimiting { max_spans_per_second: u32 },
    Adaptive { based_on_load: bool },
}

impl SpanSampler {
    pub fn should_sample(&self, trace_id: &str) -> bool {
        match self.sampler_type {
            SamplerType::Probabilistic => {
                // ✨ Hash-based sampling for consistent decisions
                let hash = seahash::hash(trace_id.as_bytes());
                (hash as f64 / u64::MAX as f64) < self.sample_rate
            }
            SamplerType::RateLimiting { max_spans_per_second } => {
                // ✨ Rate-based sampling
                self.check_rate_limit(max_spans_per_second)
            }
            SamplerType::Adaptive { based_on_load } => {
                // ✨ Adaptive sampling based on system load
                if based_on_load {
                    self.adaptive_sampling_decision()
                } else {
                    true
                }
            }
        }
    }
}

