    pub async fn aggregate_spans(&self, spans: Vec<TurnSpan>) -> SpanMetrics {
        let mut metrics = SpanMetrics::default();

        for span in spans {
            // ✨ Aggregate timing data
            if let Some(duration) = span.duration {
                metrics.total_duration += duration;
                metrics.span_count += 1;

                // ✨ Track operation-specific metrics
                *metrics.operation_counts.entry(span.operation_name.clone()).or_insert(0) += 1;

                // ✨ Track error rates
                if matches!(span.status, SpanStatus::Error { .. }) {
                    metrics.error_count += 1;
                }

                // ✨ Track service-specific metrics
                *metrics.service_durations.entry(span.service_name.clone())
                    .or_insert(Duration::from_secs(0)) += duration;
            }
        }

        metrics
    }
}

