#### 🧱 Strategy Loop Architecture

```rust
use std::time::{Duration, Instant};
use serde::{Deserialize, Serialize};

#[derive(Debug)]
pub enum StrategyOutput {
    Success(serde_json::Value),
    Pause {
        reason: String,
        context: serde_json::Value,
        checkpoint_id: String,
    },
    Error {
        error: Error,
        retryable: bool,
        backoff_duration: Option<Duration>,
    },
}

#[derive(Debug)]
pub struct StrategyLoopConfig {
    pub max_retries: usize,
    pub base_backoff: Duration,
    pub max_backoff: Duration,
    pub timeout: Duration,
    pub pause_timeout: Duration,
}

pub struct StrategyExecutor {
    config: StrategyLoopConfig,
    metrics_collector: MetricsCollector,
}

impl StrategyExecutor {
    pub async fn execute_with_loop(
        &self,
        mut input: StrategyInput,
    ) -> Result<StrategyResult, Error> {
        let start_time = Instant::now();
        let mut retry_count = 0;
        let mut current_backoff = self.config.base_backoff;

        loop {
            // ✨ Check overall timeout
            if start_time.elapsed() > self.config.timeout {
                return Err(Error::StrategyTimeout {
                    elapsed: start_time.elapsed(),
                    max_allowed: self.config.timeout,
                });
            }

            match self.execute_single_step(input.clone()).await {
                // ✨ PAUSE HANDLING - Wait for human intervention
                Ok(StrategyOutput::Pause { reason, context, checkpoint_id }) => {
                    println!("✋ Strategy loop paused: {} (checkpoint: {})", reason, checkpoint_id);

                    // ✨ Record pause metrics
                    self.metrics_collector.record_pause(&reason).await?;

                    // ✨ Wait for human intervention (could be async)
                    match self.wait_for_human_intervention(
                        &checkpoint_id,
                        self.config.pause_timeout,
                    ).await {
                        Ok(resume_context) => {
                            // ✨ Resume with new context
                            input = self.merge_resume_context(input, resume_context)?;
                            println!("🔄 Strategy loop resuming after human intervention");
                            retry_count = 0; // Reset retry count after human intervention
                            current_backoff = self.config.base_backoff; // Reset backoff
                            continue;
                        }
                        Err(e) => {
                            return Err(Error::HumanInterventionFailed {
                                checkpoint_id,
                                original_error: Box::new(e),
                            });
                        }
                    }
                }

                // ✨ ERROR HANDLING - Retry logic or failure
                Ok(StrategyOutput::Error { error, retryable, backoff_duration }) => {
                    println!("❌ Strategy loop error: {} (retryable: {})", error, retryable);

                    // ✨ Record error metrics
                    self.metrics_collector.record_error(&error, retryable).await?;

                    if retryable && retry_count < self.config.max_retries {
                        retry_count += 1;

                        // ✨ Apply backoff
                        let backoff = backoff_duration.unwrap_or(current_backoff);
                        println!("🔄 Strategy loop retrying in {:?} (attempt {}/{})", 
                                 backoff, retry_count, self.config.max_retries);

                        tokio::time::sleep(backoff).await;

                        // ✨ Exponential backoff (if no specific duration given)
                        if backoff_duration.is_none() {
                            current_backoff = std::cmp::min(
                                current_backoff * 2,
                                self.config.max_backoff,
                            );
                        }

                        continue;
                    } else {
                        // ✨ Non-retryable or max retries exceeded
                        println!("💥 Strategy loop giving up after {} attempts", retry_count);
                        return Err(error);
                    }
                }

                // ✨ SUCCESS - We're done!
                Ok(StrategyOutput::Success(result)) => {
                    println!("✅ Strategy loop completed successfully");

                    // ✨ Record success metrics
                    self.metrics_collector.record_success(start_time.elapsed()).await?;

                    return Ok(StrategyResult::Success { data: result });
                }
            }
        }
    }

    async fn wait_for_human_intervention(
        &self,
        checkpoint_id: &str,
        timeout: Duration,
    ) -> Result<ResumeContext, Error> {
        println!("⏳ Waiting for human intervention on checkpoint: {}", checkpoint_id);

        // ✨ This could involve:
        // - Webhook notifications to human operators
        // - Polling for approval status
        // - WebSocket connections for real-time updates
        // - Email/SMS notifications

        tokio::select! {
            result = self.poll_for_approval(checkpoint_id) => {
                result
            }
            _ = tokio::time::sleep(timeout) => {
                Err(Error::HumanInterventionTimeout {
                    checkpoint_id: checkpoint_id.to_string(),
                    timeout,
                })
            }
        }
    }
}
