// Example strategy that demonstrates both errors and pauses
async fn example_strategy_with_both(input: StrategyInput) -> Result<StrategyOutput, Error> {
    // ✨ Simulate different scenarios

    // Scenario 1: Network error (retryable)
    if should_simulate_network_error() {
        return Ok(StrategyOutput::Error {
            error: Error::NetworkError("Temporary network issue".to_string()),
            retryable: true,
            backoff_duration: Some(Duration::from_secs(2)),
        });
    }

    // Scenario 2: Rate limit error (retryable with backoff)
    if should_simulate_rate_limit() {
        return Ok(StrategyOutput::Error {
            error: Error::RateLimitExceeded,
            retryable: true,
            backoff_duration: Some(Duration::from_secs(5)), // Longer backoff
        });
    }

    // Scenario 3: Invalid input (non-retryable)
    if input.is_invalid() {
        return Ok(StrategyOutput::Error {
            error: Error::InvalidInput("Input validation failed".to_string()),
            retryable: false,
            backoff_duration: None,
        });
    }

    // Scenario 4: High-risk operation (requires human pause)
    if input.requires_human_review() {
        let checkpoint_id = generate_checkpoint_id();
        let context = serde_json::json!({
            "risk_score": input.calculate_risk_score().await?,
            "user_id": input.user_id,
            "operation": input.operation_type,
            "amount": input.amount,
        });

        return Ok(StrategyOutput::Pause {
            reason: "High-risk operation requires human approval".to_string(),
            context,
            checkpoint_id,
        });
    }

    // Scenario 5: Success
    let result = process_input_successfully(input).await?;
    Ok(StrategyOutput::Success(result))
}

