    if risk_score > 0.8 {
        return Ok(StrategyOutput::Pause {
            reason: "High-risk transaction requires approval".to_string(),
            context: serde_json::json!({
                "risk_score": risk_score,
                "amount": input.amount,
                "currency": input.currency,
                "user_id": input.user_id,
                "flags": identify_risk_flags(&input).await?,
            }),
            checkpoint_id: generate_secure_checkpoint_id(),
        });
    }

    // ✨ Step 3: External service call (retryable)
    match call_payment_processor(&input).await {
        Ok(result) => {
            // ✨ Success!
            Ok(StrategyOutput::Success(serde_json::json!({
