                backoff_duration: Some(Duration::from_secs(3)),
            })
        }
        Err(PaymentError::RateLimit) => {
            // ✨ Rate limit - longer backoff
            Ok(StrategyOutput::Error {
                error: Error::RateLimitExceeded,
                retryable: true,
                backoff_duration: Some(Duration::from_secs(10)),
            })
