// 2. Smart backoff strategies
#[derive(Debug)]
pub enum BackoffStrategy {
    Exponential,
    Linear,
    Fibonacci,
    Custom(fn(usize) -> Duration),
}

impl StrategyExecutor {
    fn calculate_backoff(&self, retry_count: usize, strategy: BackoffStrategy) -> Duration {
        match strategy {
            BackoffStrategy::Exponential => {
                self.config.base_backoff * 2_u32.pow(retry_count as u32)
            }
            BackoffStrategy::Linear => {
                self.config.base_backoff + (self.config.base_backoff * retry_count as u32)
            }
            BackoffStrategy::Fibonacci => {
                let fib = fibonacci(retry_count);
                self.config.base_backoff * fib
            }
            BackoffStrategy::Custom(func) => func(retry_count),
        }
    }
}

