    phase: usize,
    reason: String,
    context: Value,
) -> Result<String, Error> {
    let checkpoint = PauseCheckpoint {
        id: generate_checkpoint_id(),
        phase,
        reason: reason.clone(),
        context: context.clone(),
        created_at: Instant::now(),
        expires_at: Instant::now() + Duration::from_secs(3600), // 1 hour TTL
        status: PauseStatus::Pending,
    };

    // Store checkpoint for later resumption
    store_checkpoint(&checkpoint).await?;

    // Notify relevant parties
    notify_pause_handlers(&checkpoint).await?;

    println!("⏸️  Strategy paused at phase {} - waiting for human intervention", phase + 1);
    Ok(checkpoint.id)
}

// ✨ Backoff calculation for retries
fn calculate_exponential_backoff(retry_count: usize) -> Duration {
    let base_delay = Duration::from_secs(1);
    let max_delay = Duration::from_secs(300); // 5 minutes max

    let delay = base_delay * 2_u32.pow(retry_count as u32);
    delay.min(max_delay)
}
