impl CircuitBreaker {
    async fn execute_with_circuit_breaker<F, Fut, T>(
        &self,
        operation: F,
    ) -> Result<T, StrategyError>
    where
        F: FnOnce() -> Fut,
        Fut: std::future::Future<Output = Result<T, StrategyError>>,
    {
        if self.is_open() {
            return Err(StrategyError::Transient {
                error: "Circuit breaker is open".to_string(),
                retryable: false,
            });
        }

        match operation().await {
            Ok(result) => {
                self.reset();
                Ok(result)
            }
            Err(e) => {
                self.record_failure();
                Err(e)
            }
        }
    }
}

