// Batch error handling
async fn handle_batch_errors(
    results: Vec<Result<StrategyOutput, StrategyError>>,
) -> Result<Vec<StrategyOutput>, StrategyError> {
    let mut successful_outputs = Vec::new();
    let mut errors = Vec::new();

    for result in results {
        match result {
            Ok(output) => successful_outputs.push(output),
            Err(error) => errors.push(error),
        }
    }

    if !errors.is_empty() {
        // Determine if batch should fail or continue
        let should_fail = errors.iter().any(|e| {
            matches!(e, StrategyError::Permanent { .. } | StrategyError::Security { .. })
        });

        if should_fail {
            return Err(StrategyError::Permanent {
                error: format!("Batch failed with {} errors", errors.len()),
            });
        } else {
            // Log transient errors but continue with successful items
            for error in errors {
                log_warning(&format!("Batch item failed: {:?}", error)).await;
            }
        }
    }

    Ok(successful_outputs)
}
