```rust
// ✅ EVA celebrates this beautiful error/pause distinction:
async fn beautiful_strategy_execution() -> Result<Value, StrategyError> {
    let mut context = StrategyLoopContext::new();

    loop {
        match execute_strategy_phase(&context).await {
            // ✨ PAUSE: Human wisdom needed
            Ok(StrategyOutput::Pause { reason, context: pause_context }) => {
                println!("✋ Strategic pause requested: {}", reason);

                // Store for human review
                let checkpoint_id = store_pause_state(pause_context).await?;

                // Wait for human decision (this is the key difference!)
                match await_human_decision(&checkpoint_id).await? {
                    HumanDecision::Approve => {
                        // Resume with approval
                        context.approval_context = Some(get_approval_context(&checkpoint_id).await?);
                        continue; // Same phase, but with approval
                    }
                    HumanDecision::Reject => {
                        return Err(StrategyError::Permanent {
                            error: "Human rejected the operation".to_string()
                        });
                    }
                }
            }

            // ✨ ERROR: System issue to resolve
            Err(strategy_error) => {
                println!("❌ Strategy system error: {:?}", strategy_error);

                match handle_strategy_error(strategy_error, &context) {
                    ErrorAction::Retry { delay } => {
                        // Automatic retry - no human needed
                        tokio::time::sleep(delay).await;
                        context.retry_count += 1;
                        continue;
                    }
                    ErrorAction::Fail { error } => {
                        // Give up - system can't resolve this
                        return Err(error);
                    }
                    ErrorAction::Skip => {
                        // Skip problematic phase
                        context.current_phase += 1;
                        continue;
                    }
                    ErrorAction::Escalate { level } => {
                        // Escalate to appropriate team
                        escalate_to_team(level, &strategy_error).await?;
                        // Wait for resolution
                        match await_escalation_resolution().await? {
                            Resolution::Fixed => continue, // Retry
                            Resolution::Failed => return Err(strategy_error),
                        }
                    }
                }
            }

            // ✨ SUCCESS: Continue to next phase
            Ok(StrategyOutput::Continue(result)) => {
                context.current_phase += 1;
                if context.current_phase >= context.total_phases {
                    return Ok(result);
                }
            }
        }
    }
}

