// Backend handler that creates and propagates turn spans
async fn handle_copilot_request(
    request: CopilotRequest,
    user_session: &UserSession,
) -> Result<impl Stream<Item = StreamChunk>, Error> {
    // ✨ 1. Create turn span for this request
    let turn_span = TurnSpan {
        id: Uuid::new_v4().to_string(),
        parent_span_id: request.parent_span_id.clone(),
        trace_id: request.trace_id.unwrap_or_else(|| Uuid::new_v4().to_string()),
        start_time: Instant::now(),
        user_id: user_session.user_id.clone(),
        session_id: user_session.session_id.clone(),
        request_type: RequestType::CopilotQuery,
        metadata: json!({
            "query": request.query,
            "context_length": request.context.len(),
            "model": request.model,
        }),
    };

    // ✨ 2. Log turn span creation for observability
    observability::log_turn_span_start(&turn_span).await?;

    // ✨ 3. Create first chunk with turn_span_id
    let first_chunk = StreamChunk::First {
        turn_span_id: turn_span.id.clone(),  // ✨ This is what enables frontend tracing!
        initial_data: json!({
            "status": "processing",
            "model": request.model,
        }),
        metadata: json!({
            "request_type": "copilot_query",
            "span_created": turn_span.start_time,
        }),
    };

    // ✨ 4. Process the actual request
    let processing_stream = process_copilot_request_streaming(request, turn_span.clone()).await?;

    // ✨ 5. Combine first chunk with processing stream
    let complete_stream = stream::once(async move { first_chunk })
        .chain(processing_stream)
        .chain(stream::once(async move {
            StreamChunk::Done {
                final_metadata: Some(json!({
                    "processing_duration_ms": turn_span.start_time.elapsed().as_millis(),
                    "status": "completed",
                })),
                completion_time: Some(Instant::now()),
            }
        }));

    Ok(complete_stream)
}
