// Trace collector that uses turn_span_id for observability
class TraceCollector {
    spans = new Map();

    startSpan(spanId, options) {
        this.spans.set(spanId, {
            id: spanId,
            startTime: options.startTime,
            metadata: options.metadata,
            dataChunks: [],
            progressUpdates: [],
            status: 'active'
        });

        // ✨ Send to observability backend
        this.sendToObservabilityBackend('span_started', {
            span_id: spanId,
            ...options
        });
    }

    addDataToSpan(spanId, data) {
        const span = this.spans.get(spanId);
        if (span) {
            span.dataChunks.push(data);
            span.lastActivity = Date.now();
        }
    }

    endSpan(spanId, options) {
        const span = this.spans.get(spanId);
        if (span) {
            span.status = 'completed';
            span.endTime = options.completionTime;
            span.finalMetadata = options.finalMetadata;

            // ✨ Send completion to observability
            this.sendToObservabilityBackend('span_completed', {
                span_id: spanId,
                duration_ms: span.endTime - span.startTime,
                ...options.finalMetadata
            });

            this.spans.delete(spanId);
        }
    }
}
