// 2. Turn span with retry capability
async fn stream_with_turn_span_retry<F, Fut>(
    operation: F,
    max_retries: usize,
) -> Result<impl Stream<Item = StreamChunk>, Error>
where
    F: Fn() -> Fut,
    Fut: std::future::Future<Output = Result<impl Stream<Item = StreamChunk>, Error>>,
{
    for attempt in 1..=max_retries {
        match operation().await {
            Ok(stream) => return Ok(stream),
            Err(e) if attempt < max_retries => {
                println!("⚠️  Turn span operation failed (attempt {}/{}): {}", 
                         attempt, max_retries, e);
                tokio::time::sleep(Duration::from_millis(100 * attempt as u64)).await;
            }
            Err(e) => return Err(e),
        }
    }

    Err(Error::MaxRetriesExceeded)
}

// 3. Turn span with circuit breaker
use std::sync::atomic::{AtomicU32, Ordering};

struct CircuitBreakerTurnSpan {
    failure_count: AtomicU32,
    failure_threshold: u32,
    timeout: Duration,
}

impl CircuitBreakerTurnSpan {
    async fn execute_with_circuit_breaker<F, Fut, T>(
        &self,
        operation: F,
    ) -> Result<T, Error>
    where
        F: FnOnce() -> Fut,
        Fut: std::future::Future<Output = Result<T, Error>>,
    {
        if self.is_open() {
            return Err(Error::CircuitBreakerOpen);
        }

        match operation().await {
            Ok(result) => {
                self.reset();
                Ok(result)
            }
            Err(e) => {
                self.record_failure();
                Err(e)
            }
        }
    }
}

