// ✨ Generate beautiful, unique turn span IDs
impl TurnSpan {
    pub fn new(
        user_id: String,
        session_id: String,
        turn_type: TurnType,
        parent_span_id: Option<String>,
    ) -> Self {
        let span_id = Uuid::new_v4().to_string();
        let root_span_id = parent_span_id.clone().unwrap_or_else(|| span_id.clone());
        let now = Instant::now();

        Self {
            span_id,
            parent_span_id,
            root_span_id,
            user_id,
            session_id,
            turn_type,
            created_at: now,
            expires_at: now + std::time::Duration::from_secs(3600), // 1 hour TTL
            metadata: SpanMetadata::default(),
        }
    }

    // ✨ Create child span for hierarchical tracing
    pub fn create_child(&self, turn_type: TurnType) -> Self {
        Self::new(
            self.user_id.clone(),
            self.session_id.clone(),
            turn_type,
            Some(self.span_id.clone()),
        )
    }
