async fn collect_span_correlated_metrics(
    span: &TurnSpan,
    events: &[ObservableEvent],
) -> Result<CorrelatedMetrics, Error> {
    let mut metrics = CorrelatedMetrics::default();

    // ✨ Calculate interaction duration
    if let Some(first_event) = events.first() {
        if let Some(last_event) = events.last() {
            metrics.total_duration = last_event.timestamp.duration_since(first_event.timestamp)?;
        }
    }

    // ✨ Count different event types
    for event in events {
        match event.event_type {
            EventType::UserMessageReceived => metrics.user_messages += 1,
            EventType::AssistantProcessingStarted => metrics.ai_calls += 1,
            EventType::ToolExecution => metrics.tool_calls += 1,
            EventType::ErrorOccurred => metrics.errors += 1,
            _ => {}
        }

        // ✨ Sum durations for timing analysis
        if let Some(duration) = event.duration {
            metrics.total_processing_time += duration;
        }
    }

    // ✨ Correlate with user and session data
    metrics.user_id = span.user_id.clone();
    metrics.session_id = span.session_id.clone();
    metrics.interaction_type = format!("{:?}", span.turn_type);

    // ✨ Store with span ID for later correlation
    store_correlated_metrics(&span.span_id, &metrics).await?;

    Ok(metrics)
