#[derive(Debug)]
pub struct SamplingStrategy {
    pub base_rate: f64,               // Base sampling rate (0.0 - 1.0)
    pub priority_boost: f64,          // Boost for high-priority spans
    pub error_boost: f64,             // Boost for spans with errors
    pub user_segment_boost: HashMap<String, f64>, // Per-user-segment boosts
}

impl SamplingStrategy {
    pub fn should_sample(&self, span: &TurnSpan, events: &[ObservableEvent]) -> bool {
        let mut sample_rate = self.base_rate;

        // ✨ Boost for high-priority interactions
        match span.turn_type {
            TurnType::HumanIntervention => sample_rate += self.priority_boost,
            TurnType::ErrorRecovery => sample_rate += self.error_boost,
            _ => {}
        }

        // ✨ Boost for spans with errors
        if events.iter().any(|e| matches!(e.event_type, EventType::ErrorOccurred)) {
            sample_rate += self.error_boost;
        }

        // ✨ User segment boosting
        if let Some(boost) = self.user_segment_boost.get(&get_user_segment(&span.user_id)) {
            sample_rate += boost;
        }

        // ✨ Random sampling based on calculated rate
        let random_value: f64 = rand::random();
        random_value < sample_rate.min(1.0)
    }
}
