async fn handle_subprocess_exit(
    process_result: SubprocessResult,
    stream_sender: &EventSender,
) -> Result<(), Error> {
    match process_result {
        SubprocessResult::Completed { output, exit_code } => {
            // ✨ Normal completion
            stream_sender.send(Event::Data(output)).await?;
            stream_sender.send(Event::Done { success: true }).await?;
        }
