use serde::{Deserialize, Serialize};
use std::time::{Duration, Instant};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum SubprocessResult {
    Completed {
        output: String,
        exit_code: i32,
        duration: Duration,
    },
    ExitedEarly {
        exit_code: i32,
        reason: String,
        partial_output: Option<String>,
        duration: Duration,
    },
    Crashed {
        error: String,
        partial_output: Option<String>,
        duration: Duration,
    },
    TimedOut {
        timeout: Duration,
        partial_output: Option<String>,
    },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum StreamEvent {
    Data(String),
    Progress {
        percentage: f32,
        message: String,
    },
    Error(String),
    Done {
        success: bool,
        exit_code: Option<i32>,
        reason: Option<String>,
    },
    Heartbeat,
}

// ✨ The core fallback mechanism
async fn handle_subprocess_completion(
    result: SubprocessResult,
    event_sender: EventSender,
) -> Result<ProcessingResult, Error> {
    println!("🔄 Handling subprocess completion: {:?}", result);

    match result {
        // ✨ Normal completion path
        SubprocessResult::Completed { output, exit_code, duration } => {
            println!("✅ Subprocess completed normally in {:?}", duration);

            // Send final output
            if !output.is_empty() {
                event_sender.send(StreamEvent::Data(output.clone())).await?;
            }

            // ✨ Send completion event
            event_sender.send(StreamEvent::Done {
                success: exit_code == 0,
                exit_code: Some(exit_code),
                reason: None,
            }).await?;

            Ok(ProcessingResult::Success { 
                output, 
                exit_code, 
                duration 
            })
        }

        // ✨ EARLY EXIT PATH (where done=true fallback is crucial!)
        SubprocessResult::ExitedEarly { 
            exit_code, 
            reason, 
            partial_output, 
            duration 
        } => {
            println!("⚠️  Subprocess exited early after {:?}: {}", duration, reason);

            // ✨ Send any partial output we managed to capture
            if let Some(output) = partial_output {
                if !output.is_empty() {
                    event_sender.send(StreamEvent::Data(output.clone())).await?;
                }
            }

            // ✨ CRITICAL: Emit done=true to ensure stream doesn't hang!
            event_sender.send(StreamEvent::Done {
                success: exit_code == 0,
                exit_code: Some(exit_code),
                reason: Some(reason.clone()),
            }).await?;

            // Log the early exit for monitoring
            log_early_exit(&reason, exit_code, duration).await?;

            Ok(ProcessingResult::EarlyExit { 
                reason, 
                exit_code, 
                duration 
            })
        }

        // ✨ Crash handling
        SubprocessResult::Crashed { error, partial_output, duration } => {
            println!("💥 Subprocess crashed after {:?}: {}", duration, error);

            // Send any partial output
            if let Some(output) = partial_output {
                event_sender.send(StreamEvent::Data(output)).await?;
            }

            // ✨ Send error and completion
            event_sender.send(StreamEvent::Error(error.clone())).await?;
            event_sender.send(StreamEvent::Done {
                success: false,
                exit_code: None,
                reason: Some(error.clone()),
            }).await?;

            Err(Error::SubprocessCrash(error))
        }

        // ✨ Timeout handling
        SubprocessResult::TimedOut { timeout, partial_output } => {
            println!("⏰ Subprocess timed out after {:?}", timeout);

            // Send partial output
            if let Some(output) = partial_output {
                event_sender.send(StreamEvent::Data(output)).await?;
            }

            // ✨ Send timeout completion
