                // ❌ FORGOT to send done event!
                // Stream hangs forever!
            }
        }
        Err(e) => {
            sender.send(Event::Error(e.to_string())).await?;
            // ❌ FORGOT to send done event!
            // Stream hangs forever!
        }
    }

    // Client keeps waiting for done event that never comes!
    Ok(())
