// ✨ Example of what happens WITH done=true fallback:

async fn good_stream_handling() -> Result<(), Error> {
    let (sender, mut receiver) = create_event_stream();

    // Start subprocess
    let subprocess = start_subprocess().await?;

    // Wait for subprocess completion
    match subprocess.wait().await {
        Ok(exit_status) => {
            if exit_status.success() {
                sender.send(Event::Data("Success!".to_string())).await?;
                // ✨ ALWAYS send done event!
                sender.send(Event::Done { success: true }).await?;
            } else {
                sender.send(Event::Error("Failed".to_string())).await?;
                // ✨ ALWAYS send done event!
                sender.send(Event::Done { success: false }).await?;
            }
        }
        Err(e) => {
            sender.send(Event::Error(e.to_string())).await?;
            // ✨ ALWAYS send done event even on crash!
            sender.send(Event::Done { success: false }).await?;
