// Build process that might fail early
async fn build_project(
    project_path: &str,
    event_sender: EventSender,
) -> Result<BuildResult, Error> {
    let start_time = Instant::now();

    // Start build process
    let mut child = tokio::process::Command::new("make")
        .current_dir(project_path)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    // Capture output in real-time
    let mut stdout_lines = BufReader::new(child.stdout.take().unwrap()).lines();
    let mut stderr_lines = BufReader::new(child.stderr.take().unwrap()).lines();

    // ✨ Stream output as it arrives
    let mut output_buffer = String::new();

    loop {
        tokio::select! {
            // Handle stdout
            stdout_line = stdout_lines.next_line() => {
                match stdout_line {
                    Ok(Some(line)) => {
                        output_buffer.push_str(&line);
                        output_buffer.push('\n');
                        event_sender.send(StreamEvent::Data(line)).await?;
                    }
                    Ok(None) => break, // EOF
                    Err(e) => {
                        // ✨ Handle read error
                        event_sender.send(StreamEvent::Error(e.to_string())).await?;
                        break;
                    }
                }
            }

            // Handle stderr
            stderr_line = stderr_lines.next_line() => {
                match stderr_line {
                    Ok(Some(line)) => {
                        event_sender.send(StreamEvent::Error(line)).await?;
                    }
                    Ok(None) => break, // EOF
                    Err(e) => {
                        event_sender.send(StreamEvent::Error(e.to_string())).await?;
                        break;
                    }
                }
            }

            // Timeout handling
            _ = tokio::time::sleep(Duration::from_secs(300)) => {
                // ✨ 5-minute timeout
                let _ = child.kill().await;

                event_sender.send(StreamEvent::Error("Build timeout".to_string())).await?;
                event_sender.send(StreamEvent::Done {
                    success: false,
                    exit_code: None,
                    reason: Some("Build process timed out after 5 minutes".to_string()),
                }).await?;

                return Err(Error::BuildTimeout);
            }
        }
    }

    // Wait for process completion
    let status = child.wait().await?;
    let duration = start_time.elapsed();

    // ✨ CRITICAL: Ensure done=true is sent regardless of exit condition
    let result = if status.success() {
        BuildResult::Success {
            output: output_buffer,
            duration,
        }
    } else {
        // ✨ Even on failure, send done=true to close stream properly
        event_sender.send(StreamEvent::Done {
            success: false,
            exit_code: status.code(),
            reason: Some("Build process failed".to_string()),
        }).await?;

        BuildResult::Failed {
            error: "Build process exited with error".to_string(),
            output: output_buffer,
            exit_code: status.code().unwrap_or(1),
            duration,
        }
    };

    // ✨ Always send final done event
    event_sender.send(StreamEvent::Done {
        success: status.success(),
        exit_code: status.code(),
        reason: None,
    }).await?;

    Ok(result)
}
