async fn retry_with_done_tracking(
    max_retries: usize,
    operation: impl Fn() -> Future<Output = Result<SubprocessResult, Error>>,
    event_sender: EventSender,
) -> Result<ProcessingResult, Error> {
    let mut retry_count = 0;

    loop {
        match operation().await {
            Ok(result) => {
                // ✨ Success - handle normally
                return handle_subprocess_completion(result, event_sender).await;
            }
            Err(e) if retry_count < max_retries => {
                // ✨ Retryable error - increment and retry
                retry_count += 1;
                println!("🔄 Retrying operation (attempt {}/{})", retry_count, max_retries);
                tokio::time::sleep(Duration::from_secs(2_u64.pow(retry_count as u32))).await;
            }
            Err(e) => {
                // ✨ Final failure - send done=true
                event_sender.send(StreamEvent::Error(e.to_string())).await?;
                event_sender.send(StreamEvent::Done {
                    success: false,
                    exit_code: None,
                    reason: Some(format!("Operation failed after {} retries", max_retries)),
                }).await?;
                return Err(e);
            }
        }
    }
}
