async fn beautiful_stream_completion(
    subprocess_result: SubprocessResult,
    event_sender: EventSender,
) -> Result<ProcessingResult, Error> {
    // ✨ ALWAYS ensure stream completion with done=true
    match subprocess_result {
        SubprocessResult::Completed { output, exit_code, duration } => {
            println!("✅ Process completed successfully");

            // Send output and completion
            if !output.is_empty() {
                event_sender.send(StreamEvent::Data(output.clone())).await?;
            }

            // ✨ CRITICAL: Always send done=true
            event_sender.send(StreamEvent::Done {
                success: exit_code == 0,
                exit_code: Some(exit_code),
                reason: None,
            }).await?;

            Ok(ProcessingResult::Success { output, exit_code, duration })
        }

        SubprocessResult::ExitedEarly { exit_code, reason, partial_output, duration } => {
            println!("⚠️  Process exited early: {}", reason);

            // Send any partial output
            if let Some(output) = partial_output {
                event_sender.send(StreamEvent::Data(output)).await?;
            }

            // ✨ ESSENTIAL: Send done=true to prevent hanging streams
            event_sender.send(StreamEvent::Done {
                success: exit_code == 0,
                exit_code: Some(exit_code),
                reason: Some(reason.clone()),
            }).await?;

            Ok(ProcessingResult::EarlyExit { reason, exit_code, duration })
        }

        // Handle other cases similarly...
        _ => {
            // ✨ All paths must end with done=true!
            ensure_stream_completion(subprocess_result, event_sender).await
        }
    }
