            request_context: serde_json::to_value(&initial_request)?,
            system_state: capture_system_state().await?,
            security_context: SecurityContext::from_session(user_session),
        }
    );

    // ✨ 3. Record initial audit event
    circuit.record_audit_event(AuditEvent {
        timestamp: Instant::now(),
        event_type: AuditEventType::RequestReceived,
        actor: user_session.user_id.clone(),
        target: "system".to_string(),
        action: "submit_request".to_string(),
        outcome: "success".to_string(),
        metadata: json!({
            "request_type": initial_request.request_type,
            "turn_span_id": root_turn_span_id,
        }),
    });

    // ✨ 4. Process request and build causal chain
    let processing_result = process_request_with_causality_tracking(
        initial_request,
        &mut circuit,
        root_turn_span_id.clone(),
    ).await?;

    // ✨ 5. Complete the circuit
    circuit.complete();

    Ok(circuit)
}

// Processing with causal relationship tracking
async fn process_request_with_causality_tracking(
    request: UserRequest,
    circuit: &mut LineageCircuit,
    parent_span_id: String,
) -> Result<ProcessingResult, Error> {
    // ✨ Step 1: Input validation
    let validation_span_id = uuid::Uuid::new_v4().to_string();
    validate_input(&request)?;

    // ✨ Add causal link: request received → input validated
    circuit.add_causal_link(CausalLink {
        cause_span_id: parent_span_id.clone(),
        effect_span_id: validation_span_id.clone(),
        cause_operation: "request_received".to_string(),
        effect_operation: "input_validation".to_string(),
        relationship_type: CausalityType::DirectCause,
        timestamp: Instant::now(),
        confidence: 1.0,
        metadata: json!({ "validation_rules": "standard" }),
    });

    // ✨ Step 2: Risk assessment
    let risk_span_id = uuid::Uuid::new_v4().to_string();
    let risk_score = assess_risk(&request).await?;

    // ✨ Add causal link: input validated → risk assessed
    circuit.add_causal_link(CausalLink {
        cause_span_id: validation_span_id,
        effect_span_id: risk_span_id.clone(),
        cause_operation: "input_validation".to_string(),
        effect_operation: "risk_assessment".to_string(),
        relationship_type: CausalityType::Dependency,
        timestamp: Instant::now(),
        confidence: 0.95,
        metadata: json!({ "risk_score": risk_score }),
    });

    // ✨ Step 3: Decision making based on risk
    let decision_span_id = uuid::Uuid::new_v4().to_string();
    let decision = make_decision_based_on_risk(risk_score, &request)?;

    // ✨ Add causal link: risk assessed → decision made
    circuit.add_causal_link(CausalLink {
        cause_span_id: risk_span_id,
        effect_span_id: decision_span_id.clone(),
        cause_operation: "risk_assessment".to_string(),
        effect_operation: "decision_making".to_string(),
        relationship_type: CausalityType::Trigger,
        timestamp: Instant::now(),
        confidence: 0.9,
        metadata: json!({ "decision_type": format!("{:?}", decision) }),
    });

    // ✨ Record decision audit event
    circuit.record_audit_event(AuditEvent {
        timestamp: Instant::now(),
        event_type: AuditEventType::DecisionMade,
        actor: "system".to_string(),
        target: request.user_id.clone(),
        action: "make_decision".to_string(),
        outcome: format!("{:?}", decision),
        metadata: json!({
            "risk_score": risk_score,
            "decision_span_id": decision_span_id,
        }),
    });

    Ok(ProcessingResult {
        decision,
        lineage_circuit_id: circuit.circuit_id.clone(),
    })
}
