// Lineage circuit with confidence scoring
impl LineageCircuit {
    pub fn calculate_lineage_confidence(&self) -> f32 {
        if self.causal_chain.is_empty() {
            return 0.0;
        }

        let total_confidence: f32 = self.causal_chain
            .iter()
            .map(|link| link.confidence)
            .sum();

        total_confidence / self.causal_chain.len() as f32
    }

    pub fn find_causal_path(&self, from_span_id: &str, to_span_id: &str) -> Option<Vec<CausalLink>> {
        // ✨ Find path through causal chain
        let mut path = Vec::new();
        let mut current_span = from_span_id.to_string();

        while current_span != to_span_id {
            let next_link = self.causal_chain
                .iter()
                .find(|link| link.cause_span_id == current_span);

            match next_link {
                Some(link) => {
                    path.push(link.clone());
                    current_span = link.effect_span_id.clone();
                }
                None => return None, // No path found
            }
        }

        Some(path)
    }

    pub fn get_related_audits(&self, span_id: &str) -> Vec<&AuditEvent> {
        self.audit_trail
            .iter()
            .filter(|audit| {
                audit.metadata.get("span_id")
                    .and_then(|v| v.as_str())
                    .map(|id| id == span_id)
                    .unwrap_or(false)
            })
            .collect()
    }
}

// Lineage visualization
pub struct LineageVisualizer {
    circuit: LineageCircuit,
