impl LineageVisualizer {
    pub fn generate_mermaid_diagram(&self) -> String {
        let mut diagram = "graph TD\n".to_string();

        for link in &self.circuit.causal_chain {
            let relationship_symbol = match link.relationship_type {
                CausalityType::DirectCause => "-->";
                CausalityType::Trigger => "==>";
                CausalityType::Dependency => "-.->";
                _ => "-->",
            };

            diagram.push_str(&format!(
                "    {}[{}] {} {}[{}]\n",
                link.cause_span_id[..8].to_string(),
                link.cause_operation,
                relationship_symbol,
                link.effect_span_id[..8].to_string(),
                link.effect_operation
            ));
        }

        diagram
    }

    pub fn generate_timeline(&self) -> Vec<LineageEvent> {
        let mut events = Vec::new();

        // Add audit events
        for audit in &self.circuit.audit_trail {
            events.push(LineageEvent {
                timestamp: audit.timestamp,
                event_type: LineageEventType::Audit(audit.clone()),
                span_id: audit.metadata.get("span_id")
                    .and_then(|v| v.as_str())
                    .map(|s| s.to_string()),
            });
        }

        // Add causal links
        for link in &self.circuit.causal_chain {
            events.push(LineageEvent {
                timestamp: link.timestamp,
                event_type: LineageEventType::CausalLink(link.clone()),
                span_id: Some(link.cause_span_id.clone()),
            });
        }

        events.sort_by_key(|event| event.timestamp);
        events
    }
}

