use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::time::Instant;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LineageCircuit {
    pub turn_span: TurnSpan,              // ✨ Current turn's span
    pub causal_chain: Vec<CausalLink>,    // ✨ Links to influencing turns
    pub influence_map: HashMap<String, InfluenceMetrics>, // ✨ Detailed influence data
    pub lineage_depth: usize,             // ✨ How far back the lineage goes
    pub convergence_points: Vec<String>,  // ✨ Where multiple influences converge
    pub divergence_points: Vec<String>,   // ✨ Where influences split
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CausalLink {
    pub source_turn_span_id: String,      // ✨ Originating turn
    pub target_turn_span_id: String,      // ✨ Receiving turn
    pub influence_strength: f32,          // ✨ 0.0 to 1.0 strength
    pub influence_type: InfluenceType,    // ✨ Semantic, contextual, etc.
    pub influence_path: Vec<String>,      // ✨ Path through influence graph
    pub timestamp: Instant,               // ✨ When influence was established
    pub metadata: serde_json::Value,      // ✨ Additional context
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum InfluenceType {
    Semantic,        // ✨ Meaning-based influence
    Contextual,      // ✨ Context-based influence
    Temporal,        // ✨ Time-based influence
    Syntactic,       // ✨ Structure-based influence
    Pragmatic,       // ✨ Purpose-based influence
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InfluenceMetrics {
    pub total_influence: f32,
    pub influence_sources: Vec<String>,
    pub influence_decay: f32,
    pub influence_stability: f32,
    pub contribution_score: f32,
}

impl LineageCircuit {
    // ✨ Create new lineage circuit with turn span
    pub fn new(turn_span: TurnSpan) -> Self {
        Self {
            turn_span,
            causal_chain: Vec::new(),
            influence_map: HashMap::new(),
            lineage_depth: 0,
            convergence_points: Vec::new(),
            divergence_points: Vec::new(),
        }
    }

    // ✨ Add causal link from previous turn
    pub fn add_causal_link(&mut self, link: CausalLink) {
        // ✨ Update influence map
        let influence_metrics = self.influence_map
            .entry(link.source_turn_span_id.clone())
            .or_insert_with(|| InfluenceMetrics {
                total_influence: 0.0,
                influence_sources: Vec::new(),
                influence_decay: 1.0,
                influence_stability: 1.0,
                contribution_score: 0.0,
            });

        influence_metrics.total_influence += link.influence_strength;
        influence_metrics.influence_sources.push(link.target_turn_span_id.clone());
        influence_metrics.contribution_score += link.influence_strength * 0.1; // Simple scoring

        // ✨ Add to causal chain
        self.causal_chain.push(link);

        // ✨ Update lineage depth
        self.lineage_depth = self.causal_chain.len();

        println!("🔗 Added causal link from turn {} (strength: {})", 
                 link.source_turn_span_id, link.influence_strength);
    }

    // ✨ Trace full lineage back through turn spans
    pub fn trace_lineage(&self) -> Vec<LineageTrace> {
        let mut trace = Vec::new();

        // ✨ Start with current turn
        trace.push(LineageTrace {
            turn_span_id: self.turn_span.id.clone(),
            operation: self.turn_span.operation_name.clone(),
            timestamp: self.turn_span.start_time,
            influence_from: Vec::new(),
        });

        // ✨ Trace back through causal links
        for link in &self.causal_chain {
            trace.push(LineageTrace {
                turn_span_id: link.source_turn_span_id.clone(),
                operation: "unknown".to_string(), // Would be looked up
                timestamp: link.timestamp,
                influence_from: vec![link.target_turn_span_id.clone()],
            });
        }

        trace
    }
}
