        }

        traces.push(ConversationTrace {
            turn_number: i + 2, // Turn 1 is the initial query
            turn_span_id: circuit.turn_span.id.clone(),
            influences: influence_summary,
            total_influence: circuit.influence_map.values().map(|m| m.total_influence).sum(),
        });
    }

    traces
}
