// Lineage circuit with influence decay over time
impl LineageCircuit {
    pub fn calculate_influence_decay(&self, link: &CausalLink) -> f32 {
        let time_elapsed = Instant::now().duration_since(link.timestamp);
        let hours_elapsed = time_elapsed.as_secs_f32() / 3600.0;

        // ✨ Exponential decay - influence weakens over time
        (-0.1 * hours_elapsed).exp()
    }

    pub fn get_weighted_influence_score(&self, source_span_id: &str) -> f32 {
        let base_influence = self.influence_map
            .get(source_span_id)
            .map(|m| m.total_influence)
            .unwrap_or(0.0);

        let decay_factor = self.causal_chain
            .iter()
            .find(|link| link.source_turn_span_id == source_span_id)
            .map(|link| self.calculate_influence_decay(link))
            .unwrap_or(1.0);

        base_influence * decay_factor
    }
}

// Lineage circuit with convergence detection
impl LineageCircuit {
    pub fn detect_convergence_points(&mut self) {
        let mut influence_sources: HashMap<String, usize> = HashMap::new();

        // ✨ Count how many links point to each source
        for link in &self.causal_chain {
            *influence_sources.entry(link.source_turn_span_id.clone()).or_insert(0) += 1;
        }

        // ✨ Convergence points have multiple incoming influences
        self.convergence_points = influence_sources
            .into_iter()
            .filter(|(_, count)| *count > 1)
            .map(|(source_id, _)| source_id)
            .collect();

        println!("🔄 Detected convergence points: {:?}", self.convergence_points);
    }

    pub fn detect_divergence_points(&mut self) {
        let mut influence_targets: HashMap<String, usize> = HashMap::new();

        // ✨ Count how many links originate from each target
        for link in &self.causal_chain {
            *influence_targets.entry(link.target_turn_span_id.clone()).or_insert(0) += 1;
        }

        // ✨ Divergence points have multiple outgoing influences
        self.divergence_points = influence_targets
            .into_iter()
            .filter(|(_, count)| *count > 1)
            .map(|(target_id, _)| target_id)
            .collect();

        println!("🔄 Detected divergence points: {:?}", self.divergence_points);
    }
}

