impl SampledLineageCircuit {
    pub fn new_with_sampling(turn_span: TurnSpan, sample_rate: f32) -> Self {
        let hash = seahash::hash(turn_span.id.as_bytes());
        let is_sampled = (hash as f32 / u64::MAX as f32) < sample_rate;

        Self {
            base_circuit: LineageCircuit::new(turn_span),
            sample_rate,
            is_sampled,
        }
    }

