        self.failure_count.store(0, Ordering::Release);
    }

    pub fn record_lineage_failure(&self) {
        let current_failures = self.failure_count.fetch_add(1, Ordering::AcqRel);
        if current_failures + 1 >= self.failure_threshold {
            println!("🚨 Lineage circuit breaker triggered!");
            // Trigger alert or fallback behavior
        }
    }

    pub fn is_circuit_open(&self) -> bool {
        self.failure_count.load(Ordering::Acquire) >= self.failure_threshold
    }
}

