import React, { useState, useEffect } from 'react';
import { TurnSpan, fetchTurnLineage } from '../services/observability';

interface TurnLineageStripProps {
  turnSpanId: string;  // ✨ The current turn span to trace
  maxDepth?: number;   // ✨ How far back to show lineage
  showMetadata?: boolean; // ✨ Whether to show detailed metadata
}

// ✨ The beautiful component that shows turn span lineage
const TurnLineageStrip: React.FC<TurnLineageStripProps> = ({ 
  turnSpanId, 
  maxDepth = 5, 
  showMetadata = false 
}) => {
  const [lineage, setLineage] = useState<TurnSpan[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!turnSpanId) return;

    const loadLineage = async () => {
      try {
        setLoading(true);
        setError(null);

        // ✨ Fetch the beautiful hierarchical lineage
        const spanLineage = await fetchTurnLineage(turnSpanId, maxDepth);
        setLineage(spanLineage);
      } catch (err) {
        setError(`Failed to load turn lineage: ${err}`);
        console.error('TurnLineageStrip error:', err);
      } finally {
        setLoading(false);
      }
    };

    loadLineage();
  }, [turnSpanId, maxDepth]);

  if (loading) {
    return <div className="turn-lineage-loading">✨ Loading lineage...</div>;
  }

  if (error) {
    return <div className="turn-lineage-error">❌ {error}</div>;
  }

  return (
    <div className="turn-lineage-strip" data-testid="turn-lineage-strip">
      <div className="lineage-header">
        <h4>📋 Interaction Lineage</h4>
        <span className="lineage-count">{lineage.length} spans</span>
      </div>

      <div className="lineage-nodes">
        {lineage.map((span, index) => (
          <TurnSpanNode 
            key={span.span_id}
            span={span}
            isCurrent={index === lineage.length - 1}  // ✨ Current span is last
            isRoot={index === 0}                      // ✨ Root span is first
            depth={index}
            showMetadata={showMetadata}
          />
        ))}
      </div>
    </div>
  );
};

// ✨ Individual turn span node in the lineage
interface TurnSpanNodeProps {
  span: TurnSpan;
  isCurrent: boolean;
  isRoot: boolean;
  depth: number;
  showMetadata: boolean;
}

const TurnSpanNode: React.FC<TurnSpanNodeProps> = ({ 
  span, 
  isCurrent, 
  isRoot, 
  depth,
  showMetadata 
}) => {
  const [expanded, setExpanded] = useState(false);

  return (
    <div 
      className={`turn-span-node ${isCurrent ? 'current' : ''} ${isRoot ? 'root' : ''}`}
      data-depth={depth}
      onClick={() => setExpanded(!expanded)}
    >
      {/* ✨ Visual hierarchy indicator */}
      <div className="span-depth-indicator" style={{ 
        width: `${depth * 12}px` 
      }} />

      {/* ✨ Span type icon */}
      <div className="span-icon">
        {getSpanIcon(span.turn_type)}
      </div>

      {/* ✨ Span details */}
      <div className="span-details">
        <div className="span-header">
          <span className="span-type">{formatSpanType(span.turn_type)}</span>
          {isCurrent && <span className="current-indicator">🎯 CURRENT</span>}
          {isRoot && <span className="root-indicator">🏠 ROOT</span>}
        </div>

        <div className="span-id">
          <span className="label">ID:</span>
          <code className="span-id-value">{truncateId(span.span_id)}</code>
        </div>

        <div className="span-timing">
          <span className="label">Duration:</span>
          <span className="duration">{formatDuration(span.duration)}</span>
          <span className="timestamp">{formatTimestamp(span.created_at)}</span>
        </div>

        {/* ✨ Optional metadata expansion */}
        {showMetadata && expanded && (
          <div className="span-metadata">
            <pre>{JSON.stringify(span.metadata, null, 2)}</pre>
          </div>
        )}
      </div>

      {/* ✨ Expand/collapse indicator */}
      {showMetadata && (
        <div className="expand-indicator">
          {expanded ? '▼' : '▶'}
        </div>
      )}
    </div>
