// ✨ Helper functions for beautiful display
const getSpanIcon = (turnType: TurnType): string => {
  switch (turnType) {
    case 'UserMessage': return '👤';
    case 'AssistantResponse': return '🤖';
    case 'ToolCall': return '🔧';
    case 'SystemEvent': return '⚙️';
    case 'ErrorRecovery': return '🛡️';
    case 'HumanIntervention': return '✋';
    default: return '❓';
  }
};

const formatSpanType = (turnType: TurnType): string => {
  return turnType.replace(/([A-Z])/g, ' $1').trim();
};

const truncateId = (id: string): string => {
  return id.substring(0, 8) + '...' + id.substring(id.length - 4);
};

const formatDuration = (duration: number | undefined): string => {
  if (!duration) return 'N/A';
  if (duration < 1000) return `${duration}ms`;
  return `${(duration / 1000).toFixed(2)}s`;
};

const formatTimestamp = (timestamp: string): string => {
  return new Date(timestamp).toLocaleTimeString();
};
