              isCurrent={span.span_id === turnSpanId}
              isRoot={false}
              depth={calculateSpanDepth(span, lineage)}
              showMetadata={showMetadata}
              onClick={() => onSpanSelect?.(span)}
            />
          ))}
        </div>
