#### 🧱 The Complete Frontend Merging Architecture

```typescript
// Beautiful TypeScript interfaces for observability
interface StreamEvent {
  type: 'first' | 'data' | 'progress' | 'done' | 'error';
  turn_span_id?: string;        // ✨ The magic tracing key!
  data?: string;
  metadata?: Record<string, any>;
  error?: string;
}

interface AssistantMessage {
  role: 'assistant';
  content: string;
  turn_span_id?: string;        // ✨ Merged for tracing
  timestamp: number;
  metadata?: {
    processing_time?: number;
    model_version?: string;
    confidence?: number;
    [key: string]: any;
  };
}

interface UserMessage {
  role: 'user';
  content: string;
  timestamp: number;
}

type ChatMessage = AssistantMessage | UserMessage;

// ✨ The beautiful merging function
class TurnSpanIdMerger {
  private currentTurnSpanId: string | null = null;
  private messageBuffer: string[] = [];
  private isProcessing: boolean = false;

  async mergeTurnSpanId(
    message: Partial<AssistantMessage>,
    streamEvent: StreamEvent
  ): Promise<AssistantMessage> {
    // ✨ Extract turn_span_id from stream event (if present)
    if (streamEvent.turn_span_id) {
      this.currentTurnSpanId = streamEvent.turn_span_id;
      console.log(`✨ Turn span ID captured: ${this.currentTurnSpanId}`);
    }

    // ✨ Create complete assistant message with merged turn_span_id
    const mergedMessage: AssistantMessage = {
      role: 'assistant',
      content: message.content || this.messageBuffer.join(''),
      turn_span_id: this.currentTurnSpanId || undefined,  // ✨ The merge happens here!
      timestamp: Date.now(),
      metadata: {
        ...message.metadata,
        turn_span_captured: !!this.currentTurnSpanId,
        merge_timestamp: Date.now(),
      }
    };

    // ✨ Clear buffer after successful merge
    if (this.currentTurnSpanId) {
      this.messageBuffer = [];
    }

    console.log(`🌟 Message merged with turn span ID: ${mergedMessage.turn_span_id || 'none'}`);
    return mergedMessage;
  }

  // ✨ Handle streaming chunks
  async processStreamChunk(
    chunk: StreamEvent
  ): Promise<AssistantMessage | null> {
    switch (chunk.type) {
      case 'first':
        // ✨ First chunk carries the turn_span_id!
        if (chunk.turn_span_id) {
          this.currentTurnSpanId = chunk.turn_span_id;
          console.log(`🎯 First chunk received turn span ID: ${chunk.turn_span_id}`);
        }
        return null; // First chunk doesn't contain message data

      case 'data':
        // ✨ Accumulate streaming data
        if (chunk.data) {
          this.messageBuffer.push(chunk.data);
        }
        return null; // Wait for done event to merge

      case 'done':
        // ✨ Finalize message with accumulated data and turn_span_id
        if (this.messageBuffer.length > 0) {
          const completeMessage = this.messageBuffer.join('');
          this.messageBuffer = []; // Clear buffer

          return await this.mergeTurnSpanId(
            { content: completeMessage },
            { 
              type: 'done', 
              turn_span_id: this.currentTurnSpanId || undefined 
            }
          );
        }
        return null;

      case 'error':
        // ✨ Handle error case with available turn_span_id
        console.error(`❌ Stream error: ${chunk.error}`);
        return await this.mergeTurnSpanId(
          { 
            content: `Error: ${chunk.error}`,
            metadata: { error: true, error_message: chunk.error }
          },
          { 
            type: 'error', 
            turn_span_id: this.currentTurnSpanId || undefined,
            error: chunk.error
          }
        );

      default:
        return null;
    }
  }
}
