```typescript
// Beautiful webshell implementation with turn_span_id merging
class WebshellMessageProcessor {
  private turnSpanMerger = new TurnSpanIdMerger();
  private chatHistory: ChatMessage[] = [];
  private eventSource: EventSource | null = null;

  async processSSEStream(responseStream: ReadableStream) {
    const reader = responseStream.getReader();
    let assistantMessage: Partial<AssistantMessage> = {
      role: 'assistant',
      content: '',
      timestamp: Date.now()
    };

    try {
      while (true) {
        const { done, value } = await reader.read();

        if (done) {
          // ✨ Stream complete - finalize message with turn_span_id
          if (assistantMessage.content) {
            const finalMessage = await this.turnSpanMerger.mergeTurnSpanId(
              assistantMessage,
              { type: 'done' }  // Use current turn_span_id
            );
            this.addMessageToHistory(finalMessage);
          }
          break;
        }

        // ✨ Parse SSE event
        const event = this.parseSSEEvent(value);

        // ✨ Process stream chunk with turn_span_id merging
        const processedMessage = await this.turnSpanMerger.processStreamChunk(event);
        if (processedMessage) {
          this.addMessageToHistory(processedMessage);
        }

        // ✨ Accumulate streaming content
        if (event.type === 'data' && event.data) {
          assistantMessage.content += event.data;
        }
      }
    } catch (error) {
      console.error('❌ Stream processing error:', error);

      // ✨ Even on error, merge available turn_span_id for debugging
      const errorMessage = await this.turnSpanMerger.mergeTurnSpanId(
        {
          content: `Stream error: ${error.message}`,
          metadata: { error: true, error_details: error }
        },
        { type: 'error', error: error.message }
      );

      this.addMessageToHistory(errorMessage);
    } finally {
      reader.releaseLock();
    }
  }

  private parseSSEEvent(data: Uint8Array): StreamEvent {
    const text = new TextDecoder().decode(data);
    // ✨ Parse SSE format to extract event data and turn_span_id
    const lines = text.split('\n');
    const event: StreamEvent = { type: 'data' };

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        try {
          const eventData = JSON.parse(line.slice(6));
          Object.assign(event, eventData);
        } catch (e) {
          event.data = line.slice(6);
        }
      }
    }

    return event;
  }

  private addMessageToHistory(message: ChatMessage) {
    this.chatHistory.push(message);
    this.updateUI(message);

    // ✨ Log the beautiful traceability
    if ('turn_span_id' in message && message.turn_span_id) {
      console.log(`✨ Message added with trace ID: ${message.turn_span_id}`);
    }
  }

  private updateUI(message: ChatMessage) {
    // ✨ Update chat UI with beautiful message
    const messageElement = this.createMessageElement(message);
    document.getElementById('chat-container')?.appendChild(messageElement);

    // ✨ Enable traceability UI if turn_span_id present
    if ('turn_span_id' in message && message.turn_span_id) {
      this.enableTraceabilityFeatures(message.turn_span_id);
    }
  }

  private enableTraceabilityFeatures(turnSpanId: string) {
    // ✨ Add "View Trace" button to messages with turn_span_id
    console.log(`🌟 Traceability enabled for span: ${turnSpanId}`);
    // This could enable:
    // - Click-to-view backend logs
    // - Performance metrics display
    // - Error correlation tools
    // - Full interaction timeline
  }
}
