// Turn span ID validation and sanitization
class TurnSpanValidator {
  validateTurnSpanId(turnSpanId: string | undefined): string | undefined {
    if (!turnSpanId) return undefined;

    // ✨ Validate format (UUID-like)
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(turnSpanId)) {
      console.warn(`⚠️  Invalid turn span ID format: ${turnSpanId}`);
      return undefined;
    }

    // ✨ Sanitize to prevent injection
    const sanitized = turnSpanId.replace(/[^0-9a-f\-]/g, '');
    return sanitized === turnSpanId ? turnSpanId : undefined;
  }
}

// Batch processing with turn_span_id merging
class BatchMessageProcessor {
  private merger = new TurnSpanIdMerger();
  private validator = new TurnSpanValidator();

  async processBatch(
    messages: Partial<AssistantMessage>[],
    streamEvents: StreamEvent[]
  ): Promise<AssistantMessage[]> {
    const processedMessages: AssistantMessage[] = [];

    for (let i = 0; i < messages.length; i++) {
      const message = messages[i];
      const event = streamEvents[i] || { type: 'data' };

      // ✨ Validate turn_span_id before merging
      if (event.turn_span_id) {
        event.turn_span_id = this.validator.validateTurnSpanId(event.turn_span_id);
      }

      // ✨ Beautiful merging with validation
      const processedMessage = await this.merger.mergeTurnSpanId(message, event);
      processedMessages.push(processedMessage);

      console.log(`✅ Batch item ${i + 1} processed with turn span ID: ${processedMessage.turn_span_id || 'none'}`);
    }

    return processedMessages;
  }
}
