use serde::{Deserialize, Serialize};
use std::process::Stdio;
use std::time::{Duration, Instant};
use tokio::process::Command;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CommandSpec {
    pub program: String,
    pub args: Vec<String>,
    pub env_vars: std::collections::HashMap<String, String>,
    pub timeout: Option<Duration>,
    pub working_dir: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum SubprocessResult {
    Completed { output: String, exit_code: i32 },
    TimedOut { partial_output: String },
    Crashed { error: String, partial_output: Option<String> },
    Cancelled { reason: String },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum StreamEvent {
    Data(String),
    Progress { percentage: f32, message: String },
    Error(String),
    Done { success: bool, reason: Option<String> },
}

// ✨ The robust subprocess caller with done=true fallback
async fn call_subprocess_with_robust_fallback(
    command: CommandSpec,
    event_sender: EventSender,
) -> Result<SubprocessResult, Error> {
    println!("🔄 Calling subprocess: {} {:?}", command.program, command.args);

    let start_time = Instant::now();

    // ✨ Spawn the subprocess
    let mut child = Command::new(&command.program)
        .args(&command.args)
        .envs(&command.env_vars)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|e| Error::SubprocessSpawnFailed {
            program: command.program.clone(),
            error: e.to_string(),
        })?;

    // ✨ Set up timeout if specified
    let timeout_result = if let Some(timeout) = command.timeout {
        tokio::time::timeout(timeout, process_with_fallback(child, event_sender.clone())).await
    } else {
        Ok(process_with_fallback(child, event_sender.clone()).await)
    };

    match timeout_result {
        Ok(Ok(result)) => {
            println!("✅ Subprocess completed successfully in {:?}", start_time.elapsed());
            Ok(result)
        }
        Ok(Err(e)) => {
            println!("❌ Subprocess failed: {}", e);
            Err(e)
        }
        Err(_) => {
            // ✨ Timeout occurred - ensure done=true fallback
            println!("⏰ Subprocess timed out, emitting done=true fallback");

            event_sender.send(StreamEvent::Error("Subprocess timeout".to_string())).await?;
            event_sender.send(StreamEvent::Done {
                success: false,
                reason: Some("Timeout occurred".to_string()),
            }).await?;

            Ok(SubprocessResult::TimedOut {
                partial_output: "Process timed out".to_string(),
            })
        }
    }
}

// ✨ The core processing logic with comprehensive fallback
async fn process_with_fallback(
    mut child: tokio::process::Child,
    event_sender: EventSender,
) -> Result<SubprocessResult, Error> {
    let mut stdout_buffer = String::new();
    let mut stderr_buffer = String::new();

    // ✨ Capture stdout and stderr
    let stdout_reader = BufReader::new(child.stdout.take().unwrap());
    let stderr_reader = BufReader::new(child.stderr.take().unwrap());

    let mut stdout_lines = stdout_reader.lines();
    let mut stderr_lines = stderr_reader.lines();

    // ✨ Stream output in real-time
    loop {
        tokio::select! {
            // Handle stdout
            stdout_result = stdout_lines.next_line() => {
                match stdout_result {
                    Ok(Some(line)) => {
                        stdout_buffer.push_str(&line);
                        stdout_buffer.push('\n');
                        event_sender.send(StreamEvent::Data(line)).await?;
                    }
                    Ok(None) => break, // EOF
                    Err(e) => {
                        // ✨ Error reading stdout - emit done=true fallback
                        println!("⚠️  Error reading stdout: {}", e);
                        event_sender.send(StreamEvent::Error(e.to_string())).await?;
                        event_sender.send(StreamEvent::Done {
                            success: false,
                            reason: Some(format!("Error reading stdout: {}", e)),
                        }).await?;
                        return Err(Error::SubprocessOutputError(e.to_string()));
                    }
                }
            }

            // Handle stderr
            stderr_result = stderr_lines.next_line() => {
                match stderr_result {
                    Ok(Some(line)) => {
                        stderr_buffer.push_str(&line);
                        stderr_buffer.push('\n');
                        event_sender.send(StreamEvent::Error(line)).await?;
                    }
                    Ok(None) => break, // EOF
                    Err(e) => {
                        // ✨ Error reading stderr - emit done=true fallback
                        println!("⚠️  Error reading stderr: {}", e);
                        event_sender.send(StreamEvent::Error(e.to_string())).await?;
                        event_sender.send(StreamEvent::Done {
                            success: false,
                            reason: Some(format!("Error reading stderr: {}", e)),
                        }).await?;
                        return Err(Error::SubprocessOutputError(e.to_string()));
                    }
                }
            }
        }
    }

    // ✨ Wait for process completion
    match child.wait().await {
        Ok(status) => {
            let exit_code = status.code().unwrap_or(-1);

            if status.success() {
                // ✨ Success - send completion
                event_sender.send(StreamEvent::Done {
                    success: true,
                    reason: None,
                }).await?;

                Ok(SubprocessResult::Completed {
                    output: stdout_buffer,
                    exit_code,
                })
            } else {
                // ✨ Non-zero exit code - still send done=true for proper cleanup
                println!("⚠️  Subprocess exited with code: {}", exit_code);

                event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some(format!("Process exited with code: {}", exit_code)),
                }).await?;

                Ok(SubprocessResult::Crashed {
                    error: format!("Process exited with code: {}", exit_code),
                    partial_output: Some(stdout_buffer),
                })
            }
        }
        Err(e) => {
            // ✨ Process wait failed - CRITICAL: emit done=true fallback
            println!("💥 Failed to wait for subprocess: {}", e);

            event_sender.send(StreamEvent::Error(e.to_string())).await?;
            event_sender.send(StreamEvent::Done {
                success: false,
                reason: Some(format!("Failed to wait for process: {}", e)),
            }).await?;

            Ok(SubprocessResult::Crashed {
                error: e.to_string(),
                partial_output: Some(stdout_buffer),
            })
        }
    }
}
