#### 🧱 Why done=true Fallback is Essential

```rust
// Example showing why done=true fallback is CRITICAL:

// ❌ WITHOUT done=true fallback:
async fn bad_subprocess_call() -> Result<(), Error> {
    let mut child = Command::new("some-program").spawn()?;
    let event_sender = create_event_sender();

    // Process output...
    process_output(&mut child, &event_sender).await?;

    // Wait for completion...
    match child.wait().await {
        Ok(status) => {
            if !status.success() {
                event_sender.send(StreamEvent::Error("Failed".to_string())).await?;
                // ❌ FORGOT to send done=true!
                // Client stream hangs forever waiting for completion!
            }
        }
        Err(e) => {
            event_sender.send(StreamEvent::Error(e.to_string())).await?;
            // ❌ FORGOT to send done=true!
            // Stream hangs forever!
        }
    }

    Ok(()) // Client never knows stream is complete!
}

// ✨ WITH done=true fallback:
async fn good_subprocess_call() -> Result<(), Error> {
    let mut child = Command::new("some-program").spawn()?;
    let event_sender = create_event_sender();

    // Process output...
    if let Err(e) = process_output(&mut child, &event_sender).await {
        event_sender.send(StreamEvent::Error(e.to_string())).await?;
        // ✨ ALWAYS send done=true on error!
        event_sender.send(StreamEvent::Done {
            success: false,
            reason: Some(e.to_string()),
        }).await?;
        return Err(e);
    }

    // Wait for completion...
    match child.wait().await {
        Ok(status) => {
            if status.success() {
                event_sender.send(StreamEvent::Done {
                    success: true,
                    reason: None,
                }).await?;
            } else {
                event_sender.send(StreamEvent::Error("Failed".to_string())).await?;
                // ✨ ALWAYS send done=true!
                event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some("Process failed".to_string()),
                }).await?;
            }
        }
        Err(e) => {
            event_sender.send(StreamEvent::Error(e.to_string())).await?;
            // ✨ ALWAYS send done=true even on wait failure!
            event_sender.send(StreamEvent::Done {
                success: false,
                reason: Some(e.to_string()),
            }).await?;
        }
    }

    Ok(()) // Client receives done=true and knows stream is complete!
}
