// Fallback with retry mechanism
async fn call_subprocess_with_retry_and_fallback(
    command: CommandSpec,
    event_sender: EventSender,
    max_retries: usize,
) -> Result<SubprocessResult, Error> {
    let mut retry_count = 0;

    loop {
        match call_subprocess_with_robust_fallback(command.clone(), event_sender.clone()).await {
            Ok(result) => return Ok(result),
            Err(e) if retry_count < max_retries => {
                retry_count += 1;
                println!("🔄 Retrying subprocess (attempt {}/{})", retry_count, max_retries + 1);

                // ✨ Send retry notification but keep stream alive
                event_sender.send(StreamEvent::Progress {
                    percentage: (retry_count as f32 / (max_retries + 1) as f32) * 100.0,
                    message: format!("Retry attempt {}/{}", retry_count, max_retries),
                }).await?;

                tokio::time::sleep(Duration::from_secs(2_u64.pow(retry_count as u32))).await;
            }
            Err(e) => {
                // ✨ Final failure - ensure done=true is sent
                event_sender.send(StreamEvent::Error(e.to_string())).await?;
                event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some(format!("Failed after {} retries: {}", max_retries, e)),
                }).await?;

                return Err(e);
            }
        }
    }
}

