use std::sync::atomic::{AtomicU32, Ordering};

struct CircuitBreaker {
    failure_count: AtomicU32,
    failure_threshold: u32,
    timeout: Duration,
}

impl CircuitBreaker {
    async fn call_with_circuit_breaker_and_fallback<F, Fut, T>(
        &self,
        operation: F,
        event_sender: EventSender,
    ) -> Result<T, Error>
    where
        F: FnOnce() -> Fut,
        Fut: std::future::Future<Output = Result<T, Error>>,
    {
        if self.is_open() {
            // ✨ Circuit breaker open - send immediate done=true
            event_sender.send(StreamEvent::Error("Circuit breaker open".to_string())).await?;
            event_sender.send(StreamEvent::Done {
                success: false,
                reason: Some("Circuit breaker open - too many recent failures".to_string()),
            }).await?;

            return Err(Error::CircuitBreakerOpen);
        }

        match operation().await {
            Ok(result) => {
                self.reset();
                Ok(result)
            }
            Err(e) => {
                self.record_failure();
                // ✨ Even on circuit breaker error, done=true sent by fallback
                Err(e)
            }
        }
    }
}

// Graceful shutdown handling
async fn handle_graceful_shutdown_with_fallback(
    shutdown_signal: ShutdownSignal,
    mut child: tokio::process::Child,
    event_sender: EventSender,
) -> Result<(), Error> {
    tokio::select! {
        _ = shutdown_signal => {
            println!("🛑 Shutdown signal received, terminating subprocess");

            // ✨ Attempt graceful shutdown
            let _ = child.kill().await;

            // ✨ Wait briefly for cleanup
            if let Ok(Ok(_)) = tokio::time::timeout(Duration::from_secs(5), child.wait()).await {
                event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some("Process terminated due to shutdown".to_string()),
                }).await?;
            } else {
                // ✨ Force kill if graceful shutdown fails
                event_sender.send(StreamEvent::Error("Force killing process".to_string())).await?;
                event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some("Process force killed during shutdown".to_string()),
                }).await?;
            }
        }
        result = child.wait() => {
            match result {
                Ok(status) => {
                    event_sender.send(StreamEvent::Done {
                        success: status.success(),
                        reason: if status.success() { 
                            None 
                        } else { 
                            Some("Process completed with error".to_string()) 
                        },
                    }).await?;
                }
                Err(e) => {
                    event_sender.send(StreamEvent::Error(e.to_string())).await?;
                    event_sender.send(StreamEvent::Done {
                        success: false,
                        reason: Some(e.to_string()),
                    }).await?;
                }
            }
        }
    }

    Ok(())
}
