// 1. Stream lifecycle manager
struct StreamLifecycleManager {
    event_sender: EventSender,
    is_completed: AtomicBool,
}

impl StreamLifecycleManager {
    async fn ensure_completion(&self, result: StreamCompletionResult) -> Result<(), Error> {
        // ✨ Prevent double completion
        if self.is_completed.compare_exchange(
            false, true,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ).is_err() {
            return Ok(()); // Already completed
        }

        // ✨ Always send done event
        match result {
            StreamCompletionResult::Success { data } => {
                if let Some(output) = data {
                    self.event_sender.send(StreamEvent::Data(output)).await?;
                }
                self.event_sender.send(StreamEvent::Done {
                    success: true,
                    reason: None,
                }).await?;
            }
            StreamCompletionResult::Error { error, partial_output } => {
                if let Some(output) = partial_output {
                    self.event_sender.send(StreamEvent::Data(output)).await?;
                }
                self.event_sender.send(StreamEvent::Error(error.clone())).await?;
                self.event_sender.send(StreamEvent::Done {
                    success: false,
                    reason: Some(error),
                }).await?;
            }
        }

        Ok(())
    }
}

