        };

        // ✨ 7. Record beautiful metrics
        let duration = start_time.elapsed();
        self.record_write_metrics(duration, span_json.len(), compressed).await?;

        // ✨ 8. Log successful write
        println!("💾 Beautifully wrote span {} to disk: {}", 
