    // ✨ Beautiful span validation
    async fn validate_span(&self, span: &TurnSpan) -> Result<(), Error> {
        // ✨ Check required fields
        if span.span_id.is_empty() {
            return Err(Error::InvalidSpan("span_id cannot be empty".to_string()));
        }

        if span.operation_name.is_empty() {
            return Err(Error::InvalidSpan("operation_name cannot be empty".to_string()));
        }

        // ✨ Validate span status consistency
        if matches!(span.status, SpanStatus::InProgress) && span.end_time.is_some() {
            return Err(Error::InvalidSpan("In-progress span cannot have end_time".to_string()));
        }

        // ✨ Validate timestamp consistency
        if let Some(end_time) = span.end_time {
            if end_time < span.start_time {
                return Err(Error::InvalidSpan("end_time cannot be before start_time".to_string()));
            }
        }

        Ok(())
    }

    // ✨ Beautiful JSON serialization with pretty formatting
    async fn serialize_span(&self, span: &TurnSpan) -> Result<String, Error> {
        // ✨ Add serialization timestamp for audit trail
        let mut span_with_audit = span.clone();
        if let Some(obj) = span_with_audit.metadata.as_object_mut() {
            obj.insert("serialized_at".to_string(), 
                      serde_json::Value::String(chrono::Utc::now().to_rfc3339()));
        }

        // ✨ Pretty-printed JSON for human readability
        let json = serde_json::to_string_pretty(&span_with_audit)
            .map_err(|e| Error::SerializationError(e.to_string()))?;

        Ok(json)
    }

