    async fn generate_filename(&self, span: &TurnSpan) -> Result<String, Error> {
        let timestamp = span.created_at.format("%Y%m%d_%H%M%S_%3f");
        let service_name = span.service_name.replace("/", "_");
        let operation_name = span.operation_name.replace("/", "_");

        // ✨ Organize by date for easy browsing
        let date_path = span.created_at.format("%Y/%m/%d");
        let filename = format!(
            "{}/{}/span_{}_{}_{}_{}.json",
            date_path,
            service_name,
            span.span_id,
            operation_name,
            timestamp,
            uuid::Uuid::new_v4().to_string()[..8].to_string() // Short UUID for uniqueness
        );

        Ok(filename)
