    async fn ensure_storage_directory(&self) -> Result<(), Error> {
        fs::create_dir_all(&self.storage_path).await
            .map_err(|e| Error::StorageError(format!("Failed to create storage directory: {}", e)))
    }

    // ✨ Atomic write to prevent corruption
    async fn atomic_write(&self, path: &PathBuf, data: &str) -> Result<(), Error> {
        // ✨ Create parent directories
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent).await
                .map_err(|e| Error::StorageError(format!("Failed to create parent directories: {}", e)))?;
        }

        // ✨ Write to temporary file first
        let temp_path = path.with_extension("tmp");
        fs::write(&temp_path, data).await
            .map_err(|e| Error::StorageError(format!("Failed to write temporary file: {}", e)))?;

        // ✨ Atomically move to final location
        fs::rename(&temp_path, path).await
            .map_err(|e| Error::StorageError(format!("Failed to atomically move file: {}", e)))?;

        Ok(())
    }

