        // ... compression logic ...

        // ✨ Write compressed file
        fs::write(&compressed_path, compressed_data).await
            .map_err(|e| Error::StorageError(format!("Failed to write compressed file: {}", e)))?;

        // ✨ Remove original file to save space
        fs::remove_file(path).await
            .map_err(|e| Error::StorageError(format!("Failed to remove original file: {}", e)))?;

        println!("🗜️  Compressed span file: {}", compressed_path.display());
        Ok(true)
    }

