// Span rotation and cleanup
impl SpanWriter {
    pub async fn cleanup_old_spans(&self) -> Result<CleanupResult, Error> {
        let cutoff_date = chrono::Utc::now() - chrono::Duration::days(self.retention_days);
        let mut deleted_count = 0;
        let mut deleted_size = 0u64;

        println!("🧹 Cleaning up spans older than {}", cutoff_date);

        // ✨ Walk through storage directory
        let mut dir_queue = vec![self.storage_path.clone()];

        while let Some(current_dir) = dir_queue.pop() {
            let mut entries = fs::read_dir(&current_dir).await
                .map_err(|e| Error::StorageError(format!("Failed to read directory: {}", e)))?;

            while let Some(entry) = entries.next_entry().await
                .map_err(|e| Error::StorageError(format!("Failed to read directory entry: {}", e)))? {

                let path = entry.path();
                let metadata = entry.metadata().await
                    .map_err(|e| Error::StorageError(format!("Failed to get metadata: {}", e)))?;

                if metadata.is_dir() {
                    dir_queue.push(path);
                } else if metadata.is_file() {
                    // ✨ Check if file is old enough to delete
                    let modified_time = metadata.modified()
                        .map_err(|e| Error::StorageError(format!("Failed to get modified time: {}", e)))?
                        .into();

                    let modified_date: chrono::DateTime<chrono::Utc> = modified_time.into();

                    if modified_date < cutoff_date {
                        let file_size = metadata.len();
                        fs::remove_file(&path).await
                            .map_err(|e| Error::StorageError(format!("Failed to delete file: {}", e)))?;

                        deleted_count += 1;
                        deleted_size += file_size;

                        println!("🗑️  Deleted old span file: {}", path.display());
                    }
                }
            }
        }

        println!("✅ Cleanup completed - deleted {} files ({:.2} MB)",
                 deleted_count, deleted_size as f64 / 1024.0 / 1024.0);

        Ok(CleanupResult {
            deleted_files: deleted_count,
            deleted_bytes: deleted_size,
            cleanup_duration: Instant::now().duration_since(Instant::now()),
        })
    }
}
