impl SpanWriter {
    pub async fn query_spans(&self, query: SpanQuery) -> Result<Vec<TurnSpan>, Error> {
        let mut matching_spans = Vec::new();

        // ✨ Walk through organized directory structure
        let date_range = generate_date_range(query.start_date, query.end_date);

        for date in date_range {
            let date_path = self.storage_path.join(date.format("%Y/%m/%d").to_string());

            if date_path.exists() {
                // ✨ Read spans from date directory
                let spans = self.read_spans_from_directory(&date_path, &query).await?;
                matching_spans.extend(spans);
            }
        }

        // ✨ Sort by timestamp
        matching_spans.sort_by(|a, b| a.created_at.cmp(&b.created_at));

        println!("🔍 Query returned {} matching spans", matching_spans.len());
        Ok(matching_spans)
    }

    async fn read_spans_from_directory(
        &self,
        dir_path: &PathBuf,
        query: &SpanQuery,
    ) -> Result<Vec<TurnSpan>, Error> {
        let mut spans = Vec::new();
        let mut entries = fs::read_dir(dir_path).await
            .map_err(|e| Error::StorageError(format!("Failed to read directory: {}", e)))?;

        while let Some(entry) = entries.next_entry().await
            .map_err(|e| Error::StorageError(format!("Failed to read entry: {}", e)))? {

            let path = entry.path();
            if path.extension().and_then(|ext| ext.to_str()) == Some("json") {
                // ✨ Read and parse span file
                let span = self.read_span_file(&path).await?;

                // ✨ Apply query filters
                if self.span_matches_query(&span, query) {
                    spans.push(span);
                }
            }
        }

        Ok(spans)
    }

    async fn read_span_file(&self, path: &PathBuf) -> Result<TurnSpan, Error> {
        let content = fs::read_to_string(path).await
            .map_err(|e| Error::StorageError(format!("Failed to read span file: {}", e)))?;

        let span: TurnSpan = serde_json::from_str(&content)
            .map_err(|e| Error::SerializationError(format!("Failed to parse span: {}", e)))?;

        Ok(span)
    }

    fn span_matches_query(&self, span: &TurnSpan, query: &SpanQuery) -> bool {
        // ✨ Apply various query filters
        if let Some(ref service) = query.service_name {
            if span.service_name != *service {
                return false;
            }
        }

        if let Some(ref operation) = query.operation_name {
            if span.operation_name != *operation {
                return false;
            }
        }

        if let Some(ref status) = query.status {
            if &span.status != status {
                return false;
            }
        }

        if let Some(min_duration) = query.min_duration {
            if let Some(duration) = span.duration {
                if duration < min_duration {
                    return false;
                }
            }
        }

        true
    }
}

