// 2. Asynchronous background writing
pub struct AsyncSpanWriter {
    writer: SpanWriter,
    write_queue: Arc<Mutex<Vec<TurnSpan>>>,
    background_task: Option<tokio::task::JoinHandle<()>>,
}

impl AsyncSpanWriter {
    pub fn new(writer: SpanWriter) -> Self {
        let write_queue = Arc::new(Mutex::new(Vec::new()));
        let queue_clone = Arc::clone(&write_queue);
        let writer_clone = writer.clone();

        // ✨ Spawn background writing task
        let background_task = tokio::spawn(async move {
            loop {
                tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;

                let spans_to_write = {
                    let mut queue = queue_clone.lock().await;
                    if queue.is_empty() {
                        continue;
                    }
                    std::mem::take(&mut *queue)
                };

                // ✨ Batch write spans
                if let Err(e) = writer_clone.write_spans_batch(&spans_to_write).await {
                    println!("❌ Background write failed: {}", e);
                }
            }
        });

        Self {
            writer,
            write_queue,
            background_task: Some(background_task),
        }
    }

    pub async fn queue_span_for_writing(&self, span: TurnSpan) {
        let mut queue = self.write_queue.lock().await;
        queue.push(span);
        println!("📨 Queued span {} for background writing", span.span_id);
    }
}

// 3. Span validation and sanitization
impl SpanWriter {
    async fn sanitize_span(&self, span: &mut TurnSpan) -> Result<(), Error> {
        // ✨ Sanitize span ID
        span.span_id = span.span_id.chars()
            .filter(|c| c.is_alphanumeric() || *c == '-' || *c == '_')
            .collect();

        // ✨ Truncate very long fields
        if span.operation_name.len() > 255 {
            span.operation_name = span.operation_name[..255].to_string();
        }

        // ✨ Validate and clean metadata
        if let Some(obj) = span.metadata.as_object_mut() {
            obj.retain(|key, value| {
                // Remove invalid keys
                let valid_key = key.chars().all(|c| c.is_alphanumeric() || c == '_' || c == '-');
                // Remove very large values
                let valid_value = serde_json::to_string(value).unwrap_or_default().len() < 10000;
                valid_key && valid_value
            });
        }

        Ok(())
    }
}

