const getSpanTypeIcon = (type: TurnSpanType): string => {
  switch (type) {
    case 'user_message': return '👤';
    case 'assistant_response': return '🤖';
    case 'tool_call': return '🔧';
    case 'system_event': return '⚙️';
    case 'error_recovery': return '🛡️';
    default: return '❓';
  }
};

const getStatusIcon = (status: TurnSpan['status']): string => {
  switch (status) {
    case 'completed': return '✅';
    case 'failed': return '❌';
    case 'active': return '⏳';
    default: return '⚪';
  }
};

const formatSpanType = (type: TurnSpanType): string => {
  return type
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase());
};

const truncateId = (id: string): string => {
  if (id.length <= 12) return id;
  return `${id.substring(0, 8)}...${id.substring(id.length - 4)}`;
};

const formatDuration = (duration: number | undefined): string => {
  if (duration === undefined) return 'N/A';
  if (duration < 1000) return `${duration}ms`;
  return `${(duration / 1000).toFixed(2)}s`;
};

const formatTimestamp = (timestamp: string): string => {
  return new Date(timestamp).toLocaleTimeString([], { 
    hour: '2-digit', 
    minute: '2-digit', 
    second: '2-digit' 
  });
};
