// Enhanced TurnLineageStrip with filtering and search
interface EnhancedTurnLineageStripProps extends TurnLineageStripProps {
  filterByType?: TurnSpanType[];
  searchTerm?: string;
  onSpanSelect?: (span: TurnSpan) => void;
  showTiming?: boolean;
  showStatus?: boolean;
}

const EnhancedTurnLineageStrip: React.FC<EnhancedTurnLineageStripProps> = ({
  turnSpanId,
  maxDepth = 5,
  showMetadata = false,
  filterByType = [],
  searchTerm = '',
  onSpanSelect,
  showTiming = true,
  showStatus = true
}) => {
  const [lineage, setLineage] = useState<TurnSpan[]>([]);
  const [filteredLineage, setFilteredLineage] = useState<TurnSpan[]>([]);
  const [loading, setLoading] = useState(true);
  const [groupBy, setGroupBy] = useState<'none' | 'type' | 'status'>('none');

  useEffect(() => {
    // ✨ Fetch and filter lineage
    const loadAndFilterLineage = async () => {
      if (!turnSpanId) return;

      try {
        setLoading(true);
        const fullLineage = await fetchTurnLineage(turnSpanId, maxDepth);
        setLineage(fullLineage);

        // ✨ Apply filters
        let filtered = fullLineage;

        if (filterByType.length > 0) {
          filtered = filtered.filter(span => 
            filterByType.includes(span.type)
          );
        }

        if (searchTerm) {
          filtered = filtered.filter(span =>
            span.id.includes(searchTerm) ||
            span.type.includes(searchTerm) ||
            JSON.stringify(span.metadata).includes(searchTerm)
          );
        }

        setFilteredLineage(filtered);
      } finally {
        setLoading(false);
      }
    };

    loadAndFilterLineage();
  }, [turnSpanId, maxDepth, filterByType, searchTerm]);

  // ✨ Beautiful grouped visualization
  const renderGroupedLineage = () => {
    if (groupBy === 'none') {
      return filteredLineage.map((span, index) => (
        <TurnSpanNode
          key={span.id}
          span={span}
          isCurrent={span.id === turnSpanId}
          isRoot={index === 0}
          depth={index}
          showMetadata={showMetadata}
          onClick={() => onSpanSelect?.(span)}
        />
      ));
    }

    const grouped = groupByProperty(filteredLineage, groupBy);

    return Object.entries(grouped).map(([groupKey, spans]) => (
      <div key={groupKey} className="lineage-group">
        <h4 className="group-header">
          {groupBy === 'type' ? getSpanTypeIcon(groupKey as TurnSpanType) : ''}
          {groupBy === 'status' ? getStatusIcon(groupKey as any) : ''}
          {formatGroupKey(groupKey, groupBy)}
          <span className="group-count">({spans.length})</span>
        </h4>
        <div className="group-spans">
          {spans.map(span => (
            <TurnSpanNode
              key={span.id}
              span={span}
              isCurrent={span.id === turnSpanId}
              isRoot={false}
              depth={calculateSpanDepth(span, filteredLineage)}
              showMetadata={showMetadata}
              onClick={() => onSpanSelect?.(span)}
            />
          ))}
        </div>
      </div>
    ));
  };

  return (
    <div className="enhanced-turn-lineage-strip">
      {/* ✨ Beautiful filtering controls */}
      <div className="lineage-controls">
        <div className="search-container">
          <input
            type="text"
            placeholder="🔍 Search spans..."
            value={searchTerm}
            onChange={(e) => {/* update search */}}
            className="search-input"
            aria-label="Search turn spans"
          />
        </div>

        <div className="filter-container">
          <select 
            onChange={(e) => {/* update filter */}}
            aria-label="Filter by span type"
          >
            <option value="">All Types</option>
            {Object.values(TurnSpanType).map(type => (
              <option key={type} value={type}>{formatSpanType(type)}</option>
              ))}
          </select>

          <select 
            value={groupBy}
            onChange={(e) => setGroupBy(e.target.value as any)}
            aria-label="Group by"
          >
            <option value="none">No Grouping</option>
            <option value="type">Group by Type</option>
            <option value="status">Group by Status</option>
          </select>
        </div>
      </div>

      {/* ✨ The beautiful visualization */}
      <div className="lineage-visualization">
        {renderGroupedLineage()}
      </div>
    </div>
  );
};

// Utility functions
const groupByProperty = (array: any[], property: string) => {
  return array.reduce((groups, item) => {
    const groupKey = item[property];
    if (!groups[groupKey]) {
      groups[groupKey] = [];
    }
    groups[groupKey].push(item);
    return groups;
  }, {} as Record<string, any[]>);
};

const formatGroupKey = (key: string, groupBy: string): string => {
  if (groupBy === 'type') {
    return formatSpanType(key as TurnSpanType);
  }
  if (groupBy === 'status') {
    return key.charAt(0).toUpperCase() + key.slice(1);
  }
  return key;
};
