```typescript
// Beautiful TypeScript interfaces for traceable messages
interface SSEEvent {
  type: 'first' | 'data' | 'progress' | 'done' | 'error';
  turn_span_id?: string;        // ✨ The crucial tracing identifier!
  data?: string;
  progress?: number;
  error?: string;
  metadata?: Record<string, any>;
}

interface AssistantMessage {
  role: 'assistant';
  content: string;
  turn_span_id?: string;        // ✨ Merged for tracing
  timestamp: number;
  stream_metadata?: StreamMetadata;
}

interface StreamMetadata {
  start_time: number;
  end_time?: number;
  total_chunks: number;
  processing_duration?: number;
}

// ✨ The beautiful merging service
class TurnSpanIdMergeService {
  private currentTurnSpanId: string | null = null;
  private messageBuffer: string[] = [];
  private chunkCount: number = 0;
  private startTime: number = 0;

  async processStreamEvent(event: SSEEvent): Promise<AssistantMessage | null> {
    // ✨ Handle first chunk - CRITICAL for turn_span_id extraction!
    if (event.type === 'first') {
      this.handleFirstChunk(event);
      return null; // First chunk doesn't contain message data
    }

    // ✨ Handle data chunks - accumulate content
    if (event.type === 'data' && event.data) {
      this.handleDataChunk(event.data);
    }

    // ✨ Handle completion - merge turn_span_id onto final message
    if (event.type === 'done') {
      return this.createFinalMessage();
    }

    // ✨ Handle errors - still merge available turn_span_id for debugging
    if (event.type === 'error') {
      return this.createErrorMessage(event.error || 'Unknown error');
    }

    return null;
  }

  private handleFirstChunk(event: SSEEvent) {
    // ✨ THIS IS WHERE THE MAGIC HAPPENS!
    if (event.turn_span_id) {
      this.currentTurnSpanId = event.turn_span_id;
      this.startTime = Date.now();
      console.log(`✨ Turn span ID captured: ${this.currentTurnSpanId}`);
    }
  }

  private handleDataChunk(data: string) {
    this.messageBuffer.push(data);
    this.chunkCount++;
  }

  private createFinalMessage(): AssistantMessage {
    const content = this.messageBuffer.join('');

    const message: AssistantMessage = {
      role: 'assistant',
      content,
      turn_span_id: this.currentTurnSpanId || undefined,  // ✨ THE MERGE!
      timestamp: Date.now(),
      stream_metadata: {
        start_time: this.startTime,
        end_time: Date.now(),
        total_chunks: this.chunkCount,
        processing_duration: Date.now() - this.startTime
      }
    };

    // ✨ Reset for next message
    this.reset();

    console.log(`🌟 Message created with turn span ID: ${message.turn_span_id || 'none'}`);
    return message;
  }

  private createErrorMessage(error: string): AssistantMessage {
    const message: AssistantMessage = {
      role: 'assistant',
      content: `Error: ${error}`,
      turn_span_id: this.currentTurnSpanId || undefined,  // ✨ Still merge for debugging!
      timestamp: Date.now(),
      stream_metadata: {
        start_time: this.startTime,
        end_time: Date.now(),
        total_chunks: this.chunkCount,
        processing_duration: Date.now() - this.startTime
      }
    };

    this.reset();
    return message;
  }

  private reset() {
    this.currentTurnSpanId = null;
    this.messageBuffer = [];
    this.chunkCount = 0;
    this.startTime = 0;
  }
}
