// Beautiful webshell implementation with turn_span_id merging
class WebshellMessageProcessor {
  private mergeService = new TurnSpanIdMergeService();
  private chatHistory: any[] = [];

  async processAssistantResponse(responseStream: ReadableStream) {
    const reader = responseStream.getReader();

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        // ✨ Parse SSE event
        const event = this.parseSSEEvent(value);

        // ✨ Process with beautiful merging
        const processedMessage = await this.mergeService.processStreamEvent(event);

        // ✨ Add traceable message to chat
        if (processedMessage) {
          this.addTraceableMessage(processedMessage);
        }
      }
    } catch (error) {
      console.error('❌ Stream processing error:', error);

      // ✨ Even on error, merge available turn_span_id for debugging
      const errorMessage = await this.mergeService.processStreamEvent({
        type: 'error',
        error: error.message,
        turn_span_id: this.mergeService['currentTurnSpanId'] || undefined
      });

      if (errorMessage) {
        this.addTraceableMessage(errorMessage);
      }
    } finally {
      reader.releaseLock();
    }
  }

  private parseSSEEvent(data: Uint8Array): SSEEvent {
    const text = new TextDecoder().decode(data);
    const lines = text.split('\n');

    // ✨ Parse SSE format to extract event data
    const event: SSEEvent = { type: 'data' };

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        try {
          const eventData = JSON.parse(line.slice(6));
          Object.assign(event, eventData);
        } catch (e) {
          event.data = line.slice(6);
        }
      }
    }

    return event;
  }

  private addTraceableMessage(message: AssistantMessage) {
    // ✨ Add to chat history
    this.chatHistory.push(message);

    // ✨ Update UI with beautiful message
    this.updateChatUI(message);

    // ✨ Enable traceability features if turn_span_id present
