// 3. Merging with circuit breaker
class CircuitBreakerMerger {
  private failureCount = 0;
  private readonly failureThreshold = 5;
  private readonly timeout = 60000; // 1 minute
  private lastFailureTime: number | null = null;

  async mergeWithCircuitBreaker(
    message: Partial<AssistantMessage>,
    event: SSEEvent
  ): Promise<AssistantMessage> {
    // ✨ Check circuit breaker state
    if (this.isCircuitOpen()) {
      console.log('⚠️  Circuit breaker open - using fallback merge');
      return this.fallbackMerge(message, event);
    }

    try {
      const merger = new TurnSpanIdMergeService();
      const result = await merger.processStreamEvent(event);

      if (result) {
        // ✨ Reset failure count on success
        this.failureCount = 0;
        this.lastFailureTime = null;
        return result;
      }

      throw new Error('No message created');
    } catch (error) {
      // ✨ Record failure
      this.failureCount++;
      this.lastFailureTime = Date.now();

      console.error(`❌ Merge failed (${this.failureCount}/${this.failureThreshold}):`, error);

      if (this.failureCount >= this.failureThreshold) {
        console.log('🚨 Circuit breaker tripped!');
      }

      throw error;
    }
  }

  private isCircuitOpen(): boolean {
    if (this.failureCount < this.failureThreshold) {
      return false;
    }

    // ✨ Check if timeout has elapsed
    if (this.lastFailureTime && 
        Date.now() - this.lastFailureTime > this.timeout) {
      // ✨ Half-open state - allow one test
      console.log('🔄 Circuit breaker half-open - testing...');
      return false;
    }

    return true;
  }

  private fallbackMerge(
    message: Partial<AssistantMessage>,
    event: SSEEvent
  ): AssistantMessage {
    return {
      role: 'assistant',
      content: message.content || event.data || '',
      timestamp: message.timestamp || Date.now(),
      stream_metadata: {
        circuit_breaker_triggered: true,
        original_error: 'Circuit breaker active',
        merge_performed_without_turn_span: true,
        event_type: event.type
      }
    };
  }
}

