// ✨ Atomic write for data integrity
async fn atomic_write(file_path: &str, content: &str) -> Result<(), Error> {
    let temp_path = format!("{}.tmp", file_path);

    // ✨ Write to temporary file first
    fs::write(&temp_path, content).await
        .map_err(|e| Error::FileWriteError(e.to_string()))?;

    // ✨ Atomically move to final location
    fs::rename(&temp_path, file_path).await
        .map_err(|e| Error::FileMoveError(e.to_string()))?;

    Ok(())
}

// ✨ Symlink creation for easy querying
async fn create_symlink(target: &str, link_path: &str) -> Result<(), Error> {
    #[cfg(unix)]
    {
        use std::os::unix::fs::symlink;
        tokio::task::spawn_blocking(move || {
            let _ = std::fs::remove_file(link_path);
            symlink(target, link_path)
        }).await??;
    }

    #[cfg(windows)]
    {
        use std::os::windows::fs::symlink_file;
        tokio::task::spawn_blocking(move || {
            let _ = std::fs::remove_file(link_path);
            symlink_file(target, link_path)
        }).await??;
    }

    Ok(())
}
