        .map_err(|e| Error::TimeError(e.to_string()))?
        .as_secs();

    let date_str = format!("{}", timestamp / 86400); // Days since epoch
    let hour_str = format!("{}", (timestamp % 86400) / 3600); // Hour of day

    // ✨ Create time-based directory structure
