        let span_file = format!("/var/ayin/spans/{}.json", span.span_id);
        create_symlink(&span_file, &effect_symlink).await?;

        // ✨ Also index the reverse relationship
        let reverse_dir = format!("/var/ayin/index/causality_reverse/{}", span.span_id);
        fs::create_dir_all(&reverse_dir).await?;
        let cause_symlink = format!("{}/{}.json", reverse_dir, link.cause_span_id);
        let cause_file = format!("/var/ayin/spans/{}.json", link.cause_span_id);
        create_symlink(&cause_file, &cause_symlink).await?;
    }

