async fn update_performance_index(span: &TurnSpan) -> Result<(), Error> {
    if let Some(duration) = span.duration {
        // ✨ Bucket durations for performance analysis
        let bucket = match duration {
            d if d < 1_000_000 => "0-1ms",           // < 1ms
            d if d < 10_000_000 => "1-10ms",         // 1-10ms
            d if d < 100_000_000 => "10-100ms",      // 10-100ms
