// Error scenario with persistent span analysis
async fn analyze_error_with_persistent_spans(error_span_id: &str) -> Result<ErrorAnalysis, Error> {
    // ✨ Load span from disk
    let span_file = format!("/var/ayin/spans/{}.json", error_span_id);
    let span_content = fs::read_to_string(&span_file).await?;
    let span: TurnSpan = serde_json::from_str(&span_content)?;

    // ✨ Analyze error context
    let error_analysis = ErrorAnalysis {
        span_id: span.span_id.clone(),
        operation: span.operation_name.clone(),
        service: span.service_name.clone(),
        error_message: match &span.status {
            SpanStatus::Error { message } => message.clone(),
            _ => "Unknown error".to_string(),
        },
        timestamp: span.start_time,
        duration: span.duration.unwrap_or(0),
        user_id: span.user_id.clone(),
        session_id: span.session_id.clone(),
        metadata: span.metadata.clone(),
    };

    // ✨ Find causality relationships
    let causality_file = format!("/var/ayin/index/causality_reverse/{}.json", error_span_id);
    if Path::new(&causality_file).exists() {
        let cause_span_id = fs::read_link(&causality_file)
            .await?
            .file_stem()
            .unwrap()
            .to_str()
            .unwrap()
            .to_string();

        error_analysis.contributing_causes.push(Cause {
            span_id: cause_span_id.clone(),
            relationship: "causal_predecessor".to_string(),
        });

        // ✨ Recursively analyze cause spans
        let cause_analysis = analyze_error_with_persistent_spans(&cause_span_id).await?;
        error_analysis.root_causes.extend(cause_analysis.root_causes);
    }

    // ✨ Find related spans in same trace
    let trace_dir = format!("/var/ayin/spans/traces/{}/", span.trace_id);
    let mut trace_spans = Vec::new();

    let mut entries = fs::read_dir(&trace_dir).await?;
    while let Some(entry) = entries.next_entry().await? {
        let span_id = entry.file_name().to_str().unwrap().replace(".json", "");
        if span_id != error_span_id {
            trace_spans.push(span_id);
        }
    }

    error_analysis.related_spans = trace_spans;

    Ok(error_analysis)
}

