// 1. Asynchronous span writing with batching
struct SpanWriter {
    batch: Vec<TurnSpan>,
    batch_size: usize,
    write_queue: tokio::sync::mpsc::UnboundedSender<Vec<TurnSpan>>,
}

impl SpanWriter {
    async fn write_span(&mut self, span: TurnSpan) -> Result<(), Error> {
        self.batch.push(span);

        if self.batch.len() >= self.batch_size {
            let batch = std::mem::take(&mut self.batch);
            self.write_queue.send(batch).map_err(|_| Error::WriteQueueFull)?;
        }

        Ok(())
    }
}

// 2. Span validation before persistence
async fn validate_span_before_writing(span: &TurnSpan) -> Result<(), Error> {
    // ✨ Validate required fields
    if span.span_id.is_empty() {
        return Err(Error::InvalidSpan("Missing span_id".to_string()));
    }

    if span.trace_id.is_empty() {
        return Err(Error::InvalidSpan("Missing trace_id".to_string()));
    }

    if span.operation_name.is_empty() {
        return Err(Error::InvalidSpan("Missing operation_name".to_string()));
    }

    // ✨ Validate timestamp consistency
    if let Some(end_time) = span.end_time {
        if end_time < span.start_time {
            return Err(Error::InvalidSpan("End time before start time".to_string()));
        }
    }

    // ✨ Validate causality links
    for link in &span.causality_links {
        if link.cause_span_id.is_empty() || link.effect_span_id.is_empty() {
            return Err(Error::InvalidSpan("Invalid causality link".to_string()));
        }
    }

    Ok(())
}

// 3. Span encryption for sensitive data
async fn write_encrypted_span_to_disk(span: TurnSpan, encryption_key: &str) -> Result<(), Error> {
    // ✨ Encrypt sensitive fields
    let mut encrypted_span = span.clone();

    if let Some(metadata) = encrypted_span.metadata.as_object_mut() {
        for (key, value) in metadata.iter_mut() {
            if key.contains("sensitive") || key.contains("secret") {
                let encrypted_value = encrypt_data(value.to_string(), encryption_key)?;
                *value = serde_json::Value::String(encrypted_value);
            }
        }
    }

    // ✨ Write encrypted span
    write_span_to_disk(encrypted_span).await?;

    Ok(())
}

