// ✨ The beautiful deeplink router
class AYINDeeplinkRouter {
  async handleDeeplink(url: string): Promise<void> {
    try {
      const params = this.parseDeeplink(url);
      console.log(`✨ Handling AYIN deeplink: ${params.view} view for ${params.spanId}`);

      // ✨ Route to appropriate view based on 'view' parameter
      switch (params.view) {
        case 'trace':
          await this.showTraceView(params);
          break;
        case 'lineage':
          await this.showLineageView(params);
          break;
        case 'metrics':
          await this.showMetricsView(params);
          break;
        case 'logs':
          await this.showLogsView(params);
          break;
        case 'error':
          await this.showErrorView(params);
          break;
        case 'debug':
          await this.showDebugView(params);
          break;
        case 'compare':
          await this.showCompareView(params);
          break;
        case 'session':
          await this.showSessionView(params);
          break;
        case 'user':
          await this.showUserView(params);
          break;
        case 'service':
          await this.showServiceView(params);
          break;
        default:
          throw new Error(`Unknown view type: ${params.view}`);
      }

      // ✨ Track successful navigation
      this.trackViewNavigation(params);

    } catch (error) {
      console.error(`❌ AYIN deeplink handling failed:`, error);
      await this.showDeeplinkError(error as Error);
    }
  }

  private parseDeeplink(url: string): AYINDeeplinkParams {
    const urlObj = new URL(url, window.location.origin);
    const params = new URLSearchParams(urlObj.search);

    return {
      spanId: params.get('spanId') || this.generateDefaultSpanId(),
      traceId: params.get('traceId') || undefined,
      sessionId: params.get('sessionId') || undefined,
      view: (params.get('view') as AYINViewType) || 'trace',
      focus: params.get('focus') || undefined,
      timeRange: this.parseTimeRange(params.get('timeRange')),
      filters: this.parseFilters(params.get('filters')),
      tab: params.get('tab') || undefined,
      expand: params.get('expand')?.split(',') || undefined,
      source: params.get('source') || 'unknown',
      returnTo: params.get('returnTo') || undefined,
    };
  }

  private async showTraceView(params: AYINDeeplinkParams): Promise<void> {
    console.log(`🌟 Showing trace view for span: ${params.spanId}`);

    // ✨ Load trace data
    const traceData = await this.loadTraceData(params.spanId);

    // ✨ Render beautiful trace timeline
    const traceView = new TraceTimelineView({
      target: document.getElementById('ayin-view-container')!,
      props: {
        traceData,
        focusedSpan: params.focus,
        timeRange: params.timeRange,
        activeTab: params.tab || 'timeline',
        expandedSections: params.expand || [],
      }
    });

    // ✨ Enable beautiful interactions
    this.enableTraceInteractions(traceView, params);
  }

  private async showLineageView(params: AYINDeeplinkParams): Promise<void> {
