// Deeplink validation and sanitization
class AYINDeeplinkValidator {
  validateDeeplink(params: AYINDeeplinkParams): ValidationResult {
    const errors: string[] = [];

    // ✨ Validate required parameters
    if (!params.spanId) {
      errors.push('Missing required parameter: spanId');
    }

    // ✨ Validate view type
    const validViews: AYINViewType[] = [
      'trace', 'lineage', 'metrics', 'logs', 'error',
      'debug', 'compare', 'session', 'user', 'service'
    ];

    if (!validViews.includes(params.view)) {
      errors.push(`Invalid view type: ${params.view}`);
    }

    // ✨ Validate span ID format
    if (params.spanId && !this.isValidSpanId(params.spanId)) {
      errors.push(`Invalid span ID format: ${params.spanId}`);
    }

    // ✨ Validate time range
    if (params.timeRange && !this.isValidTimeRange(params.timeRange)) {
      errors.push('Invalid time range');
    }

    return {
      isValid: errors.length === 0,
      errors,
      sanitizedParams: this.sanitizeParams(params)
    };
  }

  private sanitizeParams(params: AYINDeeplinkParams): AYINDeeplinkParams {
    return {
      ...params,
      spanId: params.spanId?.replace(/[^a-zA-Z0-9\-]/g, '') || '',
      view: this.sanitizeViewType(params.view),
      filters: this.sanitizeFilters(params.filters),
    };
  }
}

// Deeplink history and navigation
class AYINDeeplinkHistory {
  private history: AYINDeeplinkParams[] = [];
  private currentIndex: number = -1;

  push(params: AYINDeeplinkParams): void {
    // ✨ Remove forward history when pushing new entry
    this.history = this.history.slice(0, this.currentIndex + 1);
    this.history.push(params);
    this.currentIndex = this.history.length - 1;

    console.log(`🧭 Deeplink history: ${this.history.length} entries`);
  }

  canGoBack(): boolean {
    return this.currentIndex > 0;
  }

  canGoForward(): boolean {
    return this.currentIndex < this.history.length - 1;
  }

  goBack(): AYINDeeplinkParams | null {
    if (this.canGoBack()) {
      this.currentIndex--;
      return this.history[this.currentIndex];
    }
    return null;
  }

  goForward(): AYINDeeplinkParams | null {
    if (this.canGoForward()) {
      this.currentIndex++;
      return this.history[this.currentIndex];
    }
    return null;
  }
}
