#### 🧱 Complete Stream Recovery Architecture

```typescript
// Beautiful stream event types
type StreamEvent = 
  | { type: 'first'; turn_span_id?: string; metadata?: Record<string, any> }
  | { type: 'data'; data: string }
  | { type: 'progress'; percentage: number; message: string }
  | { type: 'error'; error: string }
  | { type: 'done'; success: boolean; reason?: string }
  | { type: 'heartbeat' };

interface StreamRecoveryConfig {
  timeoutMs: number;           // ✨ Overall stream timeout
  heartbeatTimeoutMs: number;  // ✨ Heartbeat timeout
  maxRetries: number;          // ✨ Max retry attempts
  retryDelayMs: number;        // ✨ Delay between retries
}

class BeautifulStreamRecovery {
  private config: StreamRecoveryConfig;
  private timeoutId: NodeJS.Timeout | null = null;
  private heartbeatTimeoutId: NodeJS.Timeout | null = null;
  private lastHeartbeat: number = Date.now();
  private retryCount: number = 0;
  private isStreamActive: boolean = false;

  constructor(config: Partial<StreamRecoveryConfig> = {}) {
    this.config = {
      timeoutMs: 30000,        // 30 seconds
      heartbeatTimeoutMs: 10000, // 10 seconds
      maxRetries: 3,
      retryDelayMs: 1000,
      ...config
    };
  }

  async processStreamWithFullRecovery<T>(
    streamFactory: () => Promise<ReadableStream>,
    eventHandler: (event: StreamEvent) => Promise<void>,
    onComplete: () => void,
    onError: (error: Error) => void
  ): Promise<void> {
    console.log("🌟 Starting beautiful stream processing with full recovery");

    try {
      // ✨ 1. Set up primary timeout
      this.setupPrimaryTimeout(onComplete, onError);

      // ✨ 2. Process stream with recovery
      await this.processStreamWithMonitoring(streamFactory, eventHandler, onComplete, onError);

    } catch (error) {
      await this.handleStreamError(error, streamFactory, eventHandler, onComplete, onError);
    }
  }

  private async processStreamWithMonitoring(
    streamFactory: () => Promise<ReadableStream>,
    eventHandler: (event: StreamEvent) => Promise<void>,
    onComplete: () => void,
    onError: (error: Error) => void
  ): Promise<void> {
    const stream = await streamFactory();
    const reader = stream.getReader();

    this.isStreamActive = true;
    this.lastHeartbeat = Date.now();

    // ✨ Set up heartbeat monitoring
    this.setupHeartbeatMonitoring(onError);

    try {
      while (this.isStreamActive) {
        const { done, value } = await reader.read();

        if (done) {
          console.log("✅ Stream completed normally");
          this.clearAllTimeouts();
          onComplete();
          break;
        }

        // ✨ Parse and handle stream events
        const events = this.parseStreamEvents(value);
        for (const event of events) {
          await eventHandler(event);

          // ✨ Handle done event - clear all timeouts
          if (event.type === 'done') {
            console.log("🎯 Done event received - stream complete");
            this.clearAllTimeouts();
            onComplete();
            this.isStreamActive = false;
            break;
          }

          // ✨ Update heartbeat on any event
          this.updateHeartbeat();
        }
      }
    } finally {
      reader.releaseLock();
    }
  }

  private setupPrimaryTimeout(onComplete: () => void, onError: (error: Error) => void) {
    console.log(`⏰ Setting up primary timeout: ${this.config.timeoutMs}ms`);

    this.timeoutId = setTimeout(() => {
      console.log("⏰ Primary timeout triggered - stream taking too long");

      // ✨ Emit synthetic done event for graceful recovery
      onError(new Error("Stream timeout - no done event received"));

      // ✨ Force completion for UI recovery
      this.forceStreamCompletion(onComplete);

    }, this.config.timeoutMs);
  }

  private setupHeartbeatMonitoring(onError: (error: Error) => void) {
    console.log(`💓 Setting up heartbeat monitoring: ${this.config.heartbeatTimeoutMs}ms`);

    this.heartbeatTimeoutId = setInterval(() => {
      const timeSinceLastHeartbeat = Date.now() - this.lastHeartbeat;

      if (timeSinceLastHeartbeat > this.config.heartbeatTimeoutMs) {
        console.log(`💓 Heartbeat timeout - ${timeSinceLastHeartbeat}ms since last event`);

        // ✨ Treat as stream failure
        onError(new Error("Stream heartbeat timeout"));

        // ✨ Clear heartbeat monitoring
        if (this.heartbeatTimeoutId) {
          clearInterval(this.heartbeatTimeoutId);
          this.heartbeatTimeoutId = null;
        }

        this.isStreamActive = false;
      }
    }, 1000); // Check every second
  }

  private updateHeartbeat() {
    this.lastHeartbeat = Date.now();
    // console.log(`💓 Heartbeat updated: ${new Date(this.lastHeartbeat).toISOString()}`);
  }

  private async handleStreamError(
    error: any,
    streamFactory: () => Promise<ReadableStream>,
    eventHandler: (event: StreamEvent) => Promise<void>,
    onComplete: () => void,
    onError: (error: Error) => void
  ): Promise<void> {
    console.log(`⚠️  Stream error occurred: ${error.message}`);

    if (this.retryCount < this.config.maxRetries) {
      this.retryCount++;
      console.log(`🔄 Retry attempt ${this.retryCount}/${this.config.maxRetries}`);

      // ✨ Clear existing timeouts
      this.clearAllTimeouts();

      // ✨ Delay before retry
      await new Promise(resolve => setTimeout(resolve, this.config.retryDelayMs * this.retryCount));

      // ✨ Retry the stream
      await this.processStreamWithFullRecovery(streamFactory, eventHandler, onComplete, onError);
    } else {
      console.log("💥 Max retries exceeded - giving up");
      onError(new Error(`Max retries exceeded: ${error.message}`));
      this.forceStreamCompletion(onComplete);
    }
  }

  private forceStreamCompletion(onComplete: () => void) {
    console.log("🛡️  Forcing stream completion for UI recovery");

    // ✨ Clear all recovery timeouts
    this.clearAllTimeouts();

    // ✨ Mark stream as inactive
    this.isStreamActive = false;

    // ✨ Call completion callback for UI cleanup
    onComplete();
  }

  private clearAllTimeouts() {
    console.log("🧹 Clearing all recovery timeouts");

    if (this.timeoutId) {
      clearTimeout(this.timeoutId);
      this.timeoutId = null;
    }

    if (this.heartbeatTimeoutId) {
      clearInterval(this.heartbeatTimeoutId);
      this.heartbeatTimeoutId = null;
    }
  }

  private parseStreamEvents(data: Uint8Array): StreamEvent[] {
    const text = new TextDecoder().decode(data);
    const lines = text.split('\n').filter(line => line.trim());

    const events: StreamEvent[] = [];
    for (const line of lines) {
      if (line.startsWith('data: ')) {
        try {
          const eventData = JSON.parse(line.slice(6));
          events.push(eventData);
        } catch (e) {
          // Handle non-JSON data
          events.push({ type: 'data', data: line.slice(6) });
        }
      }
    }

    return events;
  }
}
