// Beautiful copilot response handling with recovery
class CopilotResponseRecovery {
  private recoveryManager: BeautifulStreamRecovery;
  private isProcessing: boolean = false;

  constructor() {
    this.recoveryManager = new BeautifulStreamRecovery({
      timeoutMs: 45000,        // Copilot responses can take time
      heartbeatTimeoutMs: 15000, // Longer heartbeat for complex responses
      maxRetries: 2,
      retryDelayMs: 2000
    });
  }

  async processCopilotResponse(
    prompt: string,
    onPartialResponse: (text: string) => void,
    onComplete: (finalResponse: string) => void,
    onError: (error: string) => void
  ) {
    if (this.isProcessing) {
      onError("Already processing a response");
      return;
    }

    this.isProcessing = true;
    let accumulatedResponse = "";

    console.log("🤖 Starting copilot response processing");

    try {
      await this.recoveryManager.processStreamWithFullRecovery(
        () => this.createCopilotStream(prompt),
        async (event) => {
          switch (event.type) {
            case 'data':
              accumulatedResponse += event.data;
              onPartialResponse(accumulatedResponse);
              break;

            case 'progress':
              console.log(`📊 Progress: ${event.percentage}% - ${event.message}`);
              break;

            case 'error':
              console.log(`⚠️  Copilot error: ${event.error}`);
              onError(event.error);
              break;

            case 'done':
              console.log("✅ Copilot response completed");
              onComplete(accumulatedResponse);
              break;
          }
        },
        () => {
          // ✨ Normal completion or recovery completion
          this.isProcessing = false;
          console.log("🎉 Copilot processing completed");
        },
        (error) => {
          // ✨ Error or timeout recovery
          this.isProcessing = false;
          onError(`Copilot failed: ${error.message}`);
          console.log(`💥 Copilot processing failed: ${error.message}`);
        }
      );
    } catch (error) {
      this.isProcessing = false;
      onError(`Unexpected error: ${error.message}`);
    }
  }

  private async createCopilotStream(prompt: string): Promise<ReadableStream> {
    const response = await fetch('/api/copilot/stream', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ prompt })
    });

    if (!response.body) {
      throw new Error('No response body');
    }

    return response.body;
  }
}

