class BuildProcessRecovery {
  private recoveryManager: BeautifulStreamRecovery;
  private buildStartTime: number = 0;

  constructor() {
    this.recoveryManager = new BeautifulStreamRecovery({
      timeoutMs: 300000,       // 5 minute timeout for builds
      heartbeatTimeoutMs: 30000, // 30 second heartbeat timeout
      maxRetries: 1,
      retryDelayMs: 5000
    });
  }

  async executeBuild(
    projectPath: string,
    onBuildOutput: (output: string) => void,
    onBuildProgress: (percentage: number, message: string) => void,
    onBuildComplete: (success: boolean, duration: number) => void,
    onBuildError: (error: string) => void
  ) {
    this.buildStartTime = Date.now();
    console.log(`🏗️  Starting build process for: ${projectPath}`);

    try {
      await this.recoveryManager.processStreamWithFullRecovery(
        () => this.createBuildStream(projectPath),
        async (event) => {
          switch (event.type) {
            case 'data':
              onBuildOutput(event.data);
              break;

            case 'progress':
              onBuildProgress(event.percentage, event.message);
              break;

            case 'error':
              console.log(`⚠️  Build error: ${event.error}`);
              onBuildOutput(`ERROR: ${event.error}\n`);
              break;

            case 'done':
              const duration = Date.now() - this.buildStartTime;
              const success = event.success;
              console.log(`✅ Build ${success ? 'completed' : 'failed'} in ${duration}ms`);
              onBuildComplete(success, duration);
              break;

            case 'heartbeat':
              // Keep alive signal
              break;
          }
        },
        () => {
          // ✨ Build completed normally or recovered
          console.log("🎉 Build process completed");
        },
        (error) => {
          // ✨ Build failed or timed out
          const duration = Date.now() - this.buildStartTime;
          console.log(`💥 Build process failed after ${duration}ms: ${error.message}`);
          onBuildError(`Build failed: ${error.message}`);
          onBuildComplete(false, duration);
        }
      );
    } catch (error) {
      onBuildError(`Unexpected build error: ${error.message}`);
      onBuildComplete(false, Date.now() - this.buildStartTime);
    }
  }

  private async createBuildStream(projectPath: string): Promise<ReadableStream> {
    const response = await fetch('/api/build/stream', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ projectPath })
    });

    if (!response.body) {
      throw new Error('No build stream available');
    }

    return response.body;
  }
}

