// Recovery with circuit breaker pattern
class CircuitBreakerRecovery {
  private failureCount: number = 0;
  private readonly failureThreshold: number = 5;
  private readonly timeout: number = 60000; // 1 minute
  private lastFailureTime: number | null = null;

  async callWithCircuitBreaker<T>(
    operation: () => Promise<T>,
    fallback: () => T
  ): Promise<T> {
    if (this.isCircuitOpen()) {
      console.log("⚠️  Circuit breaker open - using fallback");
      return fallback();
    }

    try {
      const result = await operation();
      this.failureCount = 0; // Reset on success
      this.lastFailureTime = null;
      return result;
    } catch (error) {
      this.failureCount++;
      this.lastFailureTime = Date.now();

      if (this.failureCount >= this.failureThreshold) {
        console.log("🚨 Circuit breaker tripped!");
      }

      throw error;
    }
  }

  private isCircuitOpen(): boolean {
    if (this.failureCount < this.failureThreshold) {
      return false;
    }

    // Check if timeout has elapsed for half-open state
    if (this.lastFailureTime && 
        Date.now() - this.lastFailureTime > this.timeout) {
      console.log("🔄 Circuit breaker half-open - testing...");
      return false;
    }

    return true;
  }
}

