        });

        await recoveryManager.processStreamWithFullRecovery(
          streamFactory,
          processor,
          onComplete,
          onError
        );

        // Success - we're done
        return;

      } catch (error) {
        console.log(`⚠️  Strategy ${strategy.name} failed: ${error.message}`);
        strategyIndex++;

        if (strategyIndex >= this.recoveryStrategies.length) {
