#### 🧱 Complete Stream Recovery Architecture

```typescript
// Beautiful stream recovery with multiple fallback strategies
class BeautifulStreamRecovery {
  private activeStreams: Map<string, StreamRecoveryContext> = new Map();
  private defaultTimeoutMs: number = 30000; // 30 seconds
  private maxRetries: number = 3;

  async processStreamWithRecovery(
    streamId: string,
    stream: ReadableStream,
    callbacks: StreamCallbacks
  ): Promise<void> {
    const context: StreamRecoveryContext = {
      id: streamId,
      reader: stream.getReader(),
      buffer: [],
      isActive: true,
      retryCount: 0,
      lastActivity: Date.now(),
      timeoutId: null,
      heartbeatIntervalId: null
    };

    this.activeStreams.set(streamId, context);

    // ✨ Set up beautiful recovery mechanisms
    this.setupRecoveryTimeout(context, callbacks);
    this.setupHeartbeatMonitoring(context);
    this.setupActivityTracking(context);

    try {
      await this.processStreamData(context, callbacks);
    } catch (error) {
      console.error(`❌ Stream ${streamId} error:`, error);
      await this.handleStreamError(context, error, callbacks);
    } finally {
      this.cleanupStreamContext(context);
    }
  }

  private setupRecoveryTimeout(
    context: StreamRecoveryContext,
    callbacks: StreamCallbacks
  ) {
    context.timeoutId = setTimeout(() => {
      if (context.isActive) {
        console.warn(`⚠️  Stream ${context.id} timeout - initiating recovery`);
        this.initiateRecovery(context, callbacks, 'timeout');
      }
    }, this.defaultTimeoutMs);
  }

  private setupHeartbeatMonitoring(context: StreamRecoveryContext) {
    // ✨ Send periodic heartbeats to detect stalled streams
    context.heartbeatIntervalId = setInterval(() => {
      if (context.isActive) {
        const timeSinceLastActivity = Date.now() - context.lastActivity;
        if (timeSinceLastActivity > 10000) { // 10 seconds
          console.log(`💓 Heartbeat check for stream ${context.id}`);
          // Could trigger early recovery or alert
        }
      }
    }, 5000); // Check every 5 seconds
  }

  private setupActivityTracking(context: StreamRecoveryContext) {
    // ✨ Reset timeout on any stream activity
    const originalTimeoutId = context.timeoutId;
    context.timeoutId = setTimeout(() => {
      if (context.isActive) {
        console.warn(`⏰ Stream ${context.id} activity timeout`);
        this.initiateRecovery(context, {
          onData: () => {},
          onError: () => {},
          onComplete: () => {},
          onRecovery: () => {}
        }, 'activity_timeout');
      }
    }, this.defaultTimeoutMs);

    // ✨ Clear original timeout
    if (originalTimeoutId) {
      clearTimeout(originalTimeoutId);
    }
  }

  private async processStreamData(
    context: StreamRecoveryContext,
    callbacks: StreamCallbacks
  ) {
    while (context.isActive) {
      try {
        const { done, value } = await context.reader.read();

        if (done) {
          console.log(`✅ Stream ${context.id} completed normally`);
          this.handleNormalCompletion(context, callbacks);
          break;
        }

        // ✨ Process stream event
        const event = this.parseSSEEvent(value);
        await this.handleStreamEvent(context, event, callbacks);

        // ✨ Update activity tracking
        context.lastActivity = Date.now();
        this.resetRecoveryTimeout(context);

      } catch (error) {
        if (context.retryCount < this.maxRetries) {
          context.retryCount++;
          console.log(`🔄 Retrying stream ${context.id} (attempt ${context.retryCount})`);
          await this.delay(1000 * context.retryCount); // Exponential backoff
          continue;
        } else {
          throw error;
        }
      }
    }
  }

  private async handleStreamEvent(
    context: StreamRecoveryContext,
    event: StreamEvent,
    callbacks: StreamCallbacks
  ) {
    switch (event.type) {
      case 'data':
        if (event.data) {
          context.buffer.push(event.data);
          callbacks.onData?.(event.data);
        }
        break;

      case 'done':
        console.log(`🎯 Stream ${context.id} received done event`);
        this.handleNormalCompletion(context, callbacks);
        break;

      case 'error':
        console.error(`💥 Stream ${context.id} error event:`, event.error);
        callbacks.onError?.(new Error(event.error));
        break;

      case 'progress':
        callbacks.onProgress?.(event.progress, event.message);
        break;

      case 'heartbeat':
        // Heartbeat received - stream is alive
        context.lastActivity = Date.now();
        break;
    }
  }

  private handleNormalCompletion(
    context: StreamRecoveryContext,
    callbacks: StreamCallbacks
  ) {
    context.isActive = false;

    // ✨ Create final message from buffer
    const finalMessage: AssistantMessage = {
      role: 'assistant',
      content: context.buffer.join(''),
      timestamp: Date.now(),
      metadata: {
        stream_id: context.id,
        completed_normally: true,
        buffer_length: context.buffer.length,
        total_duration_ms: Date.now() - context.lastActivity
      }
    };

    callbacks.onComplete?.(finalMessage);
    console.log(`🎉 Stream ${context.id} completed successfully`);
  }

  private initiateRecovery(
    context: StreamRecoveryContext,
    callbacks: StreamCallbacks,
    reason: RecoveryReason
  ) {
    console.log(`✨ Initiating recovery for stream ${context.id} due to: ${reason}`);

    // ✨ Cancel any pending timeouts
    this.cancelRecoveryTimeout(context);

    // ✨ Create recovery message
    const recoveryMessage: AssistantMessage = {
      role: 'assistant',
      content: context.buffer.join(''),
      timestamp: Date.now(),
      metadata: {
        stream_id: context.id,
        recovered: true,
        recovery_reason: reason,
        partial_content: context.buffer.length > 0,
        buffer_length: context.buffer.length,
        recovery_timestamp: Date.now()
      }
    };

    // ✨ Apply recovery strategies
    switch (reason) {
      case 'timeout':
        this.handleTimeoutRecovery(context, recoveryMessage, callbacks);
        break;
      case 'activity_timeout':
        this.handleActivityTimeoutRecovery(context, recoveryMessage, callbacks);
        break;
      case 'network_error':
        this.handleNetworkErrorRecovery(context, recoveryMessage, callbacks);
        break;
    }
  }

  private handleTimeoutRecovery(
    context: StreamRecoveryContext,
    message: AssistantMessage,
    callbacks: StreamCallbacks
  ) {
    console.log(`⏰ Timeout recovery for stream ${context.id}`);

    // ✨ Close the stream reader
    context.reader.cancel().catch(err => {
      console.warn(`⚠️  Error cancelling stream reader:`, err);
    });

    // ✨ Emit recovery message
    callbacks.onRecovery?.(message);
    callbacks.onComplete?.(message);

    context.isActive = false;
  }

  private async handleStreamError(
    context: StreamRecoveryContext,
    error: any,
    callbacks: StreamCallbacks
  ) {
    console.error(`💥 Stream error for ${context.id}:`, error);

    if (context.retryCount < this.maxRetries) {
      // ✨ Retry logic
      context.retryCount++;
      console.log(`🔄 Retrying stream ${context.id} (attempt ${context.retryCount})`);

      await this.delay(1000 * context.retryCount);
      // Could restart the stream here
    } else {
      // ✨ Final error recovery
      this.initiateRecovery(context, callbacks, 'network_error');
    }
  }

  private resetRecoveryTimeout(context: StreamRecoveryContext) {
    if (context.timeoutId) {
      clearTimeout(context.timeoutId);
    }

    context.timeoutId = setTimeout(() => {
      if (context.isActive) {
        console.warn(`⏰ Recovery timeout for stream ${context.id}`);
        this.initiateRecovery(context, {
          onData: () => {},
          onError: () => {},
          onComplete: () => {},
          onRecovery: () => {}
        }, 'timeout');
      }
    }, this.defaultTimeoutMs);
  }

  private cancelRecoveryTimeout(context: StreamRecoveryContext) {
    if (context.timeoutId) {
      clearTimeout(context.timeoutId);
      context.timeoutId = null;
    }

    if (context.heartbeatIntervalId) {
      clearInterval(context.heartbeatIntervalId);
      context.heartbeatIntervalId = null;
    }
  }

  private cleanupStreamContext(context: StreamRecoveryContext) {
    context.isActive = false;
    this.cancelRecoveryTimeout(context);

    try {
      context.reader.releaseLock();
    } catch (error) {
      console.warn(`⚠️  Error releasing stream reader:`, error);
    }

    this.activeStreams.delete(context.id);
    console.log(`🧹 Cleaned up stream context for ${context.id}`);
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  private parseSSEEvent(data: Uint8Array): StreamEvent {
    const text = new TextDecoder().decode(data);
    const lines = text.split('\n');

    const event: StreamEvent = { type: 'data' };

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        try {
          const eventData = JSON.parse(line.slice(6));
          Object.assign(event, eventData);
        } catch {
          event.data = line.slice(6);
        }
      }
    }

    return event;
  }
}

