// ✨ WITH beautiful recovery:
async function beautifulStreamHandling() {
  const response = await fetch('/stream');
  const reader = response.body!.getReader();

  let buffer: string[] = [];
  let streamActive = true;

  // ✨ Set recovery timeout
  const timeoutId = setTimeout(() => {
    if (streamActive) {
      console.warn("⚠️  Stream timeout - recovering gracefully");

      // ✨ Recover with available data
      const recoveryMessage: AssistantMessage = {
        role: 'assistant',
        content: buffer.join('') + '\n\n⚠️ Response may be incomplete',
        timestamp: Date.now(),
        metadata: {
          recovered: true,
          recovery_reason: 'timeout',
          partial_content: true
        }
      };

      displayMessage(recoveryMessage);
      streamActive = false;
    }
  }, 30000); // 30 second timeout

  try {
    while (streamActive) {
      const { done, value } = await reader.read();

      if (done) {
        // ✨ Normal completion - cancel timeout
        clearTimeout(timeoutId);
        streamActive = false;

        const finalMessage: AssistantMessage = {
          role: 'assistant',
          content: buffer.join(''),
          timestamp: Date.now()
        };

        displayMessage(finalMessage);
        break;
      }

      const text = new TextDecoder().decode(value);
      buffer.push(text);

      // ✨ Reset timeout on activity
      clearTimeout(timeoutId);
      // Set new timeout...
    }
  } catch (error) {
    // ✨ Handle stream errors
    clearTimeout(timeoutId);
    console.error("❌ Stream error:", error);

    const errorMessage: AssistantMessage = {
      role: 'assistant',
      content: buffer.join('') + `\n\n❌ Error occurred: ${error.message}`,
      timestamp: Date.now(),
      metadata: {
        error: true,
        error_message: error.message,
        partial_content: buffer.length > 0
      }
    };

    displayMessage(errorMessage);
  } finally {
    reader.releaseLock();
  }
}
