// Recovery with circuit breaker pattern
class CircuitBreakerRecovery {
  private failureCount = 0;
  private readonly failureThreshold = 5;
  private readonly timeout = 60000; // 1 minute
  private lastFailureTime: number | null = null;

  async processStreamWithCircuitBreaker(
    stream: ReadableStream,
    callbacks: StreamCallbacks
  ): Promise<void> {
    if (this.isCircuitOpen()) {
      console.log("⚠️  Circuit breaker open - using immediate recovery");
      this.immediateRecovery(callbacks);
      return;
    }

    try {
      const recoveryManager = new BeautifulStreamRecovery();
      await recoveryManager.processStreamWithRecovery(
        `stream-${Date.now()}`,
        stream,
        callbacks
      );

      // ✨ Reset failure count on success
      this.failureCount = 0;
      this.lastFailureTime = null;

    } catch (error) {
      // ✨ Record failure
      this.failureCount++;
      this.lastFailureTime = Date.now();

      console.error(`❌ Stream failure (${this.failureCount}/${this.failureThreshold}):`, error);

      if (this.failureCount >= this.failureThreshold) {
        console.log("🚨 Circuit breaker tripped!");
        this.immediateRecovery(callbacks);
      } else {
        throw error; // Let normal recovery handle it
      }
    }
  }

  private isCircuitOpen(): boolean {
    if (this.failureCount < this.failureThreshold) {
      return false;
    }

    // ✨ Check if timeout has elapsed
    if (this.lastFailureTime && 
        Date.now() - this.lastFailureTime > this.timeout) {
      // ✨ Half-open state - allow one test
      console.log("🔄 Circuit breaker half-open - testing...");
      return false;
    }

    return true;
  }

  private immediateRecovery(callbacks: StreamCallbacks) {
    const recoveryMessage: AssistantMessage = {
      role: 'assistant',
      content: '⚠️ Service temporarily unavailable. Please try again later.',
      timestamp: Date.now(),
      metadata: {
        circuit_breaker_triggered: true,
        service_unavailable: true,
        recovery_type: 'immediate'
      }
    };

    callbacks.onRecovery?.(recoveryMessage);
    callbacks.onComplete?.(recoveryMessage);
  }
