    pub parent_id: String,  // ✨ 16-character hex string  
    pub trace_flags: u8,    // ✨ Bit flags (1 = sampled)
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TurnSpan {
    pub span_id: String,              // ✨ AYIN's internal span ID
    pub trace_id: String,             // ✨ Can come from W3C traceparent
    pub parent_span_id: Option<String>, // ✨ Can come from W3C parent_id
    pub w3c_traceparent: Option<W3CTraceparent>, // ✨ W3C compatibility
    pub operation_name: String,
    pub service_name: String,
    pub start_time: std::time::Instant,
    pub end_time: Option<std::time::Instant>,
    pub status: SpanStatus,
    pub metadata: serde_json::Value,
    // ... other fields
}

// ✨ Parse W3C traceparent header
impl FromStr for W3CTraceparent {
    type Err = Error;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let parts: Vec<&str> = s.split('-').collect();

        if parts.len() != 4 {
            return Err(Error::InvalidTraceparent("Invalid format".to_string()));
        }

        let version = u8::from_str_radix(parts[0], 16)
            .map_err(|_| Error::InvalidTraceparent("Invalid version".to_string()))?;

        if version != 0 {
            return Err(Error::InvalidTraceparent("Unsupported version".to_string()));
        }

        let trace_id = parts[1].to_string();
        let parent_id = parts[2].to_string();
        let trace_flags = u8::from_str_radix(parts[3], 16)
            .map_err(|_| Error::InvalidTraceparent("Invalid trace flags".to_string()))?;

        // ✨ Validate hex format and lengths
        if trace_id.len() != 32 || !is_hex_string(&trace_id) {
            return Err(Error::InvalidTraceparent("Invalid trace_id".to_string()));
        }

        if parent_id.len() != 16 || !is_hex_string(&parent_id) {
            return Err(Error::InvalidTraceparent("Invalid parent_id".to_string()));
        }

        Ok(W3CTraceparent {
            version,
            trace_id,
            parent_id,
            trace_flags,
        })
    }
}

// ✨ Generate W3C traceparent from AYIN span
impl TurnSpan {
    pub fn to_w3c_traceparent(&self) -> W3CTraceparent {
        W3CTraceparent {
            version: 0,
            trace_id: self.trace_id.clone(),
            parent_id: self.span_id.clone(),  // ✨ Current span becomes parent
            trace_flags: if self.is_sampled() { 1 } else { 0 },
        }
    }

    pub fn to_w3c_header_value(&self) -> String {
        let tp = self.to_w3c_traceparent();
        format!(
            "{:02x}-{}-{}-{:02x}",
            tp.version, tp.trace_id, tp.parent_id, tp.trace_flags
        )
    }

    fn is_sampled(&self) -> bool {
        // ✨ Sampling logic based on trace ID or configuration
        true // Simplified for example
    }
}

// ✨ Create AYIN span from W3C traceparent
impl TurnSpan {
    pub fn from_w3c_traceparent(
        traceparent: W3CTraceparent,
        operation_name: String,
        service_name: String,
    ) -> Self {
        Self {
            span_id: generate_ayin_span_id(),  // ✨ AYIN's own ID generation
            trace_id: traceparent.trace_id,    // ✨ Use W3C trace ID
            parent_span_id: Some(traceparent.parent_id), // ✨ Link to W3C parent
            w3c_traceparent: Some(traceparent), // ✨ Keep W3C context
            operation_name,
            service_name,
            start_time: std::time::Instant::now(),
            end_time: None,
            status: SpanStatus::InProgress,
            metadata: serde_json::json!({}),
        }
    }
}
