// ✨ Extract W3C traceparent from HTTP request
fn extract_w3c_traceparent(request: &HttpRequest) -> Result<Option<W3CTraceparent>, Error> {
    if let Some(traceparent_header) = request.headers().get("traceparent") {
        let header_value = traceparent_header
            .to_str()
            .map_err(|_| Error::InvalidHeader("Invalid traceparent header".to_string()))?;

        match W3CTraceparent::from_str(header_value) {
            Ok(traceparent) => {
                println!("🔗 Parsed W3C traceparent: trace_id={}, parent_id={}",
                         traceparent.trace_id, traceparent.parent_id);
                Ok(Some(traceparent))
            }
            Err(e) => {
                println!("⚠️  Failed to parse traceparent: {}", e);
                Ok(None) // Continue without traceparent
            }
        }
    } else {
        println!("📭 No traceparent header found");
        Ok(None)
    }
}

