// Traceparent validation and sanitization
impl W3CTraceparent {
    pub fn validate(&self) -> Result<(), Error> {
        // ✨ Validate trace_id is not all zeros
        if self.trace_id.chars().all(|c| c == '0') {
            return Err(Error::InvalidTraceparent("trace_id cannot be all zeros".to_string()));
        }

        // ✨ Validate parent_id is not all zeros
        if self.parent_id.chars().all(|c| c == '0') {
            return Err(Error::InvalidTraceparent("parent_id cannot be all zeros".to_string()));
        }

        // ✨ Validate version (only 0 supported)
        if self.version != 0 {
            return Err(Error::InvalidTraceparent("Only version 0 supported".to_string()));
        }

        Ok(())
    }

    pub fn to_header_string(&self) -> String {
        format!(
            "{:02x}-{}-{}-{:02x}",
            self.version, self.trace_id, self.parent_id, self.trace_flags
        )
    }
}

