impl W3CTraceparent {
    pub fn from_header_flexible(header: &str) -> Result<Self, Error> {
        // ✨ Try to parse strict format first
        match Self::from_str(header) {
            Ok(tp) => Ok(tp),
            Err(_) => {
                // ✨ Try to be more flexible with common variations
                Self::parse_flexible(header)
            }
        }
    }

    fn parse_flexible(header: &str) -> Result<Self, Error> {
        // ✨ Handle common variations and errors
        let clean_header = header.trim();
        let parts: Vec<&str> = clean_header.split('-').collect();

        if parts.len() < 4 {
            return Err(Error::InvalidTraceparent("Too few parts".to_string()));
        }

        // ✨ Handle version padding
        let version = u8::from_str_radix(parts[0], 16).unwrap_or(0);

        // ✨ Handle trace_id padding/trimming
        let trace_id = format!("{:0>32}", parts[1]);

        // ✨ Handle parent_id padding/trimming  
