#### 🧱 W3C traceparent Header Structure

```rust
// Beautiful W3C traceparent header format
// Format: 00-TRACE_ID-SPAN_ID-TRACE_FLAGS
// Example: 00-4bf92f3577b34da6a3ce929d0e0e4736-00f067aa0ba902b7-01

#[derive(Debug, Clone)]
pub struct W3CTraceparent {
    pub version: u8,           // ✨ Version (00 = current)
    pub trace_id: String,      // ✨ 32-character hex trace identifier
    pub parent_id: String,     // ✨ 16-character hex parent span identifier  
    pub trace_flags: u8,       // ✨ Flags (01 = sampled, 00 = not sampled)
}

impl W3CTraceparent {
    // ✨ Parse W3C traceparent header
    pub fn parse(header_value: &str) -> Result<Self, Error> {
        let parts: Vec<&str> = header_value.split('-').collect();

        if parts.len() != 4 {
            return Err(Error::InvalidTraceparent("Invalid format".to_string()));
        }

        let version = u8::from_str_radix(parts[0], 16)
            .map_err(|_| Error::InvalidTraceparent("Invalid version".to_string()))?;

        if version != 0 {
            return Err(Error::InvalidTraceparent("Unsupported version".to_string()));
        }

        let trace_id = parts[1].to_string();
        let parent_id = parts[2].to_string();
        let trace_flags = u8::from_str_radix(parts[3], 16)
            .map_err(|_| Error::InvalidTraceparent("Invalid trace flags".to_string()))?;

        // ✨ Validate trace ID (32 hex chars)
        if trace_id.len() != 32 || !trace_id.chars().all(|c| c.is_ascii_hexdigit()) {
            return Err(Error::InvalidTraceparent("Invalid trace ID".to_string()));
        }

        // ✨ Validate parent ID (16 hex chars)
        if parent_id.len() != 16 || !parent_id.chars().all(|c| c.is_ascii_hexdigit()) {
            return Err(Error::InvalidTraceparent("Invalid parent ID".to_string()));
        }

        Ok(Self {
            version,
            trace_id,
            parent_id,
            trace_flags,
        })
    }

    // ✨ Generate W3C traceparent header from AYIN span
    pub fn from_ayin_span(span: &TurnSpan) -> Self {
        Self {
            version: 0,
            trace_id: span.trace_id.clone(),           // ✨ AYIN trace_id
            parent_id: span.span_id.clone(),           // ✨ Current span becomes parent
            trace_flags: if span.is_sampled() { 1 } else { 0 }, // ✨ Sampling flag
        }
    }

    // ✨ Convert to header string format
    pub fn to_header_string(&self) -> String {
        format!("00-{}-{}-{:02x}", self.trace_id, self.parent_id, self.trace_flags)
    }
}
