// Beautiful HTTP middleware that handles W3C traceparent
async fn w3c_tracing_middleware(
    request: HttpRequest,
    next: NextFn,
) -> Result<HttpResponse, Error> {
    let start_time = Instant::now();

    // ✨ Extract W3C traceparent from headers
    let traceparent = request.headers()
        .get("traceparent")
        .and_then(|h| h.to_str().ok())
        .and_then(|h| W3CTraceparent::parse(h).ok());

    // ✨ Create AYIN span from W3C traceparent (or new trace if none)
    let span = if let Some(tp) = traceparent {
        println!("🔄 Continuing existing trace: {}", tp.trace_id);
        TurnSpan::from_w3c_traceparent(
            tp,
            format!("{} {}", request.method(), request.uri().path()),
            get_service_name(),
        )
    } else {
        println!("🆕 Creating new trace");
        TurnSpan::new(
            format!("{} {}", request.method(), request.uri().path()),
            None, // New root span
        )
    };

    // ✨ Add request context to span
    span.add_metadata("http_method", request.method().as_str());
    span.add_metadata("http_path", request.uri().path());
    span.add_metadata("user_agent", request.headers().get("user-agent").and_then(|h| h.to_str().ok()).unwrap_or(""));

    // ✨ Process request with tracing
    let result = match next(request).await {
        Ok(response) => {
            span.add_metadata("response_status", &response.status().as_u16().to_string());
            span.complete();
            Ok(response)
        }
        Err(e) => {
            span.fail(&e.to_string());
            Err(e)
        }
    };

    // ✨ Record beautiful metrics
    let duration = start_time.elapsed();
    println!("✅ Request processed in {:?} with trace ID: {}", duration, span.trace_id);

    result
}

