#[derive(Debug, Clone)]
pub struct BaggageItem {
    pub value: String,
    pub metadata: Option<String>,  // Optional metadata
}

impl W3CBaggage {
    pub fn parse(header_value: &str) -> Result<Self, Error> {
        let items = header_value
            .split(',')
            .map(|item| {
                let parts: Vec<&str> = item.trim().split('=').collect();
                if parts.len() >= 2 {
                    let key = parts[0].to_string();
                    let value = parts[1].to_string();
                    let metadata = if parts.len() > 2 { 
                        Some(parts[2].to_string()) 
                    } else { 
                        None 
                    };
                    Ok((key, BaggageItem { value, metadata }))
                } else {
                    Err(Error::InvalidBaggage("Invalid baggage item".to_string()))
                }
            })
            .collect::<Result<HashMap<_, _>, _>>()?;

        Ok(Self { items })
    }

    pub fn to_header_string(&self) -> String {
        self.items
            .iter()
            .map(|(k, v)| {
                if let Some(metadata) = &v.metadata {
                    format!("{}={};{}", k, v.value, metadata)
                } else {
                    format!("{}={}", k, v.value)
                }
            })
            .collect::<Vec<_>>()
            .join(",")
    }
}
