// 3. W3C header validation and sanitization
pub struct W3CHeaderValidator;

impl W3CHeaderValidator {
    pub fn validate_and_sanitize_traceparent(header: &str) -> Result<String, Error> {
        // ✨ Parse and re-serialize to ensure correct format
        let traceparent = W3CTraceparent::parse(header)?;

        // ✨ Sanitize trace IDs (ensure valid hex)
        let sanitized_trace_id = traceparent.trace_id
            .chars()
            .filter(|c| c.is_ascii_hexdigit())
            .take(32)
            .collect::<String>();

        let sanitized_parent_id = traceparent.parent_id
            .chars()
            .filter(|c| c.is_ascii_hexdigit())
            .take(16)
            .collect::<String>();

        Ok(format!(
            "00-{}-{}-{:02x}",
            sanitized_trace_id,
            sanitized_parent_id,
            traceparent.trace_flags & 1  // Only keep sampled bit
        ))
    }
}

