async fn good_comprehensive_w3c_integration(
    request_headers: HashMap<String, String>,
) -> Result<TurnSpan, Error> {
    // ✨ Beautiful, comprehensive W3C integration
    let traceparent = request_headers
        .get("traceparent")
        .and_then(|h| h.as_str())
        .and_then(|h| W3CTraceparent::parse_gracefully(h));

    let tracestate = request_headers
        .get("tracestate")
        .and_then(|h| h.as_str())
        .and_then(|h| W3CTracestate::parse(h).ok());

    let baggage = request_headers
        .get("baggage")
        .and_then(|h| h.as_str())
        .and_then(|h| W3CBaggage::parse(h).ok());

    // ✨ Create enhanced AYIN span with full W3C context
    let mut span = if let Some(tp) = traceparent {
        TurnSpan::from_w3c_traceparent(
            tp,
            "comprehensive_integration".to_string(),
            get_service_name(),
        )
    } else {
        TurnSpan::new("comprehensive_integration", None)
    };

    // ✨ Add additional W3C context
    if let Some(ts) = tracestate {
        span.add_metadata("tracestate", &serde_json::to_string(&ts.entries)?);
    }

    if let Some(b) = baggage {
        for (key, item) in b.items {
            span.add_metadata(&key, &item.value);
        }
    }

    // ✨ Beautiful cross-system tracing enabled!
    println!("🌟 Comprehensive W3C integration complete!");
    println!("  Trace ID: {}", span.trace_id);
    println!("  Cross-system compatibility: ✅");
    println!("  Full observability: ✅");

    Ok(span)
}
