// Beautiful conversation tracking with session/turn hierarchy
async fn track_beautiful_conversation(
    user_id: String,
    initial_message: String,
) -> Result<ConversationResult, Error> {
    // ✨ 1. Create session span for entire conversation
    let mut session_span = SessionSpan::new(
        user_id.clone(),
        format!("conv-{}", Uuid::new_v4())
    );

    session_span.session_context.session_type = SessionType::Conversation;
    session_span.user_context.add_tag("active_conversation");

    println!("🏠 Session span created: {}", session_span.span.span_id);

    // ✨ 2. Create first turn for initial message
    let mut first_turn = TurnSpan::new(
        session_span.span.span_id.clone(),
        None, // First turn has no parent
        user_id.clone(),
        session_span.session_context.session_id.clone(),
    );

    first_turn.turn_context.turn_type = TurnType::UserMessage;
    first_turn.span.metadata.operation_name = "process_user_message".to_string();
    first_turn.span.metadata.tags.push("initial_message".to_string());

    // ✨ 3. Link turn to session
    session_span.add_turn_span(first_turn.span.span_id.clone());

    // ✨ 4. Process conversation turns
    let mut conversation_turns = vec![first_turn];
    let mut current_parent_turn = first_turn.span.span_id.clone();

    // Simulate multi-turn conversation
    for i in 1..=3 {
        let mut turn = TurnSpan::new(
            session_span.span.span_id.clone(),
            Some(current_parent_turn.clone()),
            user_id.clone(),
            session_span.session_context.session_id.clone(),
        );

        turn.turn_context.turn_type = if i % 2 == 0 { 
            TurnType::AssistantResponse 
        } else { 
            TurnType::UserMessage 
        };

        turn.span.metadata.operation_name = format!("process_turn_{}", i);
        turn.span.metadata.tags.push(format!("turn_{}", i));

        // ✨ Link to session and track parent relationship
        session_span.add_turn_span(turn.span.span_id.clone());
        conversation_turns.push(turn);
        current_parent_turn = turn.span.span_id.clone();

        println!("🔄 Turn {} created: {} (parent: {})", 
                 i, turn.span.span_id, turn.parent_turn_id.as_ref().unwrap());
    }

    // ✨ 5. Complete session
    session_span.span.end_time = Some(Instant::now());
    session_span.session_duration = Some(
        session_span.span.end_time.unwrap()
            .duration_since(session_span.span.start_time)
            .as_nanos() as u64
    );
    session_span.session_outcome = SessionOutcome::Completed;

    println!("🎉 Conversation session completed:");
    println!("  Session ID: {}", session_span.span.span_id);
    println!("  Total turns: {}", session_span.total_turns);
    println!("  Duration: {:?}ns", session_span.session_duration);
    println!("  Turn chain: {}", 
             conversation_turns.iter()
                 .map(|t| t.span.span_id.clone())
                 .collect::<Vec<_>>()
                 .join(" → "));

    Ok(ConversationResult {
        session_span,
        turn_spans: conversation_turns,
    })
}

