// Turn span with conversation intelligence
impl TurnSpan {
    pub fn analyze_conversation_context(&self, session: &SessionSpan) -> ConversationContext {
        ConversationContext {
            position_in_session: session.turn_spans.iter()
                .position(|id| id == &self.span.span_id)
                .map(|pos| pos + 1)
                .unwrap_or(0),
            turn_sequence: self.calculate_turn_sequence(session),
            conversation_state: self.determine_conversation_state(session),
            context_continuity: self.measure_context_continuity(session),
        }
    }

    fn calculate_turn_sequence(&self, session: &SessionSpan) -> TurnSequence {
        let position = session.turn_spans.iter()
            .position(|id| id == &self.span.span_id)
            .unwrap_or(0);

        if position == 0 {
            TurnSequence::First
        } else if position == session.total_turns - 1 {
            TurnSequence::Last
        } else {
            TurnSequence::Middle
        }
    }
}

