// 1. Span validation to ensure proper hierarchy
async fn validate_span_hierarchy(span: &HelixSpan) -> Result<(), Error> {
    match span.span_type {
        SpanType::Session => {
            // ✨ Session spans should not have parent spans
            if span.parent_span_id.is_some() {
                return Err(Error::InvalidSpan("Session spans should not have parents".to_string()));
            }
        }
        SpanType::Turn => {
            // ✨ Turn spans must have session parent
            if span.parent_span_id.is_none() {
                return Err(Error::InvalidSpan("Turn spans must have session parent".to_string()));
            }

            // ✨ Validate session link exists
            let session_span = load_session_span(span.parent_span_id.as_ref().unwrap()).await?;
            if !session_span.turn_spans.contains(&span.span_id) {
                return Err(Error::InvalidSpan("Turn not linked to session".to_string()));
            }
        }
        SpanType::SubTurn => {
            // ✨ Sub-turn spans must have turn parent
            if span.parent_span_id.is_none() {
                return Err(Error::InvalidSpan("Sub-turn spans must have turn parent".to_string()));
            }
        }
    }

    Ok(())
}

// 2. Span creation with automatic linking
pub struct SpanCreator {
    session_cache: HashMap<String, SessionSpan>,
}

impl SpanCreator {
    pub async fn create_turn_span(
        &mut self,
        session_span_id: &str,
        parent_turn_id: Option<String>,
        context: TurnCreationContext,
    ) -> Result<TurnSpan, Error> {
        // ✨ Load or cache session
        let session_span = self.get_or_load_session(session_span_id).await?;

        // ✨ Create turn span with proper linking
        let mut turn_span = TurnSpan::new(
            session_span_id.to_string(),
            parent_turn_id,
            session_span.span.user_id.clone(),
            session_span.session_context.session_id.clone(),
        );

        // ✨ Enrich with context
        turn_span.turn_context = context.turn_context;
        turn_span.span.metadata = context.metadata;

        // ✨ Link to session automatically
        self.link_turn_to_session(&mut turn_span, session_span_id).await?;

        Ok(turn_span)
    }

    async fn link_turn_to_session(
        &mut self,
        turn_span: &mut TurnSpan,
        session_span_id: &str,
    ) -> Result<(), Error> {
        // ✨ Add to session's turn list
        if let Some(session) = self.session_cache.get_mut(session_span_id) {
            session.add_turn_span(turn_span.span.span_id.clone());
        }

        // ✨ Update in persistent storage
        update_session_turn_list(session_span_id, &turn_span.span.span_id).await?;

        Ok(())
    }
}

// 3. Span querying with hierarchy awareness
pub struct SpanQueryEngine {
    database: Arc<dyn SpanDatabase>,
}

impl SpanQueryEngine {
    pub async fn query_turns_by_session(
        &self,
        session_span_id: &str,
    ) -> Result<Vec<TurnSpan>, Error> {
        // ✨ Query all turns linked to session
        let turn_span_ids = self.database
            .query_child_spans(session_span_id)
            .await?;

        let mut turn_spans = Vec::new();
        for span_id in turn_span_ids {
            let turn_span: TurnSpan = self.database.load_span(&span_id).await?;
            turn_spans.push(turn_span);
        }

        Ok(turn_spans)
    }

    pub async fn query_session_with_turns(
        &self,
        session_span_id: &str,
    ) -> Result<(SessionSpan, Vec<TurnSpan>), Error> {
        // ✨ Load session and all its turns in one query
        let session_span: SessionSpan = self.database.load_span(session_span_id).await?;
        let turn_spans = self.query_turns_by_session(session_span_id).await?;

        Ok((session_span, turn_spans))
    }
}

